-- Poems batch 254
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fca9b6dd-0a97-4e01-ac01-3a0bf975c963','古道','陳杰','宋','宋诗','song-poetry','','[]','殺雞季偉蔬留客，列鼎孫弘外一肴。',32,'全唐诗/poet.song.228000.json','["殺雞季偉蔬留客，列鼎孫弘外一肴。", "古道無存幾夫子，今人何限不全交。"]'),
('c157a9c1-9cfb-4509-838c-e167b07eb47e','故人家','陳杰','宋','宋诗','song-poetry','','[]','蓬頭歷齒王霸子，葛帔練裙任昉兒。',32,'全唐诗/poet.song.228000.json','["蓬頭歷齒王霸子，葛帔練裙任昉兒。", "世緒何妨有凋落，若敖羊舌正堪悲。"]'),
('b1bc6beb-68d6-4596-b6a0-3b2a55a39bfb','除夕對梅花燭花二首  其一','陳杰','宋','宋诗','song-poetry','','[]','花與先生共歲寒，坐來不管漏聲殘。',32,'全唐诗/poet.song.228000.json','["花與先生共歲寒，坐來不管漏聲殘。", "移瓶更轉橫枝影，貼在窗扉作畫看。"]'),
('61e7a61c-0ae8-404c-8f9b-37b7a21bb9df','除夕對梅花燭花二首  其二','陳杰','宋','宋诗','song-poetry','','[]','頃刻開花翦復成，大如菡萏小朱櫻。',32,'全唐诗/poet.song.228000.json','["頃刻開花翦復成，大如菡萏小朱櫻。", "一年歲事占來日，知爲先生報曉晴。"]'),
('c9b30dd3-ade4-4320-8821-4c1bb3deb467','小春桃李俱花','陳杰','宋','宋诗','song-poetry','','[]','陽林小春醉風日，老面得酒須臾歡。',32,'全唐诗/poet.song.228000.json','["陽林小春醉風日，老面得酒須臾歡。", "不妨桃李妍冬谷，正要松篁用歲寒。"]'),
('c77509d6-3976-4f5f-b5bb-0f84ad31e6f2','贈玉壺相士','陳杰','宋','宋诗','song-poetry','','[]','黄金取印斗來大，白玉作壺冰樣寒。',32,'全唐诗/poet.song.228000.json','["黄金取印斗來大，白玉作壺冰樣寒。", "子號甚清堪自照，吾詩愈淡欲誰看。"]'),
('acbe8f23-a404-4472-bfe1-4d744f18eace','月窗相士','陳杰','宋','宋诗','song-poetry','','[]','明月誰令作鑑寒，紙窗何日透蠅鑽。',32,'全唐诗/poet.song.228000.json','["明月誰令作鑑寒，紙窗何日透蠅鑽。", "人間萬事秋毫細，跳出須彌頂上看。"]'),
('478b81c7-b4cf-4ff1-b5f7-5161b9191ef4','贈冰月相士','陳杰','宋','宋诗','song-poetry','','[]','十年已往如冰冷，千載方來似月明。',32,'全唐诗/poet.song.228000.json','["十年已往如冰冷，千載方來似月明。", "唐許何嘗關世事，人間正有一書生。"]'),
('ec177558-ad6a-4c0d-9ca1-6d49c7d19436','和葉宋英三絕句  其一','陳杰','宋','宋诗','song-poetry','','[]','千里論詩半語無，出門濠上子知魚。',32,'全唐诗/poet.song.228000.json','["千里論詩半語無，出門濠上子知魚。", "寒潭潦盡水歸壑，落日山明人荷鋤。"]'),
('0b4147be-a093-425a-9abc-95c536671677','和葉宋英三絕句  其二','陳杰','宋','宋诗','song-poetry','','[]','大范寄詩題八十，龍韜照夜白虹寒。',32,'全唐诗/poet.song.228000.json','["大范寄詩題八十，龍韜照夜白虹寒。", "重紆剡雪歸時棹，問訊磻璜約處灘。"]'),
('b11d99f0-4924-4a35-8916-2a40a3654cc3','和葉宋英三絕句  其三','陳杰','宋','宋诗','song-poetry','','[]','昌谷鯨蛇供誕幻，玉川騄駬玩虛空。',32,'全唐诗/poet.song.228000.json','["昌谷鯨蛇供誕幻，玉川騄駬玩虛空。", "獨無桃實三千歲，更有鵬扶九萬風。"]'),
('3fc15534-5217-4636-8ef1-7059809898c9','和張純父霜月三首  其一','陳杰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭高秋乃無事，洞庭主人獨多才。',32,'全唐诗/poet.song.228000.json','["洞庭高秋乃無事，洞庭主人獨多才。", "滿天如水烏啼夜，寫出寒蟬濕兔來。"]'),
('d78618fc-0b2e-4cbd-b385-6a34280356c0','和張純父霜月三首  其二','陳杰','宋','宋诗','song-poetry','','[]','茅店板橋天落趣，素娥青女洗長新。',32,'全唐诗/poet.song.228000.json','["茅店板橋天落趣，素娥青女洗長新。", "昔人已與不傳死，千古誰憐老斲輪。"]'),
('99f89005-190e-4d0b-b9bd-c986b375351d','和張純父霜月三首  其三','陳杰','宋','宋诗','song-poetry','','[]','天公戲劇高寒上，豈識人間有凜秋。',32,'全唐诗/poet.song.228000.json','["天公戲劇高寒上，豈識人間有凜秋。", "八萬四千揮斧手，閒拋玉屑下瓊樓。"]'),
('28056afc-95fe-4243-a75a-847db2261d99','和州秋陽','陳杰','宋','宋诗','song-poetry','','[]','雨風睡過一年春，破悶無茶可策勳。',32,'全唐诗/poet.song.228000.json','["雨風睡過一年春，破悶無茶可策勳。", "失笑起來聞玉笛，嬾晴吹漲滿空雲。"]'),
('8fdb5a55-474b-4e64-a243-75ac725d9853','和成修堂見寄吟稿韻二首  其一','陳杰','宋','宋诗','song-poetry','','[]','吟屋青山萬壘間，割來風月少陵壇。',32,'全唐诗/poet.song.228000.json','["吟屋青山萬壘間，割來風月少陵壇。", "可憐雲樹相望地，今作江東渭北看。"]'),
('dfd6a806-d5ab-41ec-b26d-fa3b179a0bde','和成修堂見寄吟稿韻二首  其二','陳杰','宋','宋诗','song-poetry','','[]','猶憶朝天曉漏遲，龍蛇暖日動旌旂。',32,'全唐诗/poet.song.228000.json','["猶憶朝天曉漏遲，龍蛇暖日動旌旂。", "此生那復賡酬樂，風雪天涯各鍛詩。"]'),
('7c715c77-6909-4d37-a1c1-aa55c8060ecf','和友人生香四和','陳杰','宋','宋诗','song-poetry','','[]','水仙盆間瑞香盆，着一枝梅一幹蓀。',32,'全唐诗/poet.song.228000.json','["水仙盆間瑞香盆，着一枝梅一幹蓀。", "箇是山中生四和，麝沈棗甲更須論。"]'),
('8ead9b45-b306-40ed-9eca-b5d5692e6294','破屋','陳杰','宋','宋诗','song-poetry','','[]','江頭風雨連年惡，破屋驚秋復惜春。',32,'全唐诗/poet.song.228000.json','["江頭風雨連年惡，破屋驚秋復惜春。", "天上金甌足時棟，人間白髮是閒身。"]'),
('a2c9b5c5-c044-4f0b-a4af-7bdea3716799','挽周溪園國史三首  其一','陳杰','宋','宋诗','song-poetry','','[]','壯歲高科晚一麾，江濤如此幅巾歸。',32,'全唐诗/poet.song.228000.json','["壯歲高科晚一麾，江濤如此幅巾歸。", "書生何限經綸意，曾共危闌送落暉。"]'),
('9018b2d2-1d06-4d39-b408-3f03d9d36d8b','挽周溪園國史三首  其二','陳杰','宋','宋诗','song-poetry','','[]','一瞬風雲宇宙新，一家中外幾朱輪。',32,'全唐诗/poet.song.228000.json','["一瞬風雲宇宙新，一家中外幾朱輪。", "歸來却就千鍾養，贏得深衣處士身。"]'),
('6462f8ae-3a10-40fa-84b4-1630995ee0ae','挽周溪園國史三首  其三','陳杰','宋','宋诗','song-poetry','','[]','鉅筆曾編兩大藩，江山如畫朔風酸。',32,'全唐诗/poet.song.228000.json','["鉅筆曾編兩大藩，江山如畫朔風酸。", "如何地下修文手，還要南朝舊史官。"]'),
('691b5849-eaf1-4a8b-9564-a9190cf43dea','勸農同幕皆預即事四絕  其一','陳杰','宋','宋诗','song-poetry','','[]','鐵騎琱戈夾道馳，元戎小隊出郊時。',32,'全唐诗/poet.song.228000.json','["鐵騎琱戈夾道馳，元戎小隊出郊時。", "白袍容與其間者，莫是參謀老拾遺。"]'),
('a7b60bf3-e598-4d41-9be3-7657f26b650b','勸農同幕皆預即事四絕  其二','陳杰','宋','宋诗','song-poetry','','[]','妥貼輕輿我自便，更施小帳暖如氈。',32,'全唐诗/poet.song.228000.json','["妥貼輕輿我自便，更施小帳暖如氈。", "前山一陣東風雨，馬上諸郎陛楯然。"]'),
('9781537d-e8c9-40ea-8bb1-9869c3047b39','勸農同幕皆預即事四絕  其三','陳杰','宋','宋诗','song-poetry','','[]','風捲岡頭似怒雷，曉來驅我上崔嵬。',32,'全唐诗/poet.song.228000.json','["風捲岡頭似怒雷，曉來驅我上崔嵬。", "斗牛儘是登臨處，到得清明却不來。"]'),
('5a66cb38-f159-4edf-9b99-698151cda294','勸農同幕皆預即事四絕  其四','陳杰','宋','宋诗','song-poetry','','[]','烏帽持觴鬢似銀，近前不怕相公嗔。',32,'全唐诗/poet.song.228000.json','["烏帽持觴鬢似銀，近前不怕相公嗔。", "未知此日殷勤意，曾到深村作苦人。"]'),
('e0303d90-8f40-4712-898b-b79f0a23a351','見諸君感事之作','陳杰','宋','宋诗','song-poetry','','[]','鼎湖不挾宇宙去，驪墓曾包山海來。',32,'全唐诗/poet.song.228000.json','["鼎湖不挾宇宙去，驪墓曾包山海來。", "教兒倒誦阿房賦，一與張陽洗七哀。"]'),
('88739c4d-4320-4da5-9485-3efaf2c6ccdb','題李生烟江萬里圖','陳杰','宋','宋诗','song-poetry','','[]','白鷗飛來類從汝，寒鴈瞥起幾導吾。',32,'全唐诗/poet.song.228000.json','["白鷗飛來類從汝，寒鴈瞥起幾導吾。", "未覺咫間能萬里，曲肱殘夢落東湖。"]'),
('02fc3914-e6b7-4790-a38a-9fe27c5c3ad5','贈徐先輩星命課','陳杰','宋','宋诗','song-poetry','','[]','三命橫鋪下點星，風雷歘起斗牛靈。',32,'全唐诗/poet.song.228000.json','["三命橫鋪下點星，風雷歘起斗牛靈。", "正堪持獻雲霄士，不中山間倦客聽。"]'),
('0e715b16-7c99-400d-baf5-9de86eb7790a','閉門','陳杰','宋','宋诗','song-poetry','','[]','閉門風雨九十日，生物趨新曾未休。',32,'全唐诗/poet.song.228000.json','["閉門風雨九十日，生物趨新曾未休。", "適見桃枝暗明月，漸聞柳絮逐江流。"]'),
('f5205c6f-a5a1-4e5c-997c-bc412d851f34','東湖晚步洪恩橋海棠洞三首  其一','陳杰','宋','宋诗','song-poetry','','[]','城裏北風連夜號，平湖捲綠上枯壕。',32,'全唐诗/poet.song.228000.json','["城裏北風連夜號，平湖捲綠上枯壕。", "不知江水長多少，檣尾過城三丈高。"]'),
('08f3d5b6-4ae5-4d80-826a-2307b0b867d1','東湖晚步洪恩橋海棠洞三首  其二','陳杰','宋','宋诗','song-poetry','','[]','雪前一枝玉出牆，獨立小橋風信香。',32,'全唐诗/poet.song.228000.json','["雪前一枝玉出牆，獨立小橋風信香。", "爛霞晴日炙蔫錦，十里輭紅人若狂。"]'),
('5ffb50c1-b6e0-447a-8932-48d054b588e8','東湖晚步洪恩橋海棠洞三首  其三','陳杰','宋','宋诗','song-poetry','','[]','百花洲前萬柳隄，一川紅綠醉春時。',32,'全唐诗/poet.song.228000.json','["百花洲前萬柳隄，一川紅綠醉春時。", "樓臺忽斷見西爽，鶑燕正深聞子規。"]'),
('ac37b59e-ca46-4546-a8be-a09b95b766c0','詠歸晚步','陳杰','宋','宋诗','song-poetry','','[]','風流頓盡萬花浦，俛仰已陳雙桂亭。',32,'全唐诗/poet.song.228000.json','["風流頓盡萬花浦，俛仰已陳雙桂亭。", "黄鞠華差强人意，紅拒霜猶有典刑。"]'),
('692c64ec-088d-4dae-a00b-a693f98b44ed','書生舊夢二解皆因榜過作  其一','陳杰','宋','宋诗','song-poetry','','[]','長憶西風翠袖單，暮簷修玉倚初寒。',32,'全唐诗/poet.song.228000.json','["長憶西風翠袖單，暮簷修玉倚初寒。", "一回得嫁平生足，更用花枝插白看。"]'),
('5c85e9b6-97de-4698-8b77-08bac633fc65','書生舊夢二解皆因榜過作  其二','陳杰','宋','宋诗','song-poetry','','[]','一著當機已百全，落枰忽誤豈非天。',32,'全唐诗/poet.song.228000.json','["一著當機已百全，落枰忽誤豈非天。", "空函墮甑都休惋，赤壁淮淝本偶然。"]'),
('855b89bf-33a6-4257-b805-3092f3373c2f','和徐子蒼揚州夢梅','陳杰','宋','宋诗','song-poetry','','[]','林昏月落淮南夜，還憶江清水見沙。',32,'全唐诗/poet.song.228000.json','["林昏月落淮南夜，還憶江清水見沙。", "冰雪爲魂玉在側，了知不是夢梨花。"]'),
('397893e8-bfec-45d1-bdff-f579c966edf3','寒夢','陳杰','宋','宋诗','song-poetry','','[]','寒夢初回斗帳深，清輝忽破小窗陰。',32,'全唐诗/poet.song.228000.json','["寒夢初回斗帳深，清輝忽破小窗陰。", "若爲推上松蘿月，展盡梅花一寸心。"]'),
('47dff824-144d-429a-80d6-2c820eafa109','題驛壁','陳杰','宋','宋诗','song-poetry','','[]','驊騮捕鼠不如狸，鏌干綴履不如錐。',32,'全唐诗/poet.song.228000.json','["驊騮捕鼠不如狸，鏌干綴履不如錐。", "過都歷塊成何事，剸虎裁蛟彼一時。"]'),
('23a136d1-ea82-49dc-9702-ac6424914f81','六朝','陳杰','宋','宋诗','song-poetry','','[]','正朔奄奄一脈垂，不多文物迭興衰。',32,'全唐诗/poet.song.228000.json','["正朔奄奄一脈垂，不多文物迭興衰。", "菰蘆等是偏方士，爾尚生逢六季時。"]'),
('4ede631c-c94a-4199-b0e3-d91cc24c5039','詠涂璋家屏風上題宣和壬寅季夏','陳杰','宋','宋诗','song-poetry','','[]','玉芝隨手燕堂空，翠幰宸遊黍滿宮。',32,'全唐诗/poet.song.228000.json','["玉芝隨手燕堂空，翠幰宸遊黍滿宮。", "一片宣和殘歲月，百年田舍古屏風。"]'),
('03829e2b-6295-4756-8a8f-45365c46f84e','詠史','陳杰','宋','宋诗','song-poetry','','[]','蜀相猶雄懿已王，江東逮見魏先亡。',32,'全唐诗/poet.song.228000.json','["蜀相猶雄懿已王，江東逮見魏先亡。", "山陽更在江東後，如此三分未用傷。"]'),
('d25ee504-1345-42e5-9f3b-dc4f6cf348b8','題梅壇毛慶甫道士雲悅樓','陳杰','宋','宋诗','song-poetry','','[]','白衣蒼狗無情物，翻手悲歡變古今。',32,'全唐诗/poet.song.228000.json','["白衣蒼狗無情物，翻手悲歡變古今。", "輸與道人長快活，看渠起滅不關心。"]'),
('399ef58c-3644-4d33-a715-e2db5333a222','答李道士','陳杰','宋','宋诗','song-poetry','','[]','老子廢吟恐妨道，道人學詩如學僊。',32,'全唐诗/poet.song.228000.json','["老子廢吟恐妨道，道人學詩如學僊。", "探藏不惜藏諸密，試換黄庭內景篇。"]'),
('6ea1af64-4131-43f1-a2a8-6eee4e96fed7','題傅道士鶴鳴泉','陳杰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夢回華表千年遠，思入廬山三疊寒。',32,'全唐诗/poet.song.228000.json','["夢回華表千年遠，思入廬山三疊寒。", "綠髮道人知許事，山中自寫鶴泉看。"]'),
('a73c72f0-e403-414f-8a68-9f2254e60a86','酬別孫道人存心歸上饒二首  其一','陳杰','宋','宋诗','song-poetry','','[]','消得剛風三日夜，吹開正色泬寥天。',32,'全唐诗/poet.song.228000.json','["消得剛風三日夜，吹開正色泬寥天。", "蘇門月朗君長嘯，太華雲高我晝眠。"]'),
('9f7b635a-3ec4-4ae5-b919-a4e69b071730','酬別孫道人存心歸上饒二首  其二','陳杰','宋','宋诗','song-poetry','','[]','短些幾迴無寄處，一聲歸鶴落江東。',32,'全唐诗/poet.song.228000.json','["短些幾迴無寄處，一聲歸鶴落江東。", "兩行老淚千年恨，問訊騎鯨太白翁。"]'),
('d6e725e7-cef3-475e-b908-11d474c839b0','和諸公瓊花二首  其一','陳杰','宋','宋诗','song-poetry','','[]','豔不山礬瘦不梅，全身奪得八仙胎。',32,'全唐诗/poet.song.228000.json','["豔不山礬瘦不梅，全身奪得八仙胎。", "揚州怕有歸來鶴，曾見無雙檻裏開。"]'),
('60986bd8-0197-4b39-9a54-c078598703d1','和諸公瓊花二首  其二','陳杰','宋','宋诗','song-poetry','','[]','淡日微雲燕麥斜，江思笋蕨客思家。',32,'全唐诗/poet.song.228000.json','["淡日微雲燕麥斜，江思笋蕨客思家。", "是非欲共東風語，一曲欄干眼自花。"]'),
('a209b0d2-82b8-4dcd-b4fd-8d2a3af86e99','題宣和御畫蘆禽','陳杰','宋','宋诗','song-poetry','','[]','蘆邊晚吹冷颼颼，背立孤禽有許愁。',32,'全唐诗/poet.song.228000.json','["蘆邊晚吹冷颼颼，背立孤禽有許愁。", "可是殿庭無事筆，已含原野十分秋。"]'),
('6fbe31a7-f5d1-4ae8-9f21-ec71f552e585','男竹枝歌','陳杰','宋','宋诗','song-poetry','','[]','東園一株千葉茶，阿翁手栽紅錦花。',32,'全唐诗/poet.song.228000.json','["東園一株千葉茶，阿翁手栽紅錦花。", "今年團欒且同看，明年大哥天一涯。"]'),
('78f6c0b2-a645-42c7-a943-53e03f003fdf','女竹枝歌','陳杰','宋','宋诗','song-poetry','','[]','南園一株雨前茶，阿婆手種黄玉芽。',32,'全唐诗/poet.song.228000.json','["南園一株雨前茶，阿婆手種黄玉芽。", "今年團欒且同摘，明年大姊阿誰家。"]'),
('1e8a7d6b-6582-4767-afc4-42a74a041aa2','和彭教諭論詩','陳杰','宋','宋诗','song-poetry','','[]','平生於二南，百過在芣苢。',108,'全唐诗/poet.song.228000.json','["平生於二南，百過在芣苢。", "不知孰舞蹈，但覺烏可已。", "煌煌古人心，豈與不死傳。", "天和本發中，世味或食耳。", "全明凋靡後，未造放蕩始。", "折楊紛皇荂，敗素正堪紫。", "斯文吾衰久，安得力任鄙。", "天河儻可挽，舉俗快一洗。", "不且尊杜黄，卿言尚予起。"]'),
('0494d495-a95d-4117-9b60-c2ecced77fa5','誦詩','陳杰','宋','宋诗','song-poetry','','[]','盛氣劘騷壘，長歌歷杜藩。',24,'全唐诗/poet.song.228000.json','["盛氣劘騷壘，長歌歷杜藩。", "二南四字始，萬古一解難。"]'),
('66e1df8f-4baf-461e-a4fc-aea378b5b765','無題  其一','陳杰','宋','宋诗','song-poetry','','[]','大地生靈惜暵乾，紙田不飽腐儒餐。',32,'全唐诗/poet.song.228000.json','["大地生靈惜暵乾，紙田不飽腐儒餐。", "閑將博士虀鹽味，試上先生苜蓿盤。"]'),
('2bb8985e-ef33-4382-88b4-7be326308fba','無題  其二','陳杰','宋','宋诗','song-poetry','','[]','口語甘時心猶異，中邊甜處味方宜。',32,'全唐诗/poet.song.228000.json','["口語甘時心猶異，中邊甜處味方宜。", "詩情合薦東坡老，慙媿當年蜜荔枝。"]'),
('674b2dea-804b-48d8-bcbe-13715c2ac935','無題  其三','陳杰','宋','宋诗','song-poetry','','[]','聞道江邊起柁樓，欲將吾道付滄洲。',64,'全唐诗/poet.song.228000.json','["聞道江邊起柁樓，欲將吾道付滄洲。", "三年惡瞰盧仝屋，一日輕裝范蠡舟。", "蹈海高懷欣獨往，濟川好手蹇難留。", "檣陰舸下能容我，雨笠烟簑傲白鷗。"]'),
('ca70e106-30ba-4e69-ba59-2d6b1ea4ddcd','至日拜賜','陳杰','宋','宋诗','song-poetry','','[]','千官萬歲講朝儀，黄繖高張簇仗齊。',32,'全唐诗/poet.song.228000.json','["千官萬歲講朝儀，黄繖高張簇仗齊。", "清曉山窗頻扣首，虬鬚隆準伴宸奎。"]'),
('56928af3-0247-4a08-8f22-262e9f641675','程簿能靜袖詩來訪次韻','陳杰','宋','宋诗','song-poetry','','[]','高吟鼎臠屢經嘗，群噪紛紛子貢牆。',64,'全唐诗/poet.song.228000.json','["高吟鼎臠屢經嘗，群噪紛紛子貢牆。", "雪曲我應慙郢下，笛聲公自感山陽。", "堪嗟絳老泥塗役，孤負春官桃李場。", "斗大康山盛儒者，憑誰推此叩循良。"]'),
('7703788d-9ee6-4816-9589-3fc1acc78e4f','東湖','陳杰','宋','宋诗','song-poetry','','[]','重遊如隔世，露雨暗池臺。',48,'全唐诗/poet.song.228000.json','["重遊如隔世，露雨暗池臺。", "蓬島又淺水，昆明幾劫灰。", "蒼鵝飛底去，白雁集何來。", "萬古南州土，荒祠一造哀。"]'),
('74f519ff-2bff-4a40-a70b-d118f786dd91','西湖','陳杰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小春好風日，湖上足池臺。',48,'全唐诗/poet.song.228000.json','["小春好風日，湖上足池臺。", "彼美少年子，適從何處來。", "恩光被鞍馬，艷麗照樽罍。", "今者不自樂，後人誰爾哀。"]'),
('535281db-fad9-4632-b433-c075617bd7a8','小家住深村','陳杰','宋','宋诗','song-poetry','','[]','小家住深村，獨犬應門戶。',48,'全唐诗/poet.song.228000.json','["小家住深村，獨犬應門戶。", "招麾不去來，進止有常處。", "從田仍司盜，奔走亦禦侮。", "常恐下生氂，八方嘯狐兔。"]'),
('05ac334a-391b-4100-a14c-18694f81ed34','送中齋過家入燕','陳杰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江浙相望半月程，燕雲萬里重行行。',64,'全唐诗/poet.song.228000.json','["江浙相望半月程，燕雲萬里重行行。", "幾多臨水登山賦，不盡還家去國情。", "三入換來金印大，一歸贏得綵衣明。", "東湖何似西湖好，且對梅花捧壽觥。"]'),
('30490f47-e2c2-4e8b-9b2a-3b0a20d14f9b','充善堂爲吳氏題','陳杰','宋','宋诗','song-poetry','','[]','厥初生人，稟性受中。',160,'全唐诗/poet.song.228000.json','["厥初生人，稟性受中。", "不患不善，患不能充。", "血氣既剛，物我交戰。", "不患不充，又患不善。", "充而善者，可鸞可凰。", "匪善而充，化爲豺狼。", "其充爲何，勿助勿害。", "鷄鳴而興，善與利對。", "申嚴界限，審察毫釐。", "誠內僞外，理公欲私。", "充無穿窬，義不勝用。", "彼充孔揚，傲誕是從。", "故得其正，泉達火然。", "一有弗協，履冰臨淵。", "嗚呼道微，志遠瞻卓。", "子如充之，明善守約。"]'),
('0e54ffa9-90b5-4f3d-95b6-1e5954c836b3','中興事蹟','陳杰','宋','宋诗','song-poetry','','[]','瑶編每讀憤填膺，始末權姦託罷兵。',64,'全唐诗/poet.song.228000.json','["瑶編每讀憤填膺，始末權姦託罷兵。", "初渡已誅雙烈士，小吏更壞一長城。", "齧氈大老投荒死，借劍孤忠竄島生。", "長與東南羞汗簡，更堪西北望神京。"]'),
('8f0a866f-dbaa-4ecf-a086-18b749bb116b','送萬平野余秋山被薦北行','陳杰','宋','宋诗','song-poetry','','[]','朔雲垂天野四平，羌笛叫月山秋清。',64,'全唐诗/poet.song.228000.json','["朔雲垂天野四平，羌笛叫月山秋清。", "金臺此日燕萬里，綿蕞當年魯兩生。", "衢路屏營詩少味，江關蕭瑟賦多情。", "西風瞥眼鱸魚鱠，一夜相思聞雁聲。"]'),
('41820a35-aab5-4331-9bdc-f72e13ce6402','題信州月巖','陳杰','宋','宋诗','song-poetry','','[]','岡路陰陰忽半規，無盈萬古亦無虧。',64,'全唐诗/poet.song.228000.json','["岡路陰陰忽半規，無盈萬古亦無虧。", "鑿開空洞地有眼，劈下廣寒天不知。", "小著山河偏影處，平分蟾桂上弦時。", "遊人莫訝清光少，照見江東幾盛衰。"]'),
('f1fd3ae2-c180-4e18-b1a2-1c37b44c28f7','秋熱抵信上一歌館壁張蘆雁寒林','陳杰','宋','宋诗','song-poetry','','[]','老火張成傘，柔金伏在爐。',48,'全唐诗/poet.song.228000.json','["老火張成傘，柔金伏在爐。", "正遮西日手，忽坐北風圖。", "霜葉條嗷雁，冰枝有噤烏。", "摩挲懷美獻，短策濟時無。"]'),
('4f11d748-0ce4-477f-b8e9-a2c7f5745f53','大窖齧旃','陳杰','宋','宋诗','song-poetry','','[]','伸脚踏胡地，開口喫漢天。',60,'全唐诗/poet.song.228000.json','["伸脚踏胡地，開口喫漢天。", "見天不見雪，况辨雪與旃。", "胡人不敢殺，謂是不死仙。", "漢庭方求不死訣，方士取露和玉屑，何如老臣旃夾雪。"]'),
('1b184fb7-bbd9-40a5-8795-4bd8624b58bc','先主','陳杰','宋','宋诗','song-poetry','','[]','扶義風雲急，投難歲月長。',48,'全唐诗/poet.song.228000.json','["扶義風雲急，投難歲月長。", "猶懷置嗣子，豈要負劉璋。", "討賊吾誰遜，違天有併亡。", "春秋復讎方，萬古烜炎光。"]'),
('d53adb83-0a24-4b28-8d32-7e39471e0ef8','曹操','陳杰','宋','宋诗','song-poetry','','[]','鹿去卯金刀，當塗未敢高。',48,'全唐诗/poet.song.228000.json','["鹿去卯金刀，當塗未敢高。", "爭榮猶在弈，食馬已同槽。", "身後三分閏，生前百詐勞。", "就如題墓上，盜豹亦焉逃。"]'),
('fabaaf40-b7a1-4864-a6ac-dd280210898a','司馬懿','陳杰','宋','宋诗','song-poetry','','[]','本祖賊爲媒，聊同漢報仇。',48,'全唐诗/poet.song.228000.json','["本祖賊爲媒，聊同漢報仇。", "機深螳後雀，禍隠馬中牛。", "夷甫毋專罪，江生足遠猷。", "誰開千古恨，落日淡神州。"]'),
('d0680739-65af-4e8f-9577-82a50baf3bd3','登岳陽樓','陳杰','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','扁舟小繫畫欄西，萬里清光一拄頤。',64,'全唐诗/poet.song.228000.json','["扁舟小繫畫欄西，萬里清光一拄頤。", "湖面欲包天外去，嶠鬟疑割海中來。", "高空自瀉軒皇樂，元氣長涵老杜詩。", "慶曆殘碑重回首，此生何限退憂時。"]'),
('259c85b0-f5ee-40d4-b61d-c453ed134760','赴崖山贈別陳燾父','郭居安','宋','宋诗','song-poetry','','[]','詩來老氣鬰沈沈，猶負驛騮萬里駸。',64,'全唐诗/poet.song.228000.json','["詩來老氣鬰沈沈，猶負驛騮萬里駸。", "輦路風塵重回首，梅花歲晚獨知心。", "張南有死天無遠，管邴如生海未深。", "明發陽關底須疊，只哦雅製沈哇淫。"]'),
('e1f1e072-b641-41d7-a728-d1beb86e7fb0','句','雷侍郎','宋','宋诗','song-poetry','','[]','無魔不成佛，觀過始知仁。',12,'全唐诗/poet.song.228000.json','["無魔不成佛，觀過始知仁。"]'),
('9f541e38-6a1a-42ab-86ce-766533065786','陪山泉登芝山和文正公舊韻','釋道璨','宋','宋诗','song-poetry','','[]','培塿視崔巍，眼高如許哉。',48,'全唐诗/poet.song.228000.json','["培塿視崔巍，眼高如許哉。", "舉頭天在上，四面景皆來。", "漸老成多病，看山又一回。", "盡供詩世界，霽色爲君開。"]'),
('fa94b47a-2fe4-4490-9184-8781f9e6b87f','水月軒','釋道璨','宋','宋诗','song-poetry','','[]','江水清無底，江月明如洗。',88,'全唐诗/poet.song.228000.json','["江水清無底，江月明如洗。", "開軒浥清明，道人清若此。", "春風不摇江面波，春雲不載江頭雨。", "天地無塵夜未央，照影軒中惟自許。", "我來風雨夜漫漫，水月俱忘無表裏。", "笑拍闌干問阿師，水在月兮月在水。"]'),
('340ab454-b61c-4a5a-acca-cde7beca33a4','題物初蕙蘭','釋道璨','宋','宋诗','song-poetry','','[]','花短秋意長，神清顔色少。',24,'全唐诗/poet.song.228000.json','["花短秋意長，神清顔色少。", "筆端有西風，國香來未了。"]'),
('1c217b31-399d-4b99-b538-9c7b87bc4f7e','仙巢海棠洞','釋道璨','宋','宋诗','song-poetry','','[]','領客坐花陰，飲客酌花露。',48,'全唐诗/poet.song.228000.json','["領客坐花陰，飲客酌花露。", "先生自家春，八荒一牖戶。", "凄其望前修，一枝閲世故。", "鶴車來不來，東風吹日暮。"]'),
('a8ae9f86-7a05-4f17-928f-215291952507','野水橫舟','釋道璨','宋','宋诗','song-poetry','','[]','望之一葉輕，即之萬鈞重。',48,'全唐诗/poet.song.228000.json','["望之一葉輕，即之萬鈞重。", "天風吹不去，世波摇不動。", "送盡千帆飛，濟川已無夢。", "月冷蘋花秋，此興白鷗共。"]'),
('f67aacb8-054d-4ad1-a071-83e1e92ddaf0','月窟','釋道璨','宋','宋诗','song-poetry','','[]','鑿開渾沌竅，豁見天地根。',48,'全唐诗/poet.song.228000.json','["鑿開渾沌竅，豁見天地根。", "舉瓢酌桂漿，引足蹈崑崙。", "湛然一精明，身外無乾坤。", "我欲從之遊，雲深入無門。"]'),
('f04bf184-abce-4551-bdde-70045fb4b5fd','蘭溪夜泊','釋道璨','宋','宋诗','song-poetry','','[]','我泛浙西船，夜泊蘭溪岸。',62,'全唐诗/poet.song.228000.json','["我泛浙西船，夜泊蘭溪岸。", "篷窗坐不眠，縣鼓鳴夜半。", "橋上趁墟人，徃來徹清旦。", "辦此朝夕勞，不博一日飯。", "複氈睡正煖，閉戶有人嫌夜短。"]'),
('aaff70dd-b5c6-4338-a07f-e8bfc31ebe82','贈觀妙道士','釋道璨','宋','宋诗','song-poetry','','[]','妙處不可觀，可觀非是妙。',72,'全唐诗/poet.song.228000.json','["妙處不可觀，可觀非是妙。", "杳杳無方所，冥冥無朕兆。", "我觀三十年，力盡不能透。", "及其會心時，忻然惟一笑。", "碧桃開晚花，黄鸝囀春晝。", "大哉衆妙門，老子親傳授。"]'),
('59d9cda2-d7c0-45a8-b1d5-239edd4edc29','題源虛叟廬山行卷','釋道璨','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','胸中有廬山，筆下有廬山。',84,'全唐诗/poet.song.228000.json','["胸中有廬山，筆下有廬山。", "窗下有廬山，眼中有廬山。", "別山十七年，見山一日間。", "韵險落鬼膽，語妙破天慳。", "永懷看山人，恨不同躋攀。", "摩挲青石硯，負山良厚顔。", "天風幾時來，乘之欲西還。"]'),
('04fafee4-eead-4885-bbb0-9eddbe69bb32','題於潜西菩兼山閣參寥受業','釋道璨','宋','宋诗','song-poetry','','[]','青山在屋頭，易見甚難識。',84,'全唐诗/poet.song.228000.json','["青山在屋頭，易見甚難識。", "如玉有碎氣，如土有正色。", "平生萬里眼，付此千丈壁。", "雲行山欲動，雲深山更碧。", "動止同一機，兼處貴自得。", "心外無青山，身外無周易。", "安得識山人，倚闌論未畫。"]'),
('9730175e-7494-471f-8f24-fdd2168237a5','題會稽孫竹閣望梅亭','釋道璨','宋','宋诗','song-poetry','','[]','梅梁在屋東，梅溪在屋西。',84,'全唐诗/poet.song.228000.json','["梅梁在屋東，梅溪在屋西。", "舉頭東西望，古意入雙眉。", "彼溺猶己溺，彼饑猶己饑。", "皇皇聖人心，萬世同一機。", "誠明與物欲，方寸分町畦。", "火然而泉達，擴充無邊涯。", "禹亦何人哉，勉之宜及時。"]'),
('ec0a837b-c751-495e-b543-f83cc14d70ed','和雨崖吳提刑奉母夫人雨中登魯公亭','釋道璨','宋','宋诗','song-poetry','','[]','白髮照黄花，薄晚散幽步。',84,'全唐诗/poet.song.228000.json','["白髮照黄花，薄晚散幽步。", "何年乘五雲，來自三神嶼。", "膝下千載人，富貴等儒素。", "西風天地秋，細雨江城莫。", "酒酣拍闌干，憂時起愁緒。", "懷哉平原公，孤忠乃吾與。", "重此一臂力，日月容易去。"]'),
('c6ccddbd-c812-4a2f-a2bf-c56202fe1e96','喜雨呈梅石趙都大','釋道璨','宋','宋诗','song-poetry','','[]','久旱天地焦，酷出秦法外。',84,'全唐诗/poet.song.228000.json','["久旱天地焦，酷出秦法外。", "一雨中夜來，漢兵起豐沛。", "萬物皆吐氣，昭蘇脫厄會。", "憂國有天人，愛民如子輩。", "心香徹九關，化爲雲靉靆。", "生意一萬里，直在方寸內。", "老農相與言，曉晴坐牛背。"]'),
('aa6b7daf-75ac-4cea-bd04-462e6e9882ac','寄題瑞昌簿廳景蘇堂墨竹','釋道璨','宋','宋诗','song-poetry','','[]','一葉復一葉，世道幾翻覆。',84,'全唐诗/poet.song.228000.json','["一葉復一葉，世道幾翻覆。", "一點復一點，書脈要接續。", "親見長公來，一節不肯曲。", "見竹如見公，北麓能不俗。", "回首熙豐間，幾人愧此竹。", "翰墨直枝葉，點化到草木。", "長公有深意，此事付北麓。"]'),
('07363e22-04ec-4760-9a14-63da6c333412','和卧龍招隠吟','釋道璨','宋','宋诗','song-poetry','','[]','武侯與晦翁，千載兩名流。',96,'全唐诗/poet.song.228000.json','["武侯與晦翁，千載兩名流。", "各以一臂力，能鎮百世浮。", "神游天地間，或爲山阿留。", "心期有佳人，駕言寫幽憂。", "水流崖華開，山空明月秋。", "桂樹影團團，乳鹿鳴呦呦。", "薦菊秋盈筐，酌茶花滿甌。", "兩翁來不來，徘徊駐歸騶。"]'),
('55dd6216-69cf-4196-932e-258a3af736b0','和梅邊汪提幹','釋道璨','宋','宋诗','song-poetry','','[]','我夢稽山陰，茂林映修竹。',96,'全唐诗/poet.song.228000.json','["我夢稽山陰，茂林映修竹。", "鑒湖八百里，眼看不盈掬。", "管領天下清，此樂梅邊獨。", "幾欲驅車去，雲根夜同宿。", "山空秋月明，安期未可卜。", "蓬萊水清淺，褰裳同往復。", "徑謁蔡少霞，不待青童覆。", "共草新宮銘，調高語圓熟。"]'),
('63617b21-c89b-41b9-b714-741543ecf650','和童敬重','釋道璨','宋','宋诗','song-poetry','','[]','空山木葉下，坐觀不二門。',96,'全唐诗/poet.song.228000.json','["空山木葉下，坐觀不二門。", "茶香舌本甘，直探天地根。", "兩袖江海風，眼前見夫君。", "十年戎馬間，未發詩與文。", "逐祿士之常，一廉減萬想。", "六經在日用，論說漫深廣。", "躬行能尺寸，光燄長萬丈。", "世波易溺人，外此無保障。"]'),
('f39ad79e-f276-41c9-9670-74c4f4036751','潛上人求菊山','釋道璨','宋','宋诗','song-poetry','','[]','具郎號菊山，秀色已衰朽。',96,'全唐诗/poet.song.228000.json','["具郎號菊山，秀色已衰朽。", "潛郎號菊山，清香滿襟袖。", "天地一東籬，萬古一重九。", "絕愛陶淵明，攬之不盈手。", "後人不識秋，多向籬邊守。", "璨璨萬黄金，把玩豈長久。", "西風容易老，回首已如箒。", "因潛憶具郎，有淚如苦酒。"]'),
('2c42b3f4-9bde-4f35-b094-d2e436c60891','送愿上人過雪竇兼呈弁山','釋道璨','宋','宋诗','song-poetry','','[]','去年無準死，今年癡絕喪。',108,'全唐诗/poet.song.228000.json','["去年無準死，今年癡絕喪。", "二老百世師，一去空天壤。", "玉磬與天球，滿耳皆新響。", "堂堂萬鐘鼎，橫列乳峰上。", "愿也天台來，雙眉擁青嶂。", "要見乳峰人，不作行役相。", "碧樹明秋花，吹香上藤杖。", "長松四十圍，懸水一千丈。", "到門相見時，爲我問無恙。"]'),
('d3515411-f371-4601-9e34-f45857cd8e19','雪菊','釋道璨','宋','宋诗','song-poetry','','[]','大雪凍不死，秋風吹不開。',120,'全唐诗/poet.song.228000.json','["大雪凍不死，秋風吹不開。", "許大天地間，受得一氣獃。", "生意在根本，肯趁陽和回。", "要從梅兄游，一笑霜雪堆。", "六花已飛舞，槁悴如根荄。", "下有返魂香，英英死不摧。", "老仙造化手，妙處能奪胎。", "喚醒萬黄金，桃李皆奴儕。", "對花酌老仙，高致誰能陪。", "東籬有佳人，萬些招不來。"]'),
('9285636f-b31c-4e51-9f2f-71502ab16a5b','坐圓常江天軒聽謀西江示衆語','釋道璨','宋','宋诗','song-poetry','','[]','三洲相接連，斷處直如割。',120,'全唐诗/poet.song.228000.json','["三洲相接連，斷處直如割。", "中洲二十里，平沙浄如刷。", "雲開天四垂，雨晴山一抹。", "綠波三萬頃，乞與漁翁撥。", "納之窗戶間，道人巧點掇。", "我來不忍去，倚闌腕欲脫。", "草青烟冉冉，柳靜浪聒聒。", "天風駕滄海，奔突不可遏。", "忻然見此翁，句險眼能活。", "遡流欲從之，水深春岸闊。"]'),
('08b20926-0c3e-4f20-a5ec-883b8d12af07','紀夢','釋道璨','宋','宋诗','song-poetry','','[]','我不識靈溪，夢向溪邊去。',156,'全唐诗/poet.song.228000.json','["我不識靈溪，夢向溪邊去。", "溪遶屋頭流，橋通溪上路。", "軒窗水面開，水清石無數。", "煮茶僧請詩，茶香竹當戶。", "花箋暈淺紅，霜毫脫毛兔。", "引筆信手書，波峭含韻度。", "置筆喜語客，眼明失沉痼。", "夢覺秋滿床，殘月挂庭樹。", "病眩二十年，萬花舞深霧。", "夢中能楷書，以我心念故。", "人生孰非夢，百年等是寓。", "便欲驅車去，傍溪縛茅住。", "但恐秋雨來，溪深不可渡。"]'),
('0a95a961-334a-48ef-a8a2-d34f43615654','贈明侍者','釋道璨','宋','宋诗','song-poetry','','[]','好詩無音律，至文難言說。',144,'全唐诗/poet.song.228000.json','["好詩無音律，至文難言說。", "學之無他術，先要心路絕。", "兀坐送清晝，萬事付一拙。", "如是三十年，大巧自發越。", "萬象赴陶冶，百怪乞提挈。", "興來忽運筆，妙處無前哲。", "古來翰墨士，外此別無訣。", "明也江南來，俊氣方烈烈。", "乘潮觀海門，入越探禹穴。", "須從言外參，莫向紙上竊。", "此方吾必秘，爲子輕漏洩。", "慎勿語俗子，只可自怡悅。"]'),
('dc6957f4-bdc3-4cf7-8810-e19e6de50da9','吳太清有遠役以詩寄別次韻','釋道璨','宋','宋诗','song-poetry','','[]','宇宙入八窗，芙蓉製衣裳。',180,'全唐诗/poet.song.228000.json','["宇宙入八窗，芙蓉製衣裳。", "兩眼挂萬古，深柱書傳香。", "筆端膚寸合，要作天下凉。", "餘事亦演雅，簸弄正未妨。", "顛倒走百怪，陸離羅衆芳。", "氣焰壓牛斗，何止萬丈光。", "笑他兒女曹，白道空茫茫。", "秋風三尺劍，塵土壓下方。", "斫却月中桂，及此鬢未蒼。", "我欲援北斗，酌以椒桂漿。", "文章於此道，太山一毫芒。", "洙泗到伊洛，波瀾正泱泱。", "多少遡流人，褰裳復回翔。", "孰知方寸間，一葦直可航。", "勉哉吳夫子，此事當毋忘。"]'),
('8620395d-226f-4f4d-904d-9137cddd1a5c','蹋雪下雲居山宿崇壽寄草堂','釋道璨','宋','宋诗','song-poetry','','[]','別山三十年，見山雙眼碧。',180,'全唐诗/poet.song.228000.json','["別山三十年，見山雙眼碧。", "山靈喜我來，一笑作戲劇。", "縱橫萬花舞，變亂山顔色。", "圭璧拔地起，自在羣玉國。", "去興紛莫留，下足深沒膝。", "凍合坡長短，石礙路剞側。", "躋攀脚未穩，失勢落數尺。", "平生江海屐，常患天地窄。", "立處貴穩密，取道貴徑直。", "只要緩步行，不在多用力。", "祇以到爲期，半途肯休息。", "須臾到山趾，坦途隨意適。", "回看行路處，倚天立青壁。", "極愛山上雲，長年抱幽石。", "耐得許多清，一夜遥相憶。"]'),
('245be63a-f025-4dc3-b48f-da8b3787749b','和郭澹溪','釋道璨','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','秋氣入我窗，秋風吹我裳。',180,'全唐诗/poet.song.228000.json','["秋氣入我窗，秋風吹我裳。", "可人溪上來，語妙齒頰香。", "餘味徹肝肺，散作六月凉。", "苦吟有天知，不知正無妨。", "譬如叢生蘭，無人亦自芳。", "明珠遺我把，爛爛照乘光。", "疾風駕滄海，世波正茫茫。", "老氣蓋九州，老眼隘四方。", "黄塵暗長淮，蒹葭色蒼蒼。", "醉草馬上檄，舉瓢酌天漿。", "雲開帝星明，妖彗收光芒。", "長江砥樣平，鷗鳥水泱泱。", "照影東湖濱，矯首看橫翔。", "釣竿拂珊瑚，凉意滿歸航。", "到海得明月，寄我毋相忘。"]'),
('af9f5845-11c8-4606-ae69-9eed8ed27d65','送西苑徑上人見深居馮常簿求寺記','釋道璨','宋','宋诗','song-poetry','','[]','西苑寶峰麓，占地寬一弓。',192,'全唐诗/poet.song.228000.json','["西苑寶峰麓，占地寬一弓。", "梵放殷青冥，與峰相長雄。", "鬼域何方來，包舉歸提封。", "樓鐘不敢鳴，僧趨鄰寺鐘。", "徑也鐵石姿，直欲箋天公。", "天高不可叫，虎豹守九重。", "六年長安道，往來如飛蓬。", "雲開日正杲，死草生華風。", "青山復入手，盡埽狐兔蹤。", "魚鼓發新響，松桂還舊容。", "掘地尋泉源，鋤荒理菊叢。", "桃李一家春，萬古無異宗。", "玉色十丈煇，秀潤浄磨礱。", "大書付誰氏，千載深居翁。", "他年來讀碑，病眼摩朦朧。", "爲碑三夕留，卧聽寒巖松。"]'),
('eee4d4e1-c4ff-49d5-a0f4-c6fcf931fbf5','和蕭太山韻相士李月齋','釋道璨','宋','宋诗','song-poetry','','[]','心明於月過於月，廣寒有殿無城闕。',80,'全唐诗/poet.song.228000.json','["心明於月過於月，廣寒有殿無城闕。", "不須更服九轉丹，目光射人如月寒。", "凌烟閣上公侯像，未必肩如山字樣。", "玉川地上蟣虱臣，未必文章非此人。", "口眼分明天不夜，輸與月齋擅聲價。"]'),
('a9dd1b60-c4de-4e2f-b502-3a5e54801a45','和滄洲尚書送坦上人','釋道璨','宋','宋诗','song-poetry','','[]','貂蟬換却章甫冠，十年出入鵷行間。',96,'全唐诗/poet.song.228000.json','["貂蟬換却章甫冠，十年出入鵷行間。", "天門九重虎豹惡，手携諫疏歸掩關。", "白鷗浩蕩滄波闊，冷看諸公治三窟。", "庭院無人春日長，尚記向來頻往復。", "平生眼裏無機雲，建安餘子不足吞。", "剔起枝葉見根本，上人將底酬公恩。"]'),
('7d5653ae-aa05-4a6b-b076-6f7e0d958b0b','題饒德操關子長紫芝詩軸','釋道璨','宋','宋诗','song-poetry','','[]','郭家墓田土花碧，輪菌紫芝大盈尺。',96,'全唐诗/poet.song.228000.json','["郭家墓田土花碧，輪菌紫芝大盈尺。", "淋浪雨淚種得成，不識春風生長力。", "晴雲練練依遥岑，霽月烱烱懸崖陰。", "苦心實竹誰賞識，青山重疊黄泉深。", "兩翁落筆九天上，發煇潛德光千丈。", "此卷長留天地間，靈芝萬古常無恙。"]'),
('f67420e2-d7fc-4790-afcc-a54529b0f633','送誠上人','釋道璨','宋','宋诗','song-poetry','','[]','長安城頭秋日黄，長安道上秋風凉。',128,'全唐诗/poet.song.228000.json','["長安城頭秋日黄，長安道上秋風凉。", "游子念親從定起，一衲卷雲歸故鄉。", "七月八月吳楚路，十里五里東南疆。", "遥知子母相見處，籬落黄花吹晚香。", "我母今年六十四，千丈白髮應滄浪。", "石田茆屋歸未得，西山幾度明斜陽。", "因送君行發深省，天地闊遠愁茫茫。", "他年相尋君勿忘，楊柳當門水滿塘。"]'),
('6fb0e031-8286-4392-8fc6-9c50e2b399ab','題善住閣','釋道璨','宋','宋诗','song-poetry','','[]','閣前溪水聲潺湲，閣後山色空巑岏。',128,'全唐诗/poet.song.228000.json','["閣前溪水聲潺湲，閣後山色空巑岏。", "取之不得舍不得，善住道人如是觀。", "浩蕩春風滿天地，飛絮游絲無定處。", "去無所至來無蹤，善住道人如是住。", "有所住兮成守株，魚止濼兮鳥栖蘆。", "無所住兮成漫浪，空中迹兮鏡中像。", "道人一笑璨琳琅，住不住兮吾已忘。", "閒倚闌干春晝長，眼看白鳥浮滄浪。"]'),
('6890e43c-fb6d-46cd-8195-0e8fcccc9441','題和山推蓬看梅','釋道璨','宋','宋诗','song-poetry','','[]','沙頭寒聲入蘆葦，沙際暝烟濕微雨。',144,'全唐诗/poet.song.228000.json','["沙頭寒聲入蘆葦，沙際暝烟濕微雨。", "疎花明在樹梢頭，吟身卧在船蓬底。", "相看一笑大江橫，白鳥不飛天似水。", "逃禪英骨閟九原，褚郎有神呼得起。", "倔强橫枝不受屈，玲瓏孤標浄如洗。", "春風滿面吹不開，冰雪滿身凍不死。", "歲寒心事誰得知，大似和山隠君子。", "我有扁舟簑笠盟，落在吳頭并楚尾。", "挑燈今夜不成眠，免得相尋來夢裏。"]'),
('c8f96910-c529-4112-b3bc-dbe44b7e6512','寄題趙山台蓮花方丈','釋道璨','宋','宋诗','song-poetry','','[]','四壁縱橫都十尺，門對若耶溪水碧。',64,'全唐诗/poet.song.228000.json','["四壁縱橫都十尺，門對若耶溪水碧。", "畫闌漠漠吹香風，綠窗練練浮秋色。", "中有詩家白玉顔，飲露沐芳度朝夕。", "當軒大坐眼波橫，只許詩人來入室。"]'),
('6917fcca-6db0-44b5-87c3-7845a6c13d9d','和鄭半溪','釋道璨','宋','宋诗','song-poetry','','[]','詞林丈夫安晚氏，筆端有口吞餘子。',64,'全唐诗/poet.song.228000.json','["詞林丈夫安晚氏，筆端有口吞餘子。", "阿戎在傍橫點頭，萬言不直一杯水。", "文詞於道祇毫芒，枉勞平生兩鬢蒼。", "落花植實願自□，□□□□□□□。"]'),
('5c5f66e1-854e-4512-b81c-155a0f692636','和騰可趙司戶','釋道璨','宋','宋诗','song-poetry','','[]','可人久別喜逢迎，分坐南窗曉放晴。',64,'全唐诗/poet.song.228000.json','["可人久別喜逢迎，分坐南窗曉放晴。", "竹所多時無此樂，梅兄一笑讓渠清。", "字如晉樣神饒韻，詩比唐人語更精。", "雋永韋編有真味，更須分我一杯羹。"]'),
('5c110ece-30c7-4954-bba2-43e3062063b4','賦張寺丞樗寮','釋道璨','宋','宋诗','song-poetry','','[]','樗寮先生千載士，草木有誰同臭味。',160,'全唐诗/poet.song.228000.json','["樗寮先生千載士，草木有誰同臭味。", "外無刀斧斫削痕，中有冰霜不老氣。", "紅紫紛紛滿上林，我自無心趁桃李。", "蘇秦張儀自縱橫，寵辱不驚魯連氏。", "梁棟峨峨入阿閣，我自無心爲杞梓。", "杜喬李固自黨錮，網羅不及徐孺子。", "故家喬木百世陰，有此孫枝能蔽芾。", "落去英華植本根，深培不朽聖賢事。", "犧尊青黄互翻覆，眼看世事如醒醉。", "願言善保丘壑姿，留取清風在天地。"]'),
('51a30311-d50d-4a00-af3d-78dd05ef9213','樗寮生日','釋道璨','宋','宋诗','song-poetry','','[]','長庚流煇千丈强，斗南夜氣浮耿光。',192,'全唐诗/poet.song.228000.json','["長庚流煇千丈强，斗南夜氣浮耿光。", "晉唐以前舊人物，翩然乘風下大荒。", "平生厭官不愛做，自歌招隠山中住。", "後園明月手自鋤，多種山前老梅樹。", "歲寒心事梅花清，滄浪白髮梅花明。", "有時指花對客道，此是吾家難弟兄。", "上國春風醉桃李，過眼紛紛付流水。", "禁得清寒耐後霜，幽獨何曾有如許。", "今年枝間著子無，黄金作顆應纍纍。", "想見日長庭院靜，時時繞枝如哺雛。", "摘來不用供調鼎，且喚麯生相管領。", "等閒一醉一千年，莫遣東風吹酒醒。"]'),
('bc29bcf5-ec8e-4501-bb93-ad2c4426e957','和余山南僉判清溪觀荷','釋道璨','宋','宋诗','song-poetry','','[]','東風已老南風急，浪蕊浮花和露泣。',240,'全唐诗/poet.song.228000.json','["東風已老南風急，浪蕊浮花和露泣。", "翠袖盈盈波上來，相向美人如玉立。", "軒渠一笑俱動容，彼此一樣冰雪蹤。", "明珠散不論斛斗，清溪化作驪龍宮。", "大江以東北山北，時樣新粧皆失色。", "古心一寸誰得知，江上晚來數峰碧。", "普天之下率土濱，容著不盡胸中春。", "濂溪愛花我愛葉，難將此意輕語人。", "探尋勝處到深杳，兩眼眈眈天地小。", "不離枝葉見花實，紅白紛紛跡如埽。", "膝間不著無絃琴，酒中清濁時自斟。", "興寄超然八方內，身在水流香世界。", "綠雲冉冉撥不開，樂地可中能許大。", "中通外直真絕奇，一語能覺千古迷。", "二百年後誰傳衣，清溪滾滾通濂溪。"]'),
('d4db3c7c-d63b-42dc-9024-c7197dd27419','和陳東廬提幹','釋道璨','宋','宋诗','song-poetry','','[]','髮白爲憂時，思家日念歸。',48,'全唐诗/poet.song.228000.json','["髮白爲憂時，思家日念歸。", "涉春問行李，隔歲理征衣。", "夜雨繙書屋，秋風把釣磯。", "叮嚀舊僮僕，拂拭蘚痕微。"]'),
('ca3e1012-3891-473d-bfee-c28be450a29e','和吳山泉知府','釋道璨','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','亂來誰訪古，杖屨竹邊聞。',48,'全唐诗/poet.song.228000.json','["亂來誰訪古，杖屨竹邊聞。", "小立真堪畫，閒談亦自文。", "長翁千載語，中允百年墳。", "寂寞廬山下，幽尋獨有君。"]'),
('9b777ae5-4e21-4ca0-a0e6-96ee2c11507b','和馮叔炎梅桂二首  其一','釋道璨','宋','宋诗','song-poetry','','[]','色香俱第一，知己是華光。',48,'全唐诗/poet.song.228000.json','["色香俱第一，知己是華光。", "風味嫌膚淺，精神貴斂藏。", "一生雖抱獨，千古却流芳。", "若論調羹事，還他一日長。"]'),
('80b3f93f-5f22-4784-9826-ebd87051d953','和馮叔炎梅桂二首  其二','釋道璨','宋','宋诗','song-poetry','','[]','風露透枝葉，團團翠滿坡。',48,'全唐诗/poet.song.228000.json','["風露透枝葉，團團翠滿坡。", "但教秋思足，不必月明多。", "騷在誰招隠，山空自放歌。", "故家射科手，折取莫蹉跎。"]'),
('e4123e2a-cfc8-48c7-8a67-11d8e41cf076','和致軒送余魁','釋道璨','宋','宋诗','song-poetry','','[]','眉睫功名氣，筆端天地春。',48,'全唐诗/poet.song.228000.json','["眉睫功名氣，筆端天地春。", "孰知心念苦，祇與聖賢親。", "味淡有真樂，眼高無古人。", "金鸞行夜直，坐聽漏聲頻。"]'),
('48911364-0c8f-430d-9b36-41ef9b9a730c','哭馮深居常簿','釋道璨','宋','宋诗','song-poetry','','[]','泛宅江湖上，蕭蕭兩鬢皤。',48,'全唐诗/poet.song.228000.json','["泛宅江湖上，蕭蕭兩鬢皤。", "祇知衣可典，不厭客來多。", "文富家安有，名高實若何。", "身前身後事，令我起悲歌。"]'),
('d987d09c-fa8e-4438-91af-d15a5bbea877','致軒趙使君領客及妻子入山即事原韻','釋道璨','宋','宋诗','song-poetry','','[]','戴家湖上宅，近市有山林。',48,'全唐诗/poet.song.228000.json','["戴家湖上宅，近市有山林。", "雨足四郊潤，雲低盡日陰。", "竹疎和翠減，松老受春深。", "留得行窩住，樓頭午漏沉。"]'),
('9774691a-ead6-4a40-9693-e37275bdef23','和致軒趙使君午日讀騷','釋道璨','宋','宋诗','song-poetry','','[]','君王愛不均，不信問江濱。',48,'全唐诗/poet.song.228000.json','["君王愛不均，不信問江濱。", "却是一江水，能知千載人。", "仲連寧蹈海，百里忍之秦。", "先死依蘭芷，還他不二臣。"]'),
('8365a70d-ecc4-45b1-beda-0fde56366c26','西湖除夜','釋道璨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','又來上國看新元，細嚼梅花嚥冷泉。',64,'全唐诗/poet.song.228000.json','["又來上國看新元，細嚼梅花嚥冷泉。", "阿母在家年六十，孤兒爲客路三千。", "身居東海滄波上，心在西山落照邊。", "碧戶朱門楊柳岸，不知歸日是何年。"]'),
('0ca1c58c-8171-4515-9848-12df21956b5a','送松岡黄提幹','釋道璨','宋','宋诗','song-poetry','','[]','人物如公豈久淹，極和平處極森嚴。',64,'全唐诗/poet.song.228000.json','["人物如公豈久淹，極和平處極森嚴。", "無心爲祿長思去，直道從人肯避嫌。", "學務躬行惟恐失，貧於未仕不言廉。", "書邊大有閒田地，有口從今只學鉗。"]'),
('eda00ac7-fcb5-49bf-bca9-06fa4bdd9544','和恕齋吳提刑秋陽菴居','釋道璨','宋','宋诗','song-poetry','','[]','截斷人間名利塵，橫塘深碧護新墳。',64,'全唐诗/poet.song.228000.json','["截斷人間名利塵，橫塘深碧護新墳。", "昏明不定霜天月，開合無心竹屋雲。", "風雨對床差可喜，乾坤萬事不堪聞。", "栽松種竹閒功課，却爲憂時一半分。"]'),
('0111d573-96cf-4191-bfc4-7ec1b6971ad2','和鄧講書','釋道璨','宋','宋诗','song-poetry','','[]','楊柳陰陰水一涯，無邊天地入窗紗。',64,'全唐诗/poet.song.228000.json','["楊柳陰陰水一涯，無邊天地入窗紗。", "土階過雨苔生潤，竹逕無人草自花。", "聖處工夫期我立，吟邊生活頼成家。", "夜來夢泛滄浪水，兩袖清風釣岸沙。"]'),
('5c715073-4d1f-4bc5-a9d1-abb68d4a0fc9','賀恕齋除兵部侍郎','釋道璨','宋','宋诗','song-poetry','','[]','面無老色氣精明，南海歸來住未成。',64,'全唐诗/poet.song.228000.json','["面無老色氣精明，南海歸來住未成。", "不道山中無宰相，要從恕上做功名。", "雲屯萬騎西風急，月浸三更夜柝清。", "謀國定知有長算，胡雛不樹向南旌。"]'),
('4d0c99ca-8564-4714-8c8b-eac0e17ba389','和謝君澤題弋陽桃花寺并弔鄭盤翁','釋道璨','宋','宋诗','song-poetry','','[]','一曲清溪十二闌，分明常在畫中安。',64,'全唐诗/poet.song.228000.json','["一曲清溪十二闌，分明常在畫中安。", "千年藥竈和雲暖，五色丹光徹夜寒。", "魂夢不來懷好友，山居能久是蒼官。", "葛翁顔色紅如染，不信桃花樹上看。"]'),
('512daa18-7771-4f96-ad1c-77f10a29bfea','和楊在軒劑院','釋道璨','宋','宋诗','song-poetry','','[]','箭下曾親一鵠來，一簑風雨霅川回。',64,'全唐诗/poet.song.228000.json','["箭下曾親一鵠來，一簑風雨霅川回。", "近詩不逐唐聲變，燕服多依晉樣裁。", "竹屋逢僧閒煮茗，梅邊領客慣行盃。", "終當夜直金鸞去，要試平生倚馬才。"]'),
('15ecdfc5-c584-4f2d-956c-3d016c7d23e8','和君澤謝主簿','釋道璨','宋','宋诗','song-poetry','','[]','掉臂紛紛桃李場，聲名暴耀急收藏。',64,'全唐诗/poet.song.228000.json','["掉臂紛紛桃李場，聲名暴耀急收藏。", "春風未解瞻顔色，落月長思滿屋梁。", "大學十年心獨苦，天門一疏日爭光。", "弟兄千載詩書澤，染得人間草木香。"]'),
('14ffeddc-4451-49f4-921d-b073dc05d0df','和耕道趙制幹與賈秋壑同科','釋道璨','宋','宋诗','song-poetry','','[]','家近芝山傍淡湖，城居清似隠人廬。',64,'全唐诗/poet.song.228000.json','["家近芝山傍淡湖，城居清似隠人廬。", "凌煙閣上同年在，光範門前一字無。", "信口語言多得忌，謀身術數不嫌疎。", "人生要是閒中好，軒冕何須苦見拘。"]'),
('42e635fc-a1e1-4e72-aace-867b52d2cef1','和謝君直新除史館檢閲','釋道璨','宋','宋诗','song-poetry','','[]','久矣常峨豸角冠，未應上綴史臣班。',64,'全唐诗/poet.song.228000.json','["久矣常峨豸角冠，未應上綴史臣班。", "名高自是難推去，才大如何愛得閒。", "齋閣不須垂絳帳，精神留取上蓬山。", "散人夢落滄浪外，白鳥冥冥去不還。"]'),
('c1dd58da-f56e-4be5-aa95-ae4ed233dbad','和山泉喜雪','釋道璨','宋','宋诗','song-poetry','','[]','高下隨風自在吹，縱橫萬里急還遲。',64,'全唐诗/poet.song.228000.json','["高下隨風自在吹，縱橫萬里急還遲。", "園林頃刻生春意，天地中間有此奇。", "深入重城垂縛處，不持寸刃令行時。", "夜來竹外生盈尺，凍損梅花人未知。"]'),
('c97154d6-3ba2-4acd-b508-e2c2d2d211f6','和春谷趙泉使賀端齋趙憲使喜雪','釋道璨','宋','宋诗','song-poetry','','[]','蕊宮仙子下明湖，剪水桃花更滴酥。',64,'全唐诗/poet.song.228000.json','["蕊宮仙子下明湖，剪水桃花更滴酥。", "潔白十分天下瑞，光明一片剡溪圖。", "園林春到何嫌早，閶闔雲開不待呼。", "方寸去天纔尺五，笑他上界覓玄都。"]'),
('b12677ba-2ef8-4071-b28a-3b2dac990779','和菊隠陳知縣西庵有感','釋道璨','宋','宋诗','song-poetry','','[]','輕雲卷雨過簷牙，楊柳池塘合亂蛙。',64,'全唐诗/poet.song.228000.json','["輕雲卷雨過簷牙，楊柳池塘合亂蛙。", "四壁月華春夜永，一年風物此時嘉。", "詩當淡處工差退，心到平時語不誇。", "睡眼醒來人不見，杏花散影滿窗紗。"]'),
('457f6982-8c12-41cd-8905-ed7b0875480b','上安晚節丞相三首  其一','釋道璨','宋','宋诗','song-poetry','','[]','相國歸來卧舊山，功名雖好不如閒。',32,'全唐诗/poet.song.228000.json','["相國歸來卧舊山，功名雖好不如閒。", "向來北望中原眼，送在滄波白鳥間。"]'),
('01cfe145-cd38-4ef8-9231-d9be3012911b','上安晚節丞相三首  其二','釋道璨','宋','宋诗','song-poetry','','[]','清於獨鶴瘦於梅，小袖春衫晉樣裁。',32,'全唐诗/poet.song.228000.json','["清於獨鶴瘦於梅，小袖春衫晉樣裁。", "推出柴車人不指，前身曾住洛中來。"]'),
