('f779e3ed-aeae-4a8d-888f-ae78834c2a8e','偈頌十八首  其六','釋道璨','宋','宋诗','song-poetry','','[]','即心即佛，山無重數。',49,'全唐诗/poet.song.228000.json','["即心即佛，山無重數。", "非心非佛，水無重數。", "不是心不是佛，白雲又無重數。", "薦福恁麽告報，灞陵橋上望西川。"]'),
('e19a0c82-7dbf-4814-9e47-4bfc07d05f45','偈頌十八首  其七','釋道璨','宋','宋诗','song-poetry','','[]','寒一上，熱一上。',24,'全唐诗/poet.song.228000.json','["寒一上，熱一上。", "普通年事只在，于今更無三般兩樣。"]'),
('fc262aaf-1550-4d0d-8041-0b1b5239eb5a','偈頌十八首  其八','釋道璨','宋','宋诗','song-poetry','','[]','臨濟處一杓，末山處半杓。',38,'全唐诗/poet.song.228000.json','["臨濟處一杓，末山處半杓。", "玉本無暇，妄自雕琢。", "有年無德老睦州，無端拶折雲門脚。"]'),
('c921f92a-c72b-49af-93bf-5a0a64847d02','偈頌十八首  其九','釋道璨','宋','宋诗','song-poetry','','[]','玉關度了久班師，猶向人前動鼓鼙。',32,'全唐诗/poet.song.228000.json','["玉關度了久班師，猶向人前動鼓鼙。", "只道馬行荒草地，不知身已陷重圍。"]'),
('3b69b28b-fc8e-4a28-9561-deb258a10927','偈頌十八首  其一○','釋道璨','宋','宋诗','song-poetry','','[]','閙浩浩，閑寂寂。',48,'全唐诗/poet.song.228000.json','["閙浩浩，閑寂寂。", "不動一絲頭，如對萬人敵。", "惺惺直是惺惺，歷歷直是歷歷。", "捉象亦全其力，捉兔亦全其力。"]'),
('9df42ce2-af7a-4d58-b14f-1a4c4d74e293','偈頌十八首  其一一','釋道璨','宋','宋诗','song-poetry','','[]','符不書，藥不採。',36,'全唐诗/poet.song.228000.json','["符不書，藥不採。", "起死禁不祥，幸有這箇在。", "滿院薰風夏日長，人在藕花香世界。"]'),
('a09ed79c-b2dd-4c8d-b7a3-ecaeb4cca7bb','偈頌十八首  其一二','釋道璨','宋','宋诗','song-poetry','','[]','秋深夜長，露寒月皎。',55,'全唐诗/poet.song.228000.json','["秋深夜長，露寒月皎。", "鐘聲短底短長底長，蟲聲大底大小底小。", "山僧聞得，展轉反側，不寐到曉。", "一片祖師心，狼藉知多少。"]'),
('b733360d-824d-4c15-88ad-271fc8847acf','偈頌十八首  其一三','釋道璨','宋','宋诗','song-poetry','','[]','至日書雲，雲作何色。',20,'全唐诗/poet.song.229000.json','["至日書雲，雲作何色。", "眼裏無筋，青黄赤白。"]'),
('6c5ce596-67cf-44ca-928f-fcda9c481f02','偈頌十八首  其一四','釋道璨','宋','宋诗','song-poetry','','[]','江月照，松風吹，永夜清宵何所爲。',16,'全唐诗/poet.song.229000.json','["江月照，松風吹，永夜清宵何所爲。"]'),
('7d492db9-ab99-4a17-ba53-f2e7769d1b6a','偈頌十八首  其一五','釋道璨','宋','宋诗','song-poetry','','[]','漏盡夜沉沉，山房風露深。',24,'全唐诗/poet.song.229000.json','["漏盡夜沉沉，山房風露深。", "無雲生嶺上，有月落波心。"]'),
('986ac1ae-ab77-40b1-b6dd-2fcbce17fb91','偈頌十八首  其一六','釋道璨','宋','宋诗','song-poetry','','[]','道在目前，全無罅縫。',28,'全唐诗/poet.song.229000.json','["道在目前，全無罅縫。", "左之右之，百發百中。", "是風動，是旛動。"]'),
('e4cee9e2-3f47-41ac-8247-d830cc9c0829','偈頌十八首  其一七','釋道璨','宋','宋诗','song-poetry','','[]','臨濟四料揀，洞山四賓主。',40,'全唐诗/poet.song.229000.json','["臨濟四料揀，洞山四賓主。", "甜瓜徹蒂甜，苦瓠連根苦。", "倒腹傾腸說向人，恰似杏花枝上雨。"]'),
('41380ecf-1bf2-441d-b7e5-0fa873a6f592','偈頌十八首  其一八','釋道璨','宋','宋诗','song-poetry','','[]','登芝山，望五老。',68,'全唐诗/poet.song.229000.json','["登芝山，望五老。", "雲靜日月正，眼高天地小。", "達磨大師脊骨等閑踏折，釋迦老子心肝五臟一時見了。", "因思擾擾塵寰，茫茫宇宙。", "手把夜明符，幾箇知天曉。"]'),
('e6f37931-a621-441d-b8da-0bcffd80a12a','偈頌十二首  其一','釋道璨','宋','宋诗','song-poetry','','[]','無箇入處，奔走殺人。',20,'全唐诗/poet.song.229000.json','["無箇入處，奔走殺人。", "有箇入處，礙塞殺人。"]'),
('6a9cdfc3-a984-45f5-9fe8-9976d35145ea','偈頌十二首  其二','釋道璨','宋','宋诗','song-poetry','','[]','五日風，十日雨。',48,'全唐诗/poet.song.229000.json','["五日風，十日雨。", "江面不驚，邊烽不舉。", "眼前漸見太平，耳畔多聞好雨。", "山人只管看青山，有口不須吞佛祖。"]'),
('c58e70f7-0528-4f91-8990-f58888e930d5','偈頌十二首  其三','釋道璨','宋','宋诗','song-poetry','','[]','一言已出駟難追，道了如何悔得來。',32,'全唐诗/poet.song.229000.json','["一言已出駟難追，道了如何悔得來。", "冷地被人相訐露，牙關咬定口慵開。"]'),
('03c1d2e0-c2d9-457e-9f92-14f8a71de4f3','偈頌十二首  其四','釋道璨','宋','宋诗','song-poetry','','[]','擾擾匆匆，晨雞暮鐘。',36,'全唐诗/poet.song.229000.json','["擾擾匆匆，晨雞暮鐘。", "喚冬作夏，喚夏作冬。", "一線短長誰管得，雪霜盡處是春風。"]'),
('35df514e-fad8-4599-8c58-9959ce1a3ef3','偈頌十二首  其五','釋道璨','宋','宋诗','song-poetry','','[]','睚到虛空粉碎時，空花一任眼前飛。',32,'全唐诗/poet.song.229000.json','["睚到虛空粉碎時，空花一任眼前飛。", "若還別覓安心法，客路漫漫何處歸。"]'),
('6cf19c07-3903-4edf-8de6-f6e7469cd996','偈頌十二首  其六','釋道璨','宋','宋诗','song-poetry','','[]','今日則有，明日則無。',65,'全唐诗/poet.song.229000.json','["今日則有，明日則無。", "天何高，地何極。", "謂吾滅度，謂吾不滅度。", "一箇死屍，許多狼藉。", "我觀靈山百萬大衆，惟波旬却有丈夫氣息，面赤不如語直。"]'),
('8adf671a-924b-41da-aa09-2dc4209e9209','偈頌十二首  其七','釋道璨','宋','宋诗','song-poetry','','[]','臨濟一喝，德山一棒。',20,'全唐诗/poet.song.229000.json','["臨濟一喝，德山一棒。", "霹靂電光，寧容近傍。"]'),
('378abf9d-a052-449d-81b2-befb6e19bb22','偈頌十二首  其八','釋道璨','宋','宋诗','song-poetry','','[]','不撥一境，不露一機。',20,'全唐诗/poet.song.229000.json','["不撥一境，不露一機。", "錦包特石，綿裹秤椎。"]'),
('af0e4fec-413f-4f94-93e1-eac52e1d1d4f','偈頌十二首  其九','釋道璨','宋','宋诗','song-poetry','','[]','天晴蓋却屋，乘時刈却禾。',36,'全唐诗/poet.song.229000.json','["天晴蓋却屋，乘時刈却禾。", "輸納王租了，秋冬事轉多。", "阿呵呵，喚不回頭爭奈何。"]'),
('260ab925-9d1f-4375-be44-746a82f9de7f','偈頌十二首  其一○','釋道璨','宋','宋诗','song-poetry','','[]','土木場中輥一回，平生己眼豁然開。',32,'全唐诗/poet.song.229000.json','["土木場中輥一回，平生己眼豁然開。", "廣寒宮殿無關鑰，撞破髑髏歸去來。"]'),
('5a0f1e94-6b94-4861-94c0-e227948367ec','偈頌十二首  其一一','釋道璨','宋','宋诗','song-poetry','','[]','一冬不雨，一春不雨。',65,'全唐诗/poet.song.229000.json','["一冬不雨，一春不雨。", "九土皆焦枯，天高叫無路。", "開先拄杖子忽然變作空行龍王，油然起雲霈然洪澍。", "直得枯者榮甲者拆萌者吐，發機須是千鈞弩。"]'),
('92e1fcaf-655a-48f1-bcbb-7e05cff19602','偈頌十二首  其一二','釋道璨','宋','宋诗','song-poetry','','[]','肥不剩肉，瘦不露骨。',22,'全唐诗/poet.song.229000.json','["肥不剩肉，瘦不露骨。", "動地放光明，眼睛烏律律。"]'),
('6f9583cc-9367-4d54-82d1-ff4842675a0f','偈頌二十五首  其一','釋道璨','宋','宋诗','song-poetry','','[]','去去實不去，是法住法位。',24,'全唐诗/poet.song.229000.json','["去去實不去，是法住法位。", "來來實不來，世間相常住。"]'),
('621f658a-bbae-472d-8654-5995919ffca4','偈頌二十五首  其二','釋道璨','宋','宋诗','song-poetry','','[]','桃花無數，李花無數。',73,'全唐诗/poet.song.229000.json','["桃花無數，李花無數。", "若向這裏活眼不開，平地上死人更是無數。", "去年踏青人今年不來，今年上墳底明年何處。", "日月急如梭，生死無定據。", "謹白參玄人，光陰莫虛度。"]'),
('f16dcc49-0818-4bbe-bbf9-d819bdb46065','偈頌二十五首  其三','釋道璨','宋','宋诗','song-poetry','','[]','趺坐疊足，問訊起手。',37,'全唐诗/poet.song.229000.json','["趺坐疊足，問訊起手。", "眼若透青，一見便了。", "更待說心說性，山僧未曾問人借得口。"]'),
('25a1bf80-c3eb-4aec-98c2-d757c605a2db','偈頌二十五首  其四','釋道璨','宋','宋诗','song-poetry','','[]','風蕭蕭，雨蕭蕭。',73,'全唐诗/poet.song.229000.json','["風蕭蕭，雨蕭蕭。", "天高地厚，水闊山遥。", "達磨大師無端遊梁歷魏，二祖大師平白失了一臂。", "水潦和尚不合喫馬師一踏，天下大禪佛枉自喫了四藤條，說著令人恨不消。"]'),
('5842e1f8-d3da-4247-bccf-36df7e14e7da','偈頌二十五首  其五','釋道璨','宋','宋诗','song-poetry','','[]','靜處具足閙中境界，閙處顯示靜中消息。',58,'全唐诗/poet.song.229000.json','["靜處具足閙中境界，閙處顯示靜中消息。", "達磨面壁少林，普化摇鈴閙市。", "皆是眼觀東南，意在西北。", "若是向上巴鼻，畢竟何曾會得。"]'),
('f0dd6dab-2085-4919-a5bf-f93b72c1be8c','偈頌二十五首  其六','釋道璨','宋','宋诗','song-poetry','','[]','今日雨，明日雨。',36,'全唐诗/poet.song.229000.json','["今日雨，明日雨。", "春流岸岸深，屋漏無乾處。", "魯公亭上望番城，祇有湖水無行路。"]'),
('26eb1138-00e7-4f76-9464-05ed42304928','偈頌二十五首  其七','釋道璨','宋','宋诗','song-poetry','','[]','一出五六月，往返三千里。',58,'全唐诗/poet.song.229000.json','["一出五六月，往返三千里。", "信脚踢得著，信手提得起。", "不曾輕示人，深藏懷袖裏。", "歸來普請大衆做箇入門歡，是什麽浙東山浙西水。"]'),
('7824551d-43f2-459d-a6e8-8dcd7170845d','偈頌二十五首  其八','釋道璨','宋','宋诗','song-poetry','','[]','仰山撼樹，溈山良久。',20,'全唐诗/poet.song.229000.json','["仰山撼樹，溈山良久。", "說體說用，互揚家醜。"]'),
('91dc9ff5-ff24-400f-9cfd-38c357c4b015','偈頌二十五首  其九','釋道璨','宋','宋诗','song-poetry','','[]','開眼便是，開口便是。',30,'全唐诗/poet.song.229000.json','["開眼便是，開口便是。", "舉手便是，舉足便是。", "雖然如是，未是未是。"]'),
('7ae954ad-be89-413f-9f9d-085ece11902f','偈頌二十五首  其一○','釋道璨','宋','宋诗','song-poetry','','[]','百不知，百不會，喫飽飯，熟打睡。',31,'全唐诗/poet.song.229000.json','["百不知，百不會，喫飽飯，熟打睡。", "要得剋期，取燈取燈，如是三昧。"]'),
('973ea64e-d265-4fa5-8d3b-c65c20943fab','偈頌二十五首  其一一','釋道璨','宋','宋诗','song-poetry','','[]','如來禪，祖師意。',28,'全唐诗/poet.song.229000.json','["如來禪，祖師意。", "兒啼子哭，雞鳴犬吠。", "是汝諸人，瞥地也未。"]'),
('a3fbe27a-220a-458c-85cf-637d8f41a295','偈頌二十五首  其一二','釋道璨','宋','宋诗','song-poetry','','[]','堂奧雖深無鎖鑰，包容大地與山河。',32,'全唐诗/poet.song.229000.json','["堂奧雖深無鎖鑰，包容大地與山河。", "草窠裏輥人多少，喚不回頭爭奈何。"]'),
('e59d4558-80fb-4018-b92f-0d1fcff6d8e6','偈頌二十五首  其一三','釋道璨','宋','宋诗','song-poetry','','[]','京師出大黄，價直極相當。',24,'全唐诗/poet.song.229000.json','["京師出大黄，價直極相當。", "未曾識道地，枉自費商量。"]'),
('fadd5aee-4368-48c3-af2a-fb4cd559fd45','偈頌二十五首  其一四','釋道璨','宋','宋诗','song-poetry','','[]','放開也在我，捏聚也在我。',24,'全唐诗/poet.song.229000.json','["放開也在我，捏聚也在我。", "睦州擔板漢，開口成話墮。"]'),
('6537ebf4-525a-44be-8774-fce2aad07936','偈頌二十五首  其一五','釋道璨','宋','宋诗','song-poetry','','[]','溪東是國王水草，溪西是國王水草。',58,'全唐诗/poet.song.229000.json','["溪東是國王水草，溪西是國王水草。", "隨分納些些，佛法休尋討。", "堪笑水潦和尚，枉被馬師踏倒。", "薦福與麽告報，猶較王老師一線道。"]'),
('83e1c1b5-798c-4b50-b29c-817e55418bc6','偈頌二十五首  其一六','釋道璨','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','篷底欹眠醉復醒，君山只在兩眉青。',32,'全唐诗/poet.song.229000.json','["篷底欹眠醉復醒，君山只在兩眉青。", "渾家不管興亡事，一味和雲看洞庭。"]'),
('c20d7df5-e64c-47a5-a4b4-8b27a4baae9e','偈頌二十五首  其一七','釋道璨','宋','宋诗','song-poetry','','[]','語言上著到，身心上著到。',24,'全唐诗/poet.song.229000.json','["語言上著到，身心上著到。", "要透納僧關，料掉復料掉。"]'),
('ad825fe7-9705-467c-91e0-d9c34d2a50ec','偈頌二十五首  其一八','釋道璨','宋','宋诗','song-poetry','','[]','天地一東籬，萬古一重九。',48,'全唐诗/poet.song.229000.json','["天地一東籬，萬古一重九。", "黄花三兩枝，東湖隨分有。", "逢人不拈出，只麽空雙手。", "醉殺天下人，不是茱萸酒。"]'),
('3a408105-af8f-42e6-9b4e-c4de6c2b0952','偈頌二十五首  其一九','釋道璨','宋','宋诗','song-poetry','','[]','重圍身入脫身難，再拜投降得活還。',32,'全唐诗/poet.song.229000.json','["重圍身入脫身難，再拜投降得活還。", "手脚一時都露了，如何遮掩得傍觀。"]'),
('a75929b0-79df-4342-aebc-1943b4797f19','偈頌二十五首  其二○','釋道璨','宋','宋诗','song-poetry','','[]','釋迦不是佛，達磨不是祖。',40,'全唐诗/poet.song.229000.json','["釋迦不是佛，達磨不是祖。", "佛法滿天下，諸人還知否。", "青草池頭處處蛙，黄梅時節家家雨。"]'),
('4faab66d-a693-4c24-bcc2-29b3ccd9d8fa','偈頌二十五首  其二一','釋道璨','宋','宋诗','song-poetry','','[]','諸人病是山僧病，山僧病是諸人病。',53,'全唐诗/poet.song.229000.json','["諸人病是山僧病，山僧病是諸人病。", "諸人痛處山僧能忍，山僧痛處諸人欲忍不能。", "單方一服當下和平，不必松根採茯苓。"]'),
('db961956-d1ce-4973-b677-b42bdaf681bd','偈頌二十五首  其二二','釋道璨','宋','宋诗','song-poetry','','[]','北人偶與南人會，借問如何喫荔枝。',32,'全唐诗/poet.song.229000.json','["北人偶與南人會，借問如何喫荔枝。", "口未開時先話墮，香甜二字且酬伊。"]'),
('e266eb99-bcdf-4176-a829-9ca902e95dd2','偈頌二十五首  其二三','釋道璨','宋','宋诗','song-poetry','','[]','信口道一句，栗棘金圈皆露布。',65,'全唐诗/poet.song.229000.json','["信口道一句，栗棘金圈皆露布。", "信脚行一步，柳陌花衢非活路。", "未開口，未舉足，已前薦得，許你有箇入頭處。", "東湖一箭落雙鵰，鳳棲不在梧桐樹。"]'),
('644e64f4-530d-49d5-9c41-898380c2b476','偈頌二十五首  其二四','釋道璨','宋','宋诗','song-poetry','','[]','無蒲團禪板與諸人廝睚，無金圈栗蓬與諸人吞吐。',46,'全唐诗/poet.song.229000.json','["無蒲團禪板與諸人廝睚，無金圈栗蓬與諸人吞吐。", "水清月分明，雲散山呈露。", "山僧結夏來，贏得緊閉戶。"]'),
('b4702772-e69f-45ca-8dc1-350401111e2d','偈頌二十五首  其二五','釋道璨','宋','宋诗','song-poetry','','[]','雨不來，旱彌烈。',60,'全唐诗/poet.song.229000.json','["雨不來，旱彌烈。", "草木枯，金石裂。", "江流斷，井泉竭。", "盡大地，生意絕。", "東湖上，乾坤別。", "最清凉，無惱熱。", "優曇花正開，清香來不徹。"]'),
('277abfe5-0676-4be8-9702-5ac577cc667c','觀音讚','釋道璨','宋','宋诗','song-poetry','','[]','聲以眼聞，色以耳見。',44,'全唐诗/poet.song.229000.json','["聲以眼聞，色以耳見。", "下與衆生同一悲仰，上與諸佛同一悲願。", "大海枯，磐石爛，我此大心方了辦。"]'),
('ddd1e7ab-7c08-4e0e-b9c4-e03ac38def8d','又','釋道璨','宋','宋诗','song-poetry','','[]','如嶼兮媚川，如山兮倚天。',26,'全唐诗/poet.song.229000.json','["如嶼兮媚川，如山兮倚天。", "大哉圓通之道，民無得而名焉。"]'),
('dad1ad9b-a938-4035-a3b8-b7205b8ea24f','布袋讚','釋道璨','宋','宋诗','song-poetry','','[]','布袋無口，拄杖無枝。',20,'全唐诗/poet.song.229000.json','["布袋無口，拄杖無枝。", "靠定這箇，有甚了期。"]'),
('5d12461d-c26d-40ab-9c68-91aaa8c7a730','又','釋道璨','宋','宋诗','song-poetry','','[]','明皎皎，暗昏昏。',32,'全唐诗/poet.song.229000.json','["明皎皎，暗昏昏。", "未曾舉首，爍破面門。", "若更停機停思，苦哉彌勒世尊。"]'),
('c05bfc25-0772-4792-90fc-515bb03c981b','寒拾讚','釋道璨','宋','宋诗','song-poetry','','[]','蒼崖鎖寒色，題目分明極。',40,'全唐诗/poet.song.229000.json','["蒼崖鎖寒色，題目分明極。", "無端書兩字，剗地失平仄。", "颺却筆，放却墨，一句了然超百億。"]'),
('c8592c1b-614b-439a-bb36-97ec7927da6a','又','釋道璨','宋','宋诗','song-poetry','','[]','淡墨磨虛空，禿筆蘸滄海。',24,'全唐诗/poet.song.229000.json','["淡墨磨虛空，禿筆蘸滄海。", "點污天台山，是他這一對。"]'),
('dcd4b049-ff63-4b47-b655-a9981b86d1bf','半身達磨讚','釋道璨','宋','宋诗','song-poetry','','[]','毒藥醫不活，風雪凍不死。',40,'全唐诗/poet.song.229000.json','["毒藥醫不活，風雪凍不死。", "自己欠一半，說甚傳宗旨。", "天自天，地自地，枉自東游十萬里。"]'),
('8e7a6dad-1fea-444e-aedf-b5a39010cc3f','臨濟讚','釋道璨','宋','宋诗','song-poetry','','[]','開眼受睦州廝瞞，甘心喫黄蘗痛棒。',102,'全唐诗/poet.song.229000.json','["開眼受睦州廝瞞，甘心喫黄蘗痛棒。", "握定拳以當平熱生，除一喝別無伎倆。", "何曾夢見無位真人，剛要滅却正法眼藏。", "見人家則盡情藉沒，併與性命一時掃蕩。", "不可聞名，如何近傍。", "自有佛法以至于今，少曾見有箇樣，不覩是底和尚。"]'),
('3d8fc9e5-5b03-4af5-aafc-5159cb143b48','商山四皓讚','釋道璨','宋','宋诗','song-poetry','','[]','橘大天地窄，眼高秦漢小。',24,'全唐诗/poet.song.229000.json','["橘大天地窄，眼高秦漢小。", "一片隠淪心，商山青未了。"]'),
('24e40c67-fe89-4688-b702-1fdf71e3692e','呂洞賓讚','釋道璨','宋','宋诗','song-poetry','','[]','提起絛頭，垂下衣袖。',22,'全唐诗/poet.song.229000.json','["提起絛頭，垂下衣袖。", "信脚闊步行，親見黄龍後。"]'),
('454431dc-c58b-437a-a7fd-da99efc1dee8','自讚  其一','釋道璨','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','頭小面狹，眼橫鼻直。',75,'全唐诗/poet.song.229000.json','["頭小面狹，眼橫鼻直。", "難親易忘，易見難識。", "剛道笑翁手脚緩慢，無準癡絕，尺寸短窄。", "視秦山喬嶽不過一拳，視長江大河不過一滴。", "西天此土要橫行，有祖以來無此僧。"]'),
('f52f69dc-812e-4007-9e98-b4040d5e7a00','自讚  其二','釋道璨','宋','宋诗','song-poetry','','[]','讀書不識字，行脚不會禪。',40,'全唐诗/poet.song.229000.json','["讀書不識字，行脚不會禪。", "有拳爺不識，有口佛不吞。", "惟康第一莫學他，學他陷汝到黄泉。"]'),
('143013a1-c553-46aa-9cd3-7593ab7e4926','佛成道','釋道璨','宋','宋诗','song-poetry','','[]','迷是誰兮悟是誰，山僧贏得眼如眉。',32,'全唐诗/poet.song.229000.json','["迷是誰兮悟是誰，山僧贏得眼如眉。", "新糊紙被烘來暖，睡到天明日上時。"]'),
('22c9cbb4-afc5-4059-9cd3-adda7d3ad770','釣雪','釋道璨','宋','宋诗','song-poetry','','[]','百尺竿頭一縷絲，沒提撕處急提撕。',32,'全唐诗/poet.song.229000.json','["百尺竿頭一縷絲，沒提撕處急提撕。", "離鈎三寸忽拋却，正是虛空粉碎時。"]'),
('b660a827-1c22-4263-9f0f-344e22476924','送東上人','釋道璨','宋','宋诗','song-poetry','','[]','上頭上面得人憎，少見生獰箇樣僧。',32,'全唐诗/poet.song.229000.json','["上頭上面得人憎，少見生獰箇樣僧。", "莫道無又輕放過，病來無力舉烏藤。"]'),
('02f5db3e-9833-461c-a961-938715ca2a67','贈禪客','釋道璨','宋','宋诗','song-poetry','','[]','空拳打入長蛇陣，殺氣連雲戰更酣。',32,'全唐诗/poet.song.229000.json','["空拳打入長蛇陣，殺氣連雲戰更酣。", "輥到了無交涉處，牛頭向北馬頭南。"]'),
('76278dce-7df2-42fb-9406-5d4fefbe4d50','贈相士','釋道璨','宋','宋诗','song-poetry','','[]','面如生鐵鑄崑崙，有底榮枯到你論。',32,'全唐诗/poet.song.229000.json','["面如生鐵鑄崑崙，有底榮枯到你論。", "謾說青青亭畔竹，春風幾箇有兒孫。"]'),
('519befb0-29c6-448b-a497-d28c9d0ca01d','一庵','釋道璨','宋','宋诗','song-poetry','','[]','萬法須從皈處參，難將皈處與人談。',32,'全唐诗/poet.song.229000.json','["萬法須從皈處參，難將皈處與人談。", "簷頭昨夜風和雨，說得分明落二三。"]'),
('41c535ab-8457-4867-8451-ee086b562b3f','送人之圓通','釋道璨','宋','宋诗','song-poetry','','[]','無數飛花舞曉風，天開二十五圓通。',32,'全唐诗/poet.song.229000.json','["無數飛花舞曉風，天開二十五圓通。", "要知門戶從何入，問取溪邊石耳峰。"]'),
('9dcdc6d3-4828-4190-8cbe-748ae92a9820','摘茶','釋道璨','宋','宋诗','song-poetry','','[]','拈一旗兮放一鎗，多從枝葉上摶量。',32,'全唐诗/poet.song.229000.json','["拈一旗兮放一鎗，多從枝葉上摶量。", "全身入草全身出，那箇師僧無寸長。"]'),
('55a48fbb-d0ea-4bc6-aa76-1b8bb7e69dca','送仙知客總侍者','釋道璨','宋','宋诗','song-poetry','','[]','對面相看千里隔，手持史君招隠檄。',96,'全唐诗/poet.song.229000.json','["對面相看千里隔，手持史君招隠檄。", "一條拄杖兩人扶，面带東湖秋水碧。", "口裏只安三寸匙，平生懶病無藥醫。", "菜羹白飯隨處有，誰能辛苦貪住持。", "向來春風滿兩手，如今零落能多少。", "盡情包裹付二妙，散與青青湖上柳。"]'),
('ef50bb24-9f3b-417b-92bc-4283107f562e','松月軒','釋道璨','宋','宋诗','song-poetry','','[]','白雲巖上月，太平松下影。',88,'全唐诗/poet.song.229000.json','["白雲巖上月，太平松下影。", "東山大導師，指作一片境。", "若作境會孤東山，不作境會隔重關。", "蓋天蓋地這一著，分明似鏡見還難。", "認作清凉轉炎熱，掃除光影成途轍。", "廣寒宮殿等虛空，不信問取蒼髯翁。"]'),
('4f4c4923-13a9-459a-a89d-332eddb6bf5c','送奕上人','釋道璨','宋','宋诗','song-poetry','','[]','金華道人少而壯，學道苦心知趣向。',112,'全唐诗/poet.song.229000.json','["金華道人少而壯，學道苦心知趣向。", "俊如秋鷹方振揚，快似馬駒絕超放。", "無準軟頑癡絕癡，領過不消渠一狀。", "前年相別五峯巔，今年相見松江上。", "無影枝頭拾得春，要去北山呈伎倆。", "北山老人眼𦞂癡，毒手惡拳難近傍。", "跨門一機我識渠，脚跟定與三十棒。"]'),
('3e278607-8091-4496-93a4-c6311132ad1c','送覃侍者住庵','釋道璨','宋','宋诗','song-poetry','','[]','門上書心字，窗上書心字。',96,'全唐诗/poet.song.229000.json','["門上書心字，窗上書心字。", "長嘯住庵人，不知庵內事。", "除却煨芋頭，無力收寒涕。", "我觀從上來，懶瓚較些子。", "君勿輕住庵，住庵不容易。", "手中長柄鋤，上有千古意。", "前山粟自鋤，後山禾自刈。", "客來問有麽，牢把柴門閉。"]'),
('2e5d70fa-5cc8-4f60-b273-c3b47e12fe2a','送開上人','釋道璨','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','道人家住廬山寺，信脚東游二千里。',144,'全唐诗/poet.song.229000.json','["道人家住廬山寺，信脚東游二千里。", "三年飽喫浙西飯，不曾咬著浙西米。", "大川惡拳打不活，石溪淺水浸不死。", "自言辣手難近傍，祇有癡絕較些子。", "要從窗下看廬山，歸卧溪聲山色裏。", "了無玄字涴胸懷，肯將佛法掛唇齒。", "漠漠重湖五老前，衮衮九江千嶂底。", "空手携鋤種白石，赤脚提籃挈流水。", "有問參尋事若何，向道今年秋芋多。"]'),
('4b3a1fc4-5ceb-488c-8bf1-d8ad8e46c1ce','偈頌十二首  其一','釋道璨','宋','宋诗','song-poetry','','[]','隠山無量罪過，復被公安追到。',28,'全唐诗/poet.song.229000.json','["隠山無量罪過，復被公安追到。", "要得重整頹綱，不免再陞此座。"]'),
('6725b8be-e174-403f-bb8a-2eb5eb8e3155','偈頌十二首  其二','釋道璨','宋','宋诗','song-poetry','','[]','心心急要入巖隈，不合談禪信口開。',32,'全唐诗/poet.song.229000.json','["心心急要入巖隈，不合談禪信口開。", "引得王臣多愛重，遮回又被捉將來。"]'),
('1c520897-3cd8-478d-b823-ea0a7b2570ba','偈頌十二首  其三','釋道璨','宋','宋诗','song-poetry','','[]','報恩門庭，別無道理。',66,'全唐诗/poet.song.229000.json','["報恩門庭，別無道理。", "長連牀上，大衆努觜。", "本無佛法可商量，亦不坐在鬼窟裏。", "驀然洗面摸著鼻，便知得飯元是米。", "更若遲遲疑疑，白雲千里萬里。"]'),
('972dfe08-6d74-43d8-b0cc-8669bc4c44d5','偈頌十二首  其四','釋道璨','宋','宋诗','song-poetry','','[]','風和日暖，牡丹生卵。',64,'全唐诗/poet.song.229000.json','["風和日暖，牡丹生卵。", "露柱吹笙，燈籠拍版。", "城上遊人，三杯兩盞。", "報恩禪和，努觜不管。", "一念不生，前後際斷。", "踢倒鞏縣茶瓶，打破饒州瓷碗。"]'),
('8e8476be-a87f-4f8d-a656-6e75b72d6fb8','偈頌十二首  其五','釋道璨','宋','宋诗','song-poetry','','[]','隠山夜來夢喫攧，築著脚指頭出血。',110,'全唐诗/poet.song.229000.json','["隠山夜來夢喫攧，築著脚指頭出血。", "就地摸得麗水金，元來却是新羅鐵。", "翻身撞倒鳳凰峯，赤面山神驚吐舌。", "喚起前庵卧如來，休來向這裏入滅。", "一棒打殺麻姑仙，說甚長生真祕訣。", "叮嚀五通與三郎，切莫向李太白說。", "怕他俗士不甘，打你頭破腦裂。"]'),
('15012136-6c5d-46ac-a42e-6e74530fdc44','偈頌十二首  其六','釋道璨','宋','宋诗','song-poetry','','[]','奪得胡兒馬便休，何須抵死覓封侯。',32,'全唐诗/poet.song.229000.json','["奪得胡兒馬便休，何須抵死覓封侯。", "草鞋直掛龍牀角，爭似山間煨芋頭。"]'),
('aa5b1bb0-451a-4b0a-b079-e1e1e5600ff0','偈頌十二首  其七','釋道璨','宋','宋诗','song-poetry','','[]','身世悠悠不繫舟，莫將閑事掛心頭。',68,'全唐诗/poet.song.229000.json','["身世悠悠不繫舟，莫將閑事掛心頭。", "休言佛法無人會，且說晚冬又倍收。", "又倍收，蟻穴百年能幾久，龜腸一飽更何求。", "大衆拍手唱囉哩，算得生來不解愁。"]'),
('35a349fc-6fac-4a7d-afd8-f17f86dbc24c','偈頌十二首  其八','釋道璨','宋','宋诗','song-poetry','','[]','箭穿楊葉未爲親，透得金塵有幾人。',32,'全唐诗/poet.song.229000.json','["箭穿楊葉未爲親，透得金塵有幾人。", "多謝汾陽曾說破，重陽九日菊花新。"]'),
('7caa602f-d845-4595-8ed4-a41f7b91a93e','偈頌十二首  其九','釋道璨','宋','宋诗','song-poetry','','[]','天下老隠山，醜怪百千狀。',92,'全唐诗/poet.song.229000.json','["天下老隠山，醜怪百千狀。", "不依本分說禪，一向橫拈豎放。", "有時放夜市於蟭螟眼中，有時駕鐵船於須彌頂上。", "有時倒騎駿馬驟高樓，有時輕引藕絲牽大象。", "證鱉成龜，喚三作兩。", "黑豆換人眼睛，偏做遮般伎倆。"]'),
('6dd60732-1969-4386-96e6-3363b498f446','偈頌十二首  其一○','釋道璨','宋','宋诗','song-poetry','','[]','天工剪水作花飛，爲瑞爲祥也大奇。',64,'全唐诗/poet.song.229000.json','["天工剪水作花飛，爲瑞爲祥也大奇。", "管取明年禾麥熟，山河大地盡光輝。", "千樹萬樹銀花結，也是普賢呈醜拙。", "謝三郎在南臺江，手指東山笑不歇。"]'),
('772cf8d5-0ed6-40fd-8ba4-20e891624cf1','偈頌十二首  其一一','釋道璨','宋','宋诗','song-poetry','','[]','捏不成團撥不開，衲僧一見莫輕猜。',32,'全唐诗/poet.song.229000.json','["捏不成團撥不開，衲僧一見莫輕猜。", "今朝爲汝明明說，花奴花奴喫飯來。"]'),
('2fbb5f08-3597-494b-b681-0642d87f051f','偈頌十二首  其一二','釋道璨','宋','宋诗','song-poetry','','[]','釋迦彌勒是他奴，二十年來心膽粗。',32,'全唐诗/poet.song.229000.json','["釋迦彌勒是他奴，二十年來心膽粗。", "甘與魔王爲眷屬，休將惡語張荼糊。"]'),
('9c6f7bb1-987b-4e61-b723-c933f785796a','和雲壑','釋道璨','宋','宋诗','song-poetry','','[]','紛紛世事幾昏明，仙計還山又未成。',64,'全唐诗/poet.song.229000.json','["紛紛世事幾昏明，仙計還山又未成。", "欲學種松消永日，不徒煨芋博虛名。", "雲開衡嶽鵬程闊，秋入鄱陽雁影清。", "也欲摩挲病來眼，春風暖處望前旌。"]'),
('af27c144-d491-4f6d-bd64-a5a954a9eb1c','題盧可庵天邊風露樓','方逢辰','宋','宋诗','song-poetry','','[]','龍泉三尺倚天橫，濁世滔滔我獨清。',32,'全唐诗/poet.song.229000.json','["龍泉三尺倚天橫，濁世滔滔我獨清。", "一柱高臺仙掌起，願推一滴活蒼生。"]'),
('f776855d-e42a-48a4-bb7e-bd3a998ec28a','題柯峰讞掾錢君叔行敬簡軒','方逢辰','宋','宋诗','song-poetry','','[]','是非辯白只須欽，敬簡奚消讀呂刑。',32,'全唐诗/poet.song.229000.json','["是非辯白只須欽，敬簡奚消讀呂刑。", "一片公心一雙眼，心醒醒則眼醒醒。"]'),
('9c0e0bf1-2e97-4eed-abce-363416230a91','贈尹巽齋數學','方逢辰','宋','宋诗','song-poetry','','[]','陰陽晴雨可前知，此是人間第一奇。',32,'全唐诗/poet.song.229000.json','["陰陽晴雨可前知，此是人間第一奇。", "鼾睡華山何日覺，煩君更與問希夷。"]'),
('2f779cea-ebd3-4756-91f4-1ca08f3f5c30','題吳氏梅堂','方逢辰','宋','宋诗','song-poetry','','[]','聞君家在雪邊住，靠盡闌干索盡詩。',32,'全唐诗/poet.song.229000.json','["聞君家在雪邊住，靠盡闌干索盡詩。", "只怕梅花應冷笑，清香元不要人知。"]'),
('f98978ba-0eaf-4661-ad72-a11284166d3b','問天','方逢辰','宋','宋诗','song-poetry','','[]','胭脂十二萬風塵，一樣胞胎父母身。',32,'全唐诗/poet.song.229000.json','["胭脂十二萬風塵，一樣胞胎父母身。", "天欲殺之胡至此，厥初何用降生民。"]'),
('3abd3dc7-93d4-4674-8531-b64ee689f4df','天對','方逢辰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','羊祜乘危乃併孫，楊堅非解自蠶陳。',32,'全唐诗/poet.song.229000.json','["羊祜乘危乃併孫，楊堅非解自蠶陳。", "長江不是無天塹，只爲江南多婦人。"]'),
('13af0566-409f-433b-a685-cbcb4a190133','贈墨士翁彥卿','方逢辰','宋','宋诗','song-poetry','','[]','一團烟裏蓄明光，做出稜稜竹樣剛。',32,'全唐诗/poet.song.229000.json','["一團烟裏蓄明光，做出稜稜竹樣剛。", "語汝好尋臺閣主，直將勁節掃豺狼。"]'),
('d52f5d89-5330-4f7e-ad51-980a5a4e8b29','贈風鑒曹老眼','方逢辰','宋','宋诗','song-poetry','','[]','九重拊髀歎才難，幣聘皇皇難未戡。',32,'全唐诗/poet.song.229000.json','["九重拊髀歎才難，幣聘皇皇難未戡。", "老眼試尋天下看，豈無頗牧在東南。"]'),
('89a6cd79-7bf2-454c-b718-a180a43f4f0f','送胡兄遠遊','方逢辰','宋','宋诗','song-poetry','','[]','人言行路險於山，君却乘槎欲問天。',32,'全唐诗/poet.song.229000.json','["人言行路險於山，君却乘槎欲問天。", "畢竟家邦總聞達，雞鳴猛著祖生鞭。"]'),
('76f21262-57cf-4f50-a165-d6ac6843dc67','贈月心','方逢辰','宋','宋诗','song-poetry','','[]','蒼苔破屋生涯足，淡飯清湯夢寐安。',32,'全唐诗/poet.song.229000.json','["蒼苔破屋生涯足，淡飯清湯夢寐安。", "認得秀才窮快活，何須煩惱做窮官。"]'),
('d1924c07-0b70-4d2d-aa67-9478d149627b','贈大佛老子賣藥齋僧','方逢辰','宋','宋诗','song-poetry','','[]','藥中得報飯中施，始實終空不是呆。',32,'全唐诗/poet.song.229000.json','["藥中得報飯中施，始實終空不是呆。", "水復去來來復去，誰知無去亦無來。"]'),
('3aaa3f54-cebe-43f3-8f95-3ff7e600af8c','贈南山寄傲軒','方逢辰','宋','宋诗','song-poetry','','[]','著心尋處元無物，開眼見時都是天。',32,'全唐诗/poet.song.229000.json','["著心尋處元無物，開眼見時都是天。", "楚市少年霸陵尉，紛紛蠛蠓過吾前。"]'),
('f6cf87e9-d40e-46fb-8ec7-ae735f41400b','贈相者','方逢辰','宋','宋诗','song-poetry','','[]','烟霞泉石在空谷，富貴貂蟬在北方。',32,'全唐诗/poet.song.229000.json','["烟霞泉石在空谷，富貴貂蟬在北方。", "林下野人無可相，相人須去相侯王。"]'),
('a20b57f6-7dfa-4024-ba3b-bb2c190ebc42','贈梁電目','方逢辰','宋','宋诗','song-poetry','','[]','滿睫塵埃寸許深，世間豪傑尚山林。',32,'全唐诗/poet.song.229000.json','["滿睫塵埃寸許深，世間豪傑尚山林。", "冰壺指見形骸外，難照江湖一片心。"]'),
('2b378175-656f-4a5b-8948-83263db1b645','慶明堂禮成','方逢辰','宋','宋诗','song-poetry','','[]','合宮芬郁徹垓埏，治象陽明景爛然。',64,'全唐诗/poet.song.229000.json','["合宮芬郁徹垓埏，治象陽明景爛然。", "雲氣朝隮疑欲雨，帝心夕惕即旋乾。", "皇穹后土實臨汝，祖德宗功鑒在天。", "既灌更祈如未灌，緝熈此福萬斯年。"]'),
('573dfc9e-b355-45ca-8032-3fc32a057ccc','和劉府判','方逢辰','宋','宋诗','song-poetry','','[]','英雄牢落谷音空，敦薄猶存柳下風。',64,'全唐诗/poet.song.229000.json','["英雄牢落谷音空，敦薄猶存柳下風。", "善政有聲聞六邑，病軀無自謁千峰。", "乾坤許大心知少，道義相交我輩同。", "珍重瑰章何以報，烟雲留護峽山松。"]'),
('0a1dccb0-043a-450d-9a85-bfc011807f95','和張寓軒題孤山二首  其一','方逢辰','宋','宋诗','song-poetry','','[]','吝驕專恣諱言兵，禍本伊誰自種成。',64,'全唐诗/poet.song.229000.json','["吝驕專恣諱言兵，禍本伊誰自種成。", "潮汛有時聲轉怒，權奸一死罰猶輕。", "道無起滅無今古，物有消虛有長盈。", "贊化正需豪傑手，華山深處卧昇平。"]'),
('a1d0b55d-e431-4e96-a298-f63d4d09575c','和張寓軒題孤山二首  其二','方逢辰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖舊事逝如流，紅紫塵沙新綠稠。',64,'全唐诗/poet.song.229000.json','["西湖舊事逝如流，紅紫塵沙新綠稠。", "昔日賞心今日吊，前人遺迹後人遊。", "雨觀水色連山色，晴看湖頭送日頭。", "鷗鷺無情自來往，興亡不管帝王州。"]'),
('c3fc8c09-ec78-440d-9e95-586c5a11dad5','挽有宋周府君袁夫人','方逢辰','宋','宋诗','song-poetry','','[]','孩提均識愛其親，未有君家最睦姻。',64,'全唐诗/poet.song.229000.json','["孩提均識愛其親，未有君家最睦姻。", "遜畔以全諸父義，在原此豈婦人仁。", "一門鄒魯斯文地，三世羲皇太古人。", "朱紫滿門直餘事，九京可作百其身。"]'),
('1e5c5bc7-d0df-4e33-9cf2-80ae8cd63415','挽宋尚書余公二首  其一','方逢辰','宋','宋诗','song-poetry','','[]','時樣多求赫赫聲，惟公獨韞玉精神。',64,'全唐诗/poet.song.229000.json','["時樣多求赫赫聲，惟公獨韞玉精神。", "傳無房杜可書事，心即羲皇太古人。", "日月升時先奮翼，風雲濃處忽抽身。", "蒼蒼忍奪客星去，却使凌烟憶老臣。"]'),
('2948107f-0a6d-4c7e-9447-7cce56b499e2','挽宋尚書余公二首  其二','方逢辰','宋','宋诗','song-poetry','','[]','扁舟一葉掠垂虹，因泛江蓮得識公。',64,'全唐诗/poet.song.229000.json','["扁舟一葉掠垂虹，因泛江蓮得識公。", "千里軍民安席上，一年賓主坐春中。", "斑催紫橐朝天近，夢到黄粱霍地空。", "契闊真情言不盡，只將楚些寄東風。"]'),
('77a7b935-ea9b-44f3-b360-bdb4b95bb0fd','挽宋吏部趙公','方逢辰','宋','宋诗','song-poetry','','[]','翱翔碧水又蓬山，再入郎闈即丐閒。',64,'全唐诗/poet.song.229000.json','["翱翔碧水又蓬山，再入郎闈即丐閒。", "屢疏朝端詞梗梗，一麾道院政斑斑。", "閣因書創家鄒魯，堂以親名行冉顔。", "所恨與公非識面，一詩寄雁寫潸潸。"]'),
('7c5357de-1f58-4f1e-a58a-d5100a99e351','被召不赴','方逢辰','宋','宋诗','song-poetry','','[]','萬里皇華遣使輈，姓名曾覆御前甌。',64,'全唐诗/poet.song.229000.json','["萬里皇華遣使輈，姓名曾覆御前甌。", "燕臺禮重金爲屋，嚴瀨風高玉作鈎。", "丹鳳喜從天上落，白駒須向谷中求。", "敲門不醒希夷睡，休怪山雲著意留。"]'),
('cd18c5ab-6061-4506-b2c7-8ce98e161332','贈樵隠','方逢辰','宋','宋诗','song-poetry','','[]','樵仙深入琴棋境，一笑出門天地寬。',64,'全唐诗/poet.song.229000.json','["樵仙深入琴棋境，一笑出門天地寬。", "人世已非存朽斧，土音不改只南冠。", "琴中自有鐵心在，局外何妨道眼觀。", "霽月光風元屬我，飯牛何謂夜漫漫。"]'),
('cb25a27c-7554-4a37-bca1-347cf1c823c5','題何潜齋安樂窩','方逢辰','宋','宋诗','song-poetry','','[]','閒中歷覽古和今，夫豈全無所用心。',64,'全唐诗/poet.song.229000.json','["閒中歷覽古和今，夫豈全無所用心。", "書爲重看因熟讀，詩添新作費沉吟。", "消磨暇日尊前酒，賡和薰風膝上琴。", "過去未來都不管，却看明月是知音。"]'),
('fd8c1646-b49f-47d7-8d0c-79b3ee5c2549','頌徐大可爲六縣減免稅糧得請','方逢辰','宋','宋诗','song-poetry','','[]','六縣驩娛己獨勞，肯心行善是人豪。',64,'全唐诗/poet.song.229000.json','["六縣驩娛己獨勞，肯心行善是人豪。", "乞憐請命繭絲價，起死回生鼎釜熬。", "誰謂他人無力氣，不於好事拔毫毛。", "老夫贊詠非誇詡，此在春秋亦合褒。"]'),
('322bb8c6-0b3e-4290-9821-ab4fc8ccfab0','石峽山茶盛開  其一','方逢辰','宋','宋诗','song-poetry','','[]','冰崖赤骨物俱老，火樹生陽我不孤。',64,'全唐诗/poet.song.229000.json','["冰崖赤骨物俱老，火樹生陽我不孤。", "鐵葉幾經寒暑戰，丹心不爲雪霜枯。", "托根峽裏老居士，加號花中烈丈夫。", "顔色不淫枝幹古，洛陽牡藥只爲奴。"]'),
('8dd6d544-c4a9-4920-aa72-c2632e7b7884','石峽山茶盛開  其二','方逢辰','宋','宋诗','song-poetry','','[]','凡卉春妍誇國色，此花陰極抱陽明。',64,'全唐诗/poet.song.229000.json','["凡卉春妍誇國色，此花陰極抱陽明。", "人疑芝草非時出，我謂丹砂托樹生。", "可惜洛中忻富貴，不知霜裏蓄精英。", "老夫詩若宋初出，牡藥如何得盛行。"]'),
('f6943d88-f0ba-49e3-a537-66670e332808','餞修史宮講吏部陳大著赴鎮贛州','方逢辰','宋','宋诗','song-poetry','','[]','蠡湖擘破亨衢開，山川鍾作魁奇材。',192,'全唐诗/poet.song.229000.json','["蠡湖擘破亨衢開，山川鍾作魁奇材。", "九關叫後入雲岫，六陰卷出登蓬萊。", "著庭萬卷了汗竹，粉闈胡事被先幞。", "非徒五馬人生榮，正要急流剛扷足。", "章貢二水分西東，江右九郡斯爲雄。", "亭橫塵外眇四海，臺插天表森孤峯。", "三百里水見沙磧，一十八灘如劍脊。", "醉讀題詠呼坡翁，此是太守風月窟。", "又聞獷俗多驚湍，况有蠆尾鄰諸蠻。", "付之重寄憂亦大，此是太守思慮關。", "代木詩廢友道缺，道山幸有詩送別。", "一言愛助當何如，思慮先之後風月。"]'),
('443ca9e4-0321-4713-bb0a-f02444b10c72','錢判府國史直講秘書赴鎮南劍','方逢辰','宋','宋诗','song-poetry','','[]','番江之峰高插天，番湖之水淵其淵。',224,'全唐诗/poet.song.229000.json','["番江之峰高插天，番湖之水淵其淵。", "山川鍾作一書簏，胸次洶湧萬斛泉。", "呼來天上佐良史，喚起英雄斧奸魅。", "玉堂萬字雲錦章，赤墀一對國士器。", "天爲資善擇畏師，汝作羽翼從吾兒。", "光芒忽報動雙劍，翱翔直去分一麾。", "我聞了翁鐵梁脊，生晚不得拜履舄。", "又聞龜山與延平，首爲東南揭標的。", "今君剖符守其鄉，視三先生爲有光。", "開明義理當日用，扶植氣節爭秋霜。", "知君報政只數月，袴襦萬口九天徹。", "去時好趁蘆花天，歸時又見橙橘節。", "道山繾綣持一觥，臨別惟有詩送行。", "執手不敢贊諛語，版樣惟視三先生。"]'),
('e5d973f7-aba8-408d-b513-3c2273d42590','和僉事夾谷之寄韻','方逢辰','宋','宋诗','song-poetry','','[]','夫子說周易，肇開太極分。',288,'全唐诗/poet.song.229000.json','["夫子說周易，肇開太極分。", "及乎作春秋，下逮西狩麟。", "混闢至决裂，堅冰致習馴。", "三皇何皞皞，五帝何紛紛。", "卓哉洙泗翁，道大孤無鄰。", "於是作六經，以救萬世人。", "孟氏辨義利，戰國駭所聞。", "不肯爲老聃，和光同其塵。", "人不識四端，豈知有君親。", "孔孟作日月，然後夜向晨。", "天高與地下，中立師與君。", "師以扶綱常，君以治廣輪。", "廉恥甚鈇鉞，禮教威斧斤。", "自古立宇宙，以道爲精神。", "清溪斗大邑，土瘠民甚貧。", "虎豺方恣睢，駰騏忽諏詢。", "痛民若赤子，禮士如上賓。", "簞瓢在陋巷，窮則獨善身。", "家有讀書屋，乃爲劫火焚。", "仁人忽行惻，仲氏敢具陳。", "公肯挈墜道，天未亡斯文。", "移檄作主宰，歌詩示恩勤。", "絃歌已久廢，簡陋尚可因。", "祠堂儼遺像，生徒招驚麕。"]'),
('c885f844-4f1a-4dd6-9e41-a76f1138765d','送潘翠谷','方逢辰','宋','宋诗','song-poetry','','[]','無屋住僧廬，無菜挑野草。',132,'全唐诗/poet.song.229000.json','["無屋住僧廬，無菜挑野草。", "野草風味長，僧廬人跡少。", "剝剝誰扣扃，訪予事幽討。", "錢唐有騷翁，自號翠谷老。", "疋馬遊南牆，要伴松竹好。", "遐思到山人，迂尋出詩稿。", "詩無怨苦吟，掃退郊與島。", "胸次鮑明遠，筆下王逸少。", "我觀陰與陽，禪代何時了。", "不能爲魯連，尚可作商皓。", "長歌黍離篇，酹酒問旻昊。"]'),
('9b17eb01-27ef-4eb2-8d0d-8be03e0d9fc7','贈術士劉衡鑑','方逢辰','宋','宋诗','song-poetry','','[]','高目下耳赫如鑑，福善禍淫平如衡。',144,'全唐诗/poet.song.229000.json','["高目下耳赫如鑑，福善禍淫平如衡。", "顔癯胡夭跖胡壽，季氏乃富憲乃貧。", "伯道無兒湯有後，造物豈是鑑不明。", "孔明遺恨懿血食，造物豈是衡不平。", "當知稟氣有清濁，所以人品有善惡。", "至若夭壽與賤貴，又是稟氣有厚薄。", "清濁厚薄物自聖，洪纖高下天何言。", "君子惟以理自充，英雄難與造物爭。", "前人論理不論氣，不信試問劉鑑衡。"]'),
('ae4f3bec-f377-47bd-83e5-57c96c4fa398','贈星命舒雲峰','方逢辰','宋','宋诗','song-poetry','','[]','五星聚東井，天下王業開。',100,'全唐诗/poet.song.229000.json','["五星聚東井，天下王業開。", "五星聚奎宿，天下多賢才。", "蚩尤掃彯□，攙槍卷飛埃。", "日月黄道見火羅，計孛烏能爲之災。", "雲峯挾術善說命，窮通貴賤非所問。", "敢問何時聚五星，今年五星聚何分。", "聖人在上天下平，疏食飲水甘曲肱。"]'),
('aa541a6e-bd6b-4043-8f44-04f60612873a','題盧文峰十二知丞文集','方逢辰','宋','宋诗','song-poetry','','[]','驪珠一顆千仞淵，漁翁探得遭驪眠。',164,'全唐诗/poet.song.229000.json','["驪珠一顆千仞淵，漁翁探得遭驪眠。", "一朝吹墮千萬顆，恐是蛟驪卧半天。", "駢花儷葉妙天下，文賦直追古班馬。", "手抉河漢裂錦章，寫在詩歌軋騷雅。", "大篇赤手捕長蛇，不須控勒騎生騧。", "短篇任意起忽伏，蒼江浩浩濤中槎。", "文章妙手壓場屋，到底亡羊還得鹿。", "廬陵方買載月舟，清淡又展朝天軸。", "軍將打門書一封，呼起醉夢爲醒鬆。", "只怕至寶不肯留山中，雷霆風雨取去還蛟龍。"]'),
('9026e30d-c0cc-4c4d-8e89-95edcecb89d7','挽鄭直齋居士','方逢辰','宋','宋诗','song-poetry','','[]','有姪宰相才，昔惟呂文穆。',96,'全唐诗/poet.song.229000.json','["有姪宰相才，昔惟呂文穆。", "有婿國士器，昔惟晏同叔。", "公乃兼其榮，秀氣塞一門。", "爲國作瑞璉，頼公培福根。", "世態方惡直，公乃自立的。", "掉頭蠻觸爭，冷坐雪月窟。", "今世能幾人，如公心迹清。", "馨豔有如此，公死猶如生。"]'),
('6d80a02c-7120-4009-a60b-baf71246c564','贈楊內舍景堯刲股','方逢辰','宋','宋诗','song-poetry','','[]','子肉可療親，或曰不敢毀。',72,'全唐诗/poet.song.229000.json','["子肉可療親，或曰不敢毀。", "不見母生兒，生死一間耳。", "此身母之身，非可認爲己。", "殺身可救母，當還愛一死。", "天理通神明，寸膚直糠粃。", "苟能充此心，是即學曾子。"]'),
('8dfb31b0-5e95-4b9c-b9fd-3d247c33ef6b','贈五星陳東野','方逢辰','宋','宋诗','song-poetry','','[]','粵從動靜極互根，裂爲二氣分五行。',192,'全唐诗/poet.song.229000.json','["粵從動靜極互根，裂爲二氣分五行。", "未有二氣先有理，理與氣合人物生。", "人惟稟得天地氣，故爲耳目形口鼻。", "人惟稟得氣之理，故爲仁義爲禮智。", "氣爲人形理爲心，同是水木火土金。", "今人問氣不問理，茫茫只向天外尋。", "人而不仁木已死，不須更論敗在子。", "人而薄義金已傷，如何却說生在巳。", "無禮無智水火滅，不忠不信土氣絕。", "人於心上斬了根，是氣安從有萌蘗。", "出門一笑逢星翁，談天議論迥不同。", "若能論氣又論理，太極只在挑包中。"]'),
('b26a7990-48e1-48ff-8a18-1d7c4bfe46ce','田父吟','方逢辰','宋','宋诗','song-poetry','','[]','清溪眇如斗大邑，萬山壁立土磽瘠。',384,'全唐诗/poet.song.229000.json','["清溪眇如斗大邑，萬山壁立土磽瘠。", "百分地無一分田，九十九分如劍脊。", "一畝之地高復低，節節級級如橫梯。", "畈心一畦可一畝，邊旁一畝分數畦。", "大家有田僅百畝，三二十畝十八九。", "父母夫妻子婦孫，一奴一婢成九口。", "一口日噉米二升，茗鹺醯醤菜與薪。", "共來日費二三斗，尚有輸官七八分。", "小民有田不滿十，鐮方放兮有菜色。", "曹胥鄉首冬夏臨，催科差役星火急。", "年年上熟猶皺眉，一年不熟家家饑。", "山中風土多食糜，兩兒止肯育一兒。", "只緣人窮怕餓死，可悲可吊又如此。", "有司猶曰汝富民，手執鞭敲目怒視。", "今年淫雨天作難，洶湧澎湃四五番。", "浮尸弊屋環江下，迸山裂地如鯨奔。", "半山都成水澤國，平地皆作龍蛇窟。", "水頭晚退早復來，屋角朝出夕又沒。", "巋然令丞簿尉衙，下視四境無人家。", "水平歸家無屋住，有屋住者無生涯。", "農民拋家認畝隴，擔砂翻石肩皆腫。", "百千一畝判晚秧，一坵分作兩坵種。", "都來一畝無百千，買秧已費半百錢。", "眼前插種已剜肉，頭後豐歉猶在天。"]'),
('064c8c87-7ce4-4005-84e3-64b78f630b54','猩猩歌','方逢辰','宋','宋诗','song-poetry','','[]','獵者圍猩猩，疑其以衆抗。',180,'全唐诗/poet.song.229000.json','["獵者圍猩猩，疑其以衆抗。", "諉曰不取小，惟取大與壯。", "衆猩自相仇，推擠送其長。", "以次索二三，不復推已往。", "四五至于十，無一得釋放。", "衆猩怒相目，各悔受人誑。", "及早同一心，未必軀盡喪。", "吁嗟獸不靈，相仇無足嗔。", "胡爲豪傑群，不能自相親。", "秦人吞六國，諸侯各附秦。", "併力取其一，冀不及他人。", "智者欲合從，徒自腐舌唇。", "安得先震鄰，然後于其身。", "彼先噬其一，其次禍亦均。", "早知秦用術，六國同一心。"]'),
('034e2b32-05f9-4a46-9f92-1af83d984532','鷄雛吟','方逢辰','宋','宋诗','song-poetry','','[]','我聞先儒云，雞雛可觀仁。',180,'全唐诗/poet.song.229000.json','["我聞先儒云，雞雛可觀仁。", "須臾不舍母，是即孝弟根。", "不待教而知，不待習而成。", "於斯爲良知，於斯爲良能。", "人從此充拓，四海皆閔曾。", "異哉鷄伏鶩，出殻忘其恩。", "子向水中去，母從岸呼鳴。", "子往母亦往，子疏母愈親。", "鷹隼飛在天，母亦與子驚。", "或遇狸與狌，愛雛忘其身。", "不顧力小大，直與爭死生。", "天於微物上，感人惻隠真。", "人觀鷄護雛，鐵石爲動情。", "子呱方卧冰，安得卵覆人。", "勿看雞伏鶩，吾則行吾仁。"]'),
('cb9dd202-c296-41c2-8bcf-5995b1aa3a81','南康遇雪','方逢辰','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夜來怪甚風太顛，掀簸震撼不可眠。',160,'全唐诗/poet.song.229000.json','["夜來怪甚風太顛，掀簸震撼不可眠。", "門前鐵騎怒拔屋，枕上猛虎飛吼天。", "却是廬山夕作雪，楊花未春先擘綿。", "左蠡門前玉兩柱，江心落石鷺一拳。", "五峰千仞削銀壁，重湖萬頃開璚田。", "若使璚田可以種，雖遭赤地民不癲。", "若使銀壁可以鑄，當造白幣權飛錢。", "要知冬燠生意洩，明年造化工斯全。", "帝呼玄冥急收歛，閉塞陽氣胚豐年。", "雖云不可耕與種，桑麻穀粟茲開先。"]'),
('1409612a-18f5-4e56-aa4b-69370d0db8b2','雨微山','翁仲德','宋','宋诗','song-poetry','','[]','大川東逝近叢林，石壁潮音雜梵音。',32,'全唐诗/poet.song.229000.json','["大川東逝近叢林，石壁潮音雜梵音。", "旱望湫龍噓澗氣，沛然甘雨慰農心。"]'),
('3db2200b-818f-4118-9859-d3a8a998bd73','夜飛山','翁仲德','宋','宋诗','song-poetry','','[]','江南雨霽彩雲開，眼界空寬翠色排。',32,'全唐诗/poet.song.229000.json','["江南雨霽彩雲開，眼界空寬翠色排。", "蜀客躊躇還識認，子規啼月夜歸來。"]'),
('0257e208-919a-4624-8a66-e017fa524d24','鳴鶴山','翁仲德','宋','宋诗','song-poetry','','[]','滄海東頭鶴阜高，仙人騎鶴下林坳。',32,'全唐诗/poet.song.229000.json','["滄海東頭鶴阜高，仙人騎鶴下林坳。", "一聲唳起揚州去，華表空餘月下巢。"]'),
('0597828d-94de-4878-be00-0f87d0b938c3','劍池橋梁久就傾圮方丈霑公刊石伐木以遞汲且併陳樓悉改舊觀','龔潗','宋','宋诗','song-poetry','','[]','涓涓劍池泉，削崖出石乳。',120,'全唐诗/poet.song.229000.json','["涓涓劍池泉，削崖出石乳。", "流傳歲千百，評列品三五。", "輿梁見何時，樓與姓俱古。", "坐令丘壑觀，凜作巖牆懼。", "霑公大勇猛，咄嗟見未覩。", "欹傾變略彴，岞崿移朽腐。", "連筒稱深汲，惠澤徧下土。", "幽尋穩登眺，清意逼肺腑。", "何須鐵作限，只爾天可補。", "傳聞橋下雲，已作前山雨。"]'),
('29966863-70e4-466c-80c4-69517352bdd8','東巖','吳衍','宋','宋诗','song-poetry','','[]','滿壁雲濤倚太空，雙崖一線路微通。',32,'全唐诗/poet.song.229000.json','["滿壁雲濤倚太空，雙崖一線路微通。", "幾年勝概埋荆棘，好事山翁始發蒙。"]'),
('b701fcdc-c9b5-4732-a44f-f68fa6b74b31','翠蛟亭','吳衍','宋','宋诗','song-poetry','','[]','一峰擎天維，下有萬斛水。',204,'全唐诗/poet.song.229000.json','["一峰擎天維，下有萬斛水。", "委蛇到澗壑，遇坎亦不止。", "鳴鼉忽動地，濤怒生足底。", "得非坤軸裂，驚視坐爲起。", "盆傾濺珠胎，鼎沸翻玉髓。", "長蛟躩連卷，救首復救尾。", "吾廬枕清淺，徙倚每自侈。", "及茲睹奇觀，目眩顙有泚。", "便欲逃世紛，置身巖穴裏。", "蓬瀛渺溟渤，對面不遺咫。", "嗟余聞道晚，今始忘仕已。", "重來三十年，恍若游故里。", "壯顔日凋瘁，浩志亦頹靡。", "載歌蜀仙詩，此老元不死。", "至今斯亭上，清風盈棐几。", "觀水必觀瀾，是中存妙理。", "源泉何混混，有本故如此。"]'),
('08312004-3a3b-41fd-b5c3-6da182c51cd3','君子泉','李申子','宋','宋诗','song-poetry','','[]','□巖峭□色斕斑，雲葉煙蘿□□鬟。',32,'全唐诗/poet.song.229000.json','["□巖峭□色斕斑，雲葉煙蘿□□鬟。", "疑有仙琚時會集，唾珠霏屑落人間。"]'),
('65cbd9f6-aaa6-417b-8b98-c62710018853','句','李申子','宋','宋诗','song-poetry','','[]','深城市紅塵怎得侵骨雲巖檜老險驚興廢一掬清泉酌古沈寂徘徊覓句聽。',31,'全唐诗/poet.song.229000.json','["深城市紅塵怎得侵骨雲巖檜老險驚興廢一掬清泉酌古沈寂徘徊覓句聽。"]'),
('2c1ad42b-5f62-44a1-9b83-4d1dcdf7b5f5','絕句','杭學士人','宋','宋诗','song-poetry','','[]','塞翁何必恨失馬，城火可憐殃及魚。',32,'全唐诗/poet.song.229000.json','["塞翁何必恨失馬，城火可憐殃及魚。", "一笑出門天萬里，擔頭猶有斥姦書。"]'),
('8b906592-60e9-4220-b327-c49a7d1dcc89','五言','杭學士人','宋','宋诗','song-poetry','','[]','鄭五不去國，金陵深懼君。',48,'全唐诗/poet.song.229000.json','["鄭五不去國，金陵深懼君。", "校存知必毀，書在已如焚。", "自是清流禍，非干比黨分。", "歸歟雖幸矣，恨未效朱雲。"]'),
('9adaefd3-57e6-4f7d-a410-e35501b2d3a7','古詩','杭學士人','宋','宋诗','song-poetry','','[]','上書如啜盧仝茶，直論國體寧無譁。',136,'全唐诗/poet.song.229000.json','["上書如啜盧仝茶，直論國體寧無譁。", "依然茅葦縱橫斜，鍾山老柏休槎牙。", "嗚呼時事如絲麻，食肉者口徒咿哇。", "鬼蜮空含射影沙，逐客令下堪吁嗟。", "識者將謂秦得邪，淳祐寖不如端嘉。", "邪人剛指正人邪，時有引喙鳴靈鴉。", "失脚奇禍曹羅罝，尼山草木枯無華，奄奄山鬼相揄揶。", "我今束書歸天涯，不惜一去惜國家。"]'),
('39173eb0-c129-43a7-a0c1-19a5a70441e9','澹山巖','張遠猷','宋','宋诗','song-poetry','','[]','巖竇天下奇，黄詩天下稀。',48,'全唐诗/poet.song.229000.json','["巖竇天下奇，黄詩天下稀。", "洞明無所隠，石勢爭欲飛。", "雷鼓今猶在，澹仙何未歸。", "磨崖文斷滅，苔蘚却成衣。"]'),
('85a3e190-cd73-4a29-a13b-209b07739786','見梅雜興','陸夢發','宋','宋诗','song-poetry','','[]','人間誰是識梅真，棄實求花後世心。',64,'全唐诗/poet.song.229000.json','["人間誰是識梅真，棄實求花後世心。", "何似只如三代日，分甘投老萬山深。", "寄來陸凱渾多事，說到林逋亦費吟。", "耿耿知音唯月在，無言相看古猶今。"]'),
('3d9366d2-3938-4c28-8fd4-f6e4db29db51','梅花','陸夢發','宋','宋诗','song-poetry','','[]','城中忙失探梅期，初見僧窗一兩枝。',64,'全唐诗/poet.song.229000.json','["城中忙失探梅期，初見僧窗一兩枝。", "猶喜相逢那恨晚，故應更好半開時。", "今冬不雪何關事，值伴孤芳却欠伊。", "月落山空正幽獨，慰存無酒且新詩。"]'),
('807a8a03-14df-401e-ae2d-f3623682b4cc','鐵券山','吳之選','宋','宋诗','song-poetry','','[]','宗派天潢衍，文章吏部遺。',48,'全唐诗/poet.song.229000.json','["宗派天潢衍，文章吏部遺。", "前朝尺土盡，軼事幾人知。", "歲月松杉古，塵沙日夜吹。", "數家芳草外，憑弔總淒其。"]'),
('839d8db5-b091-4d32-be29-2fac36da8f4a','次韻方萬里雨夜雪意','趙與東','宋','宋诗','song-poetry','','[]','芋火房陰處，翛然類嬾殘。',48,'全唐诗/poet.song.229000.json','["芋火房陰處，翛然類嬾殘。", "雨欺梅影瘦，風助竹聲寒。", "擁袂衣全薄，哦詩字欲安。", "兒童疑有雪，頻起穴窗看。"]'),
('74c06938-cc80-4513-9d5f-56fcad258838','次韻方萬里寒甚送酒','趙與東','宋','宋诗','song-poetry','','[]','連日寒殊甚，衰年無一能。',48,'全唐诗/poet.song.229000.json','["連日寒殊甚，衰年無一能。", "硯呵磨墨凍，瓶曬插花冰。", "浮世無根絮，餘生有髮僧。", "蘇門如可即，端合事孫登。"]'),
('e6ed0810-7de5-465a-b5d1-f74138d5ae8a','郊遊遇黄府女孫','潘用中','宋','宋诗','song-poetry','','[]','誰教窄路恰相逢，脈脈靈犀一點通。',32,'全唐诗/poet.song.229000.json','["誰教窄路恰相逢，脈脈靈犀一點通。", "最恨無情芳草路，匿蘭含蕙各西東。"]'),
('7f8ea442-962f-4be7-a2b8-95b77e72fecb','答黄府女孫','潘用中','宋','宋诗','song-poetry','','[]','一曲臨風值萬金，如何難買玉人心。',32,'全唐诗/poet.song.229000.json','["一曲臨風值萬金，如何難買玉人心。", "君如解得相如意，比似金徽恨更深。"]'),
('92303550-d3c9-4191-b601-cd28c6c6adff','贈潘用中','黄氏女','宋','宋诗','song-poetry','','[]','欄桿閒倚日偏長，短笛無情苦斷腸。',32,'全唐诗/poet.song.229000.json','["欄桿閒倚日偏長，短笛無情苦斷腸。", "安得身輕如燕子，隨風容易到君傍。"]'),
('b1cda545-cac4-4b2d-81ee-881320809111','又贈','黄氏女','宋','宋诗','song-poetry','','[]','自從聞笛苦匆匆，魄散魂飛似夢中。',32,'全唐诗/poet.song.229000.json','["自從聞笛苦匆匆，魄散魂飛似夢中。", "最恨粉牆高幾許，蓬萊弱水隔千重。"]'),
('81c34dfb-98d2-4102-bbf7-09e9c43cbbfd','十月梅花','趙必成','宋','宋诗','song-poetry','','[]','初冬未見一片雪，先見梅開傍花庵。',32,'全唐诗/poet.song.229000.json','["初冬未見一片雪，先見梅開傍花庵。", "可是東君留厚意，早傳消息到江南。"]'),
('75ef7801-7ecd-44e0-8569-9e151a159d82','題陳生鯉魚圖','趙必成','宋','宋诗','song-poetry','','[]','神龍原自異凡魚，潴澤還知不久居。',64,'全唐诗/poet.song.229000.json','["神龍原自異凡魚，潴澤還知不久居。", "平地雷轟頭角露，滔天浪浴甲鱗舒。", "應誇鼇海都量遍，漫道龍門不可踰。", "試問錦標剛一躍，陡成霖雨足沾濡。"]'),
('046bc854-bc98-4664-8f15-ac036662c5f2','憩宮偶成','常楙','宋','宋诗','song-poetry','','[]','松風朝來入夢頻，公餘乘興去尋真。',64,'全唐诗/poet.song.229000.json','["松風朝來入夢頻，公餘乘興去尋真。", "紅塵物外長清境，白日壺中不老春。", "柏子灰寒烟寂寂，桃花風暖水粼粼。", "逍遥羽士閑如許，媿我浮名役此身。"]'),
('6ef946fc-e656-4d0a-bea8-3872674fa0c8','詠梅','程瑞','宋','宋诗','song-poetry','','[]','清淺溪橋水，高低籬外枝。',24,'全唐诗/poet.song.229000.json','["清淺溪橋水，高低籬外枝。", "這些風骨異，瘦盡古今詩。"]'),
('3b7fde84-ae12-4456-b4ac-d20474072505','咏古','程瑞','宋','宋诗','song-poetry','','[]','博浪沙中力士，望仙橋下軍人。',28,'全唐诗/poet.song.229000.json','["博浪沙中力士，望仙橋下軍人。", "古來忠膽一概，至今裂視二秦。"]'),
('ed0c33a2-dcc8-480c-8f0a-82ecbaa4f14b','北湖水月','王橚','宋','宋诗','song-poetry','','[]','奩鏡平開碧四圍，百重山裏亦希奇。',32,'全唐诗/poet.song.229000.json','["奩鏡平開碧四圍，百重山裏亦希奇。", "寫成萬古空明趣，只爲中秋一首詩。"]'),
('a459506d-2a94-41d8-bcaf-f804fabc96e1','幸侍軺車敬贅嚴韻  其一','趙與㒇','宋','宋诗','song-poetry','','[]','男兒有志事竟成，好把功名竹帛垂。',32,'全唐诗/poet.song.229000.json','["男兒有志事竟成，好把功名竹帛垂。", "今日輿圖當混一，誰能重拭□□碑。"]'),
('4b0d250b-4601-41c9-8c8b-78340b0be148','幸侍軺車敬贅嚴韻  其二','趙與㒇','宋','宋诗','song-poetry','','[]','細把中興唐頌看，玉環遺恨記當年。',32,'全唐诗/poet.song.229000.json','["細把中興唐頌看，玉環遺恨記當年。", "自從擁馬回靈武，整頓乾坤豈偶然。"]'),
