('7366e3bc-9780-42a0-8001-d845fa93b58b','頌古四十五首  其二六','釋如珙','宋','宋诗','song-poetry','','[]','托鉢回身去，鐘鼓未鳴時。',24,'全唐诗/poet.song.229000.json','["托鉢回身去，鐘鼓未鳴時。", "不會末後句，只有奯心知。"]'),
('e62cffaa-5954-4b67-be0d-9a5bfe3f8d3e','頌古四十五首  其二七','釋如珙','宋','宋诗','song-poetry','','[]','密啟深深意，禪和不用疑。',24,'全唐诗/poet.song.229000.json','["密啟深深意，禪和不用疑。", "恰得三年活，言中果有期。"]'),
('bee8f9a7-41ee-4961-9884-79cc2e6e9c2d','頌古四十五首  其二八','釋如珙','宋','宋诗','song-poetry','','[]','秘魔提杈起，驗你本來人。',24,'全唐诗/poet.song.229000.json','["秘魔提杈起，驗你本來人。", "得在杈下死，不負此生身。"]'),
('142fa132-702b-4bda-8632-8a5bdb00660f','頌古四十五首  其二九','釋如珙','宋','宋诗','song-poetry','','[]','螻蟻皆有佛性，爲甚狗子却無。',28,'全唐诗/poet.song.229000.json','["螻蟻皆有佛性，爲甚狗子却無。", "趙州觀音院裡，壁上掛箇胡蘆。"]'),
('0ee762ef-f3db-4b22-a698-aaa3a4debca1','頌古四十五首  其三○','釋如珙','宋','宋诗','song-poetry','','[]','大地一隻眼，誰敢屙其中。',24,'全唐诗/poet.song.229000.json','["大地一隻眼，誰敢屙其中。", "鍬子寄將去，那知到雪峰。"]'),
('9c41335d-4af9-4dcc-b75b-5f6bf3c51115','頌古四十五首  其三一','釋如珙','宋','宋诗','song-poetry','','[]','不曾出門去，莊上喫油糍。',24,'全唐诗/poet.song.229000.json','["不曾出門去，莊上喫油糍。", "莊主歸相謝，侍者不得知。"]'),
('28e38906-8418-4352-a5de-50d24dc0955b','頌古四十五首  其三二','釋如珙','宋','宋诗','song-poetry','','[]','塵中辨主問巖頭，心識如何曾得休。',32,'全唐诗/poet.song.229000.json','["塵中辨主問巖頭，心識如何曾得休。", "鼻孔眼睛都要見，銅砂鑼裏滿盛油。"]'),
('fd503b83-2283-46b6-9622-2bc137840496','頌古四十五首  其三三','釋如珙','宋','宋诗','song-poetry','','[]','擔一片板在肩頭，如何得到空王地。',32,'全唐诗/poet.song.229000.json','["擔一片板在肩頭，如何得到空王地。", "睦州古佛多垂慈，要你自家放捨去。"]'),
('1201e6c7-b16f-41ed-a2a5-9b03e40e41fe','頌古四十五首  其三四','釋如珙','宋','宋诗','song-poetry','','[]','你若學他看，牛皮真箇穿。',24,'全唐诗/poet.song.229000.json','["你若學他看，牛皮真箇穿。", "長年橫案上，字義自然圓。"]'),
('5fd99a77-a730-4a52-8cc0-64fbbd4b4a79','頌古四十五首  其三五','釋如珙','宋','宋诗','song-poetry','','[]','坐禪成佛生妄見，磨磚作鏡妄尤多。',32,'全唐诗/poet.song.229000.json','["坐禪成佛生妄見，磨磚作鏡妄尤多。", "打車打牛俱是妄，攪得心腸沒奈何。"]'),
('bc66427d-1ff8-4f52-af58-a894c19e8cf1','頌古四十五首  其三六','釋如珙','宋','宋诗','song-poetry','','[]','豈要共出一隻手，只教喚著沙彌來。',32,'全唐诗/poet.song.229000.json','["豈要共出一隻手，只教喚著沙彌來。", "鐵鐺無脚又無耳，牆下春深薺葉開。"]'),
('d0be3e12-febd-4075-b553-ba57c3c534d7','頌古四十五首  其三七','釋如珙','宋','宋诗','song-poetry','','[]','圓相中間坐底誰，便施女拜各呈機。',32,'全唐诗/poet.song.229000.json','["圓相中間坐底誰，便施女拜各呈機。", "國師道大徧天下，未許尋常人得知。"]'),
('5ef3dda1-b230-4803-ad01-95a9896f5cfe','頌古四十五首  其三八','釋如珙','宋','宋诗','song-poetry','','[]','千里同風見不差，僧持此語報玄沙。',32,'全唐诗/poet.song.229000.json','["千里同風見不差，僧持此語報玄沙。", "不知蹉過如何也，莫是玄沙蹉過他。"]'),
('7a8ad6a5-d183-4bc3-92cd-787cd8acfcb8','頌古四十五首  其三九','釋如珙','宋','宋诗','song-poetry','','[]','尊者策眉王不會，十方剎土古風清。',32,'全唐诗/poet.song.229000.json','["尊者策眉王不會，十方剎土古風清。", "佛齋勝會親曾預，不是尋堂粥飯僧。"]'),
('3e2300ee-b477-45b6-be19-a0e7f7e33b67','頌古四十五首  其四○','釋如珙','宋','宋诗','song-poetry','','[]','二十年來不具眼，茅菴燒却是徒爲。',32,'全唐诗/poet.song.229000.json','["二十年來不具眼，茅菴燒却是徒爲。", "三春暖氣無多子，真實之言亦可師。"]'),
('083f3df5-e53e-4f02-8ac0-b0a72edee4f1','頌古四十五首  其四一','釋如珙','宋','宋诗','song-poetry','','[]','只一箇休去，伎倆自然消。',24,'全唐诗/poet.song.229000.json','["只一箇休去，伎倆自然消。", "諸聖在甚處，脚下路條條。"]'),
('214ac050-375b-446d-ade4-1f40f97a22d9','頌古四十五首  其四二','釋如珙','宋','宋诗','song-poetry','','[]','斬蛇却非小小事，直是教他脫苦輪。',32,'全唐诗/poet.song.229000.json','["斬蛇却非小小事，直是教他脫苦輪。", "座主高茅心未泯，如何胡亂妄通言。"]'),
('cfd50957-6edb-48c4-b6e4-9fded742d209','頌古四十五首  其四三','釋如珙','宋','宋诗','song-poetry','','[]','北斗裏藏身，虛空中出沒。',24,'全唐诗/poet.song.229000.json','["北斗裏藏身，虛空中出沒。", "道得一句來，日頭東畔出。"]'),
('741bfec5-523f-41b7-a6c2-67ca32917d4f','頌古四十五首  其四四','釋如珙','宋','宋诗','song-poetry','','[]','設粥殷勤請念誦，白槌各爲念摩訶。',32,'全唐诗/poet.song.229000.json','["設粥殷勤請念誦，白槌各爲念摩訶。", "上來功德要圓滿，復去厨頭打破鍋。"]'),
('ac4c177b-a481-49a9-9f02-1e2fe6778b72','頌古四十五首  其四五','釋如珙','宋','宋诗','song-poetry','','[]','藥山手中書佛字，問他端爾要心開。',32,'全唐诗/poet.song.229000.json','["藥山手中書佛字，問他端爾要心開。", "只將佛字爲酬對，元是曾持五戒來。"]'),
('b4e60eb8-3fae-439e-a5ac-6053963a7d1b','彌陀懸鼓相贊','釋如珙','宋','宋诗','song-poetry','','[]','彩雲縹緲懸紅日，瞻彼慈容大導師。',32,'全唐诗/poet.song.229000.json','["彩雲縹緲懸紅日，瞻彼慈容大導師。", "四十八願丘山重，衆生雜念亂如絲。"]'),
('32098eba-c6ec-4fa8-9d8e-b3144bf544b6','寒山贊','釋如珙','宋','宋诗','song-poetry','','[]','做詩無題目，只要寫心源。',48,'全唐诗/poet.song.229000.json','["做詩無題目，只要寫心源。", "心源雖難搆，淺深在目前。", "白雲抱幽石，藤花樹上紆。", "豐干不識你，道你是文殊。"]'),
('a084b2bf-a8ea-4e77-9b0a-724a6c58389e','拾得贊','釋如珙','宋','宋诗','song-poetry','','[]','是誰拾得你，便名爲拾得。',48,'全唐诗/poet.song.229000.json','["是誰拾得你，便名爲拾得。", "手把粗糲藜，要打天邊月。", "埽地却有功，眼界得浄潔。", "閭丘太守來，也解生欣悅。"]'),
('26666ea1-4bbc-406c-8df8-71fe63e32244','豐干贊','釋如珙','宋','宋诗','song-poetry','','[]','人心既無，虎心亦無。',30,'全唐诗/poet.song.229000.json','["人心既無，虎心亦無。", "騎來騎去，是汝是吾。", "松門杳杳，朗月輪孤。"]'),
('9f15f16b-77aa-4da1-9e9e-3b6259de97af','禪月大師畫羅漢像贊','釋如珙','宋','宋诗','song-poetry','','[]','禪月羅漢應身，畫出羅漢形像。',42,'全唐诗/poet.song.229000.json','["禪月羅漢應身，畫出羅漢形像。", "絲毫無得滲漏，虛空捏作一團。", "拈來掛虛空中，咄咄咄咄咄咄。"]'),
('5f439799-61b0-49b7-95f2-1ba3f7a46c21','達磨大師贊','釋如珙','宋','宋诗','song-poetry','','[]','破六宗己見固是，折莖蘆渡江還非。',52,'全唐诗/poet.song.229000.json','["破六宗己見固是，折莖蘆渡江還非。", "大道等虛空，非虛空之量。", "大道同日月，踰日月之明。", "一華開五葉，結果自然成。"]'),
('3aa10674-1f02-4292-b23a-27fb82d7f410','六祖大師贊','釋如珙','宋','宋诗','song-poetry','','[]','曹溪本無波浪，是他來者激起。',31,'全唐诗/poet.song.229000.json','["曹溪本無波浪，是他來者激起。", "日月星辰萬象，總被陸沈，出頭不得。"]'),
('7aa64579-5299-4834-ad4e-b03cec282f34','臨濟大師贊','釋如珙','宋','宋诗','song-poetry','','[]','得馬祖百丈黄檗之旨，發自己胸中本有底光明。',51,'全唐诗/poet.song.229000.json','["得馬祖百丈黄檗之旨，發自己胸中本有底光明。", "見僧入門便喝，謂之臨濟一宗。", "三世諸佛搆不著，狸奴白牯搆不著。"]'),
('6d8329c8-8220-45b2-b2ab-e45744759d2d','德山和尚贊','釋如珙','宋','宋诗','song-poetry','','[]','吹滅紙燈，眼前黑暗。',38,'全唐诗/poet.song.229000.json','["吹滅紙燈，眼前黑暗。", "拈得白棒，胡揮亂揮。", "黄河放出，太華裂開，大千沙界絕塵埃。"]'),
('1f80fcd1-ecf7-4d9f-bb15-cc975ae87a89','雲門大師贊','釋如珙','宋','宋诗','song-poetry','','[]','睦州拶折脚，如何嗣雪峯。',38,'全唐诗/poet.song.229000.json','["睦州拶折脚，如何嗣雪峯。", "一句內，三句外，星飛電捲。", "搆得著，搆不著，總是死漢。"]'),
('e24c8ee6-8b14-4a97-bd31-9a371935f926','趙州和尚贊','釋如珙','宋','宋诗','song-poetry','','[]','有底道趙州說禪，近在口皮邊，遠過河沙國，總描邈不著。',57,'全唐诗/poet.song.229000.json','["有底道趙州說禪，近在口皮邊，遠過河沙國，總描邈不著。", "鎮州出大蘿蔔頭，是他親見南泉。", "觀音院壁上，掛箇葫蘆，風吹不落。"]'),
('30eb96a2-a87c-447e-834d-ace1ea724578','慈明和尚贊','釋如珙','宋','宋诗','song-poetry','','[]','得人怕，得人憎。',28,'全唐诗/poet.song.229000.json','["得人怕，得人憎。", "嚇得神鼎，頭縮面青。", "燒火未著，晚參鼓鳴。"]'),
('17e25176-7f00-48b6-b446-b2730d769e9e','楊岐和尚贊','釋如珙','宋','宋诗','song-poetry','','[]','屋老四壁疎，雪珠床上跳。',24,'全唐诗/poet.song.229000.json','["屋老四壁疎，雪珠床上跳。", "猶有閑情懷，對白雲發笑。"]'),
('bf3d219b-2226-4545-9cf9-b7974400f7ff','虎丘隆和尚贊','釋如珙','宋','宋诗','song-poetry','','[]','睡虎一嘯，虛空掇轉。',40,'全唐诗/poet.song.229000.json','["睡虎一嘯，虛空掇轉。", "南辰居北，北辰居南。", "馿作馿鳴，犬作犬吠。", "外道消滅，正宗亦無。"]'),
('dc4a5779-04f1-4d51-9471-9f85e12fb440','天目和尚贊','釋如珙','宋','宋诗','song-poetry','','[]','不道先師具大眼目，只道先師無肯路。',93,'全唐诗/poet.song.229000.json','["不道先師具大眼目，只道先師無肯路。", "還有知得者麽，楊岐之衣到松源師祖不傳，臨終謂兄弟久聚。", "正路行者有，只不能用黑豆法。", "難以荷負正宗，臨濟佛法到此平沈。", "痛哉痛哉，以此見先師，深得師祖之旨矣。"]'),
('bf5e5264-8c5e-49fc-81e1-3921055740d6','天目和尚贊松源和尚像永長老請贊','釋如珙','宋','宋诗','song-poetry','','[]','我祖之真，是真非真。',55,'全唐诗/poet.song.229000.json','["我祖之真，是真非真。", "我父之贊，是贊非贊。", "非真是真，非贊是贊。", "塞破虛空，斷楊岐旨，滅臨濟宗。", "分付定水，打鳳羅龍。"]'),
('dd8a929a-822b-43b2-9915-ab6bab1b4294','禪人畫師像請贊  其一','釋如珙','宋','宋诗','song-poetry','','[]','不破古人玄關，而玄關自破。',40,'全唐诗/poet.song.229000.json','["不破古人玄關，而玄關自破。", "不碎今時窠臼，而窠臼自碎。", "鷲峰之衣爛却，西丘之話無傳。"]'),
('65f47447-6d35-4990-aafe-41a67971bb84','禪人畫師像請贊  其二','釋如珙','宋','宋诗','song-poetry','','[]','尺璧千丈石，寸金萬里沙。',24,'全唐诗/poet.song.229000.json','["尺璧千丈石，寸金萬里沙。", "揀辨俱不得，達磨返流沙。"]'),
('a9c8f88d-bdf9-464a-bc68-8a256aedf63a','禪人畫師像請贊  其三','釋如珙','宋','宋诗','song-poetry','','[]','黄檗不是臨濟，爭打六十拄杖。',42,'全唐诗/poet.song.229000.json','["黄檗不是臨濟，爭打六十拄杖。", "較之七佛已前，都無許多勞攘。", "即是吾真種草，何須特地寫像。"]'),
('0bbddfb7-1f06-432c-bb2a-c181fa7d84e8','禪人畫師像請贊  其四','釋如珙','宋','宋诗','song-poetry','','[]','持刀殺人，人心不死。',30,'全唐诗/poet.song.229000.json','["持刀殺人，人心不死。", "赤手殺人，人心不死。", "伎倆俱盡，人心自死。"]'),
('c1e1ddd0-7a8c-4aa0-b540-f19acb1d6d55','禪人畫師像請贊  其五','釋如珙','宋','宋诗','song-poetry','','[]','一喝從馬師起，臨濟承虛接響。',28,'全唐诗/poet.song.229000.json','["一喝從馬師起，臨濟承虛接響。", "病叟本無氣力，不能學這般承。"]'),
('06540b05-7451-4ab6-90eb-c530f1fe0b25','禪人畫師像請贊  其六','釋如珙','宋','宋诗','song-poetry','','[]','栽菜根向上，種豆要收穀。',24,'全唐诗/poet.song.229000.json','["栽菜根向上，種豆要收穀。", "不必生疑訝，今年六十六。"]'),
('aab3e820-f52e-481b-97c3-08c48954dde8','禪人畫師像請贊  其七','釋如珙','宋','宋诗','song-poetry','','[]','不是心，不是佛，不是物。',42,'全唐诗/poet.song.229000.json','["不是心，不是佛，不是物。", "新羅國裏打鼓，大唐殿上作舞。", "天上天下人癡癡，七佛傳來到六祖。"]'),
('4c29ad3a-d3a8-4a1e-9be0-53505dc534b8','禪人畫師像請贊  其八','釋如珙','宋','宋诗','song-poetry','','[]','道遠乎哉，觸事而真。',41,'全唐诗/poet.song.229000.json','["道遠乎哉，觸事而真。", "羅公照鏡，李婆映水。", "鼻孔各別，娘生一般。", "會與不會，福州使鐵錢。"]'),
('62203b86-6401-4b47-898c-28687c2feeb2','偈頌二十首  其一','釋如珙','宋','宋诗','song-poetry','','[]','日影每從窗外過，知他奔逐幾時休。',32,'全唐诗/poet.song.229000.json','["日影每從窗外過，知他奔逐幾時休。", "虛空落地須彌碎，三世如來不出頭。"]'),
('02c1b115-e23b-4207-807b-186f825349b6','偈頌二十首  其二','釋如珙','宋','宋诗','song-poetry','','[]','月在水中撈不上，徒勞戳碎水中天。',32,'全唐诗/poet.song.229000.json','["月在水中撈不上，徒勞戳碎水中天。", "夜深山寺開門睡，月自飛來到面前。"]'),
('62ad723e-49fa-4e08-b180-9a6855faf2a6','偈頌二十首  其三','釋如珙','宋','宋诗','song-poetry','','[]','人心到老不知休，心若休時萬事休。',32,'全唐诗/poet.song.229000.json','["人心到老不知休，心若休時萬事休。", "水上葫蘆捺得住，始信橋流水不流。"]'),
('7be25542-481a-43fd-84e8-f25e9dde3d51','偈頌二十首  其四','釋如珙','宋','宋诗','song-poetry','','[]','貪瞋癡衆生根本，衆生根本佛根本。',32,'全唐诗/poet.song.229000.json','["貪瞋癡衆生根本，衆生根本佛根本。", "佛無衆生不成佛，是故衆生佛根本。"]'),
('4016b4aa-0cda-41f6-9e0b-128f2c145791','偈頌二十首  其五','釋如珙','宋','宋诗','song-poetry','','[]','樓上五更鐘未動，人間萬事已營營。',32,'全唐诗/poet.song.229000.json','["樓上五更鐘未動，人間萬事已營營。", "明朝一飯先書籍，那取工夫細度量。"]'),
('747bf231-4467-421d-8a51-516895060298','偈頌二十首  其六','釋如珙','宋','宋诗','song-poetry','','[]','諸佛面前求早悟，衆生界上幾曾迷。',32,'全唐诗/poet.song.229000.json','["諸佛面前求早悟，衆生界上幾曾迷。", "本源自性天真佛，日用中間無少虧。"]'),
('90d87cf9-9ddf-4579-b62f-36ffddaf7288','偈頌二十首  其七','釋如珙','宋','宋诗','song-poetry','','[]','清浄世界清浄人，濁惡世界濁惡人。',32,'全唐诗/poet.song.229000.json','["清浄世界清浄人，濁惡世界濁惡人。", "隨性所轉移不得，總是娘生一箇身。"]'),
('f47d6f71-634c-4c6e-a6c5-dbd4c8490838','偈頌二十首  其八','釋如珙','宋','宋诗','song-poetry','','[]','觸目盡是清浄地，清浄地上無佛住。',32,'全唐诗/poet.song.229000.json','["觸目盡是清浄地，清浄地上無佛住。", "趙州教人急走過，狸奴倒上菩提樹。"]'),
('7a16b879-8baf-4694-b386-a1f58bff125e','偈頌二十首  其九','釋如珙','宋','宋诗','song-poetry','','[]','老已無心走市廛，娑羅樹下展身眠。',32,'全唐诗/poet.song.229000.json','["老已無心走市廛，娑羅樹下展身眠。", "餘生一了一切了，不去燒香向佛前。"]'),
('de154c14-c7f9-4d73-b29d-0fd33b1d9463','偈頌二十首  其一○','釋如珙','宋','宋诗','song-poetry','','[]','萬事成空皆已悉，一身無實亦深知。',32,'全唐诗/poet.song.229000.json','["萬事成空皆已悉，一身無實亦深知。", "絲毫名利放不過，得出輪迴是幾時。"]'),
('f06f6bc3-ed67-423a-962a-f027a9af36f3','偈頌二十首  其一一','釋如珙','宋','宋诗','song-poetry','','[]','曉來雲過闌干濕，手把圓珠獨自立。',32,'全唐诗/poet.song.229000.json','["曉來雲過闌干濕，手把圓珠獨自立。", "聲聲稱念南無佛，佛道現前不成佛。"]'),
('a65ba858-f590-45f5-abd3-6b1d4b8ea46a','偈頌二十首  其一二','釋如珙','宋','宋诗','song-poetry','','[]','魚浮水面性地平，鳥入林中機路密。',32,'全唐诗/poet.song.229000.json','["魚浮水面性地平，鳥入林中機路密。", "秋到石床楓葉落，夢幻伴子六十七。"]'),
('f667ef7a-36f3-4b46-bbc9-ddf919c09674','偈頌二十首  其一三','釋如珙','宋','宋诗','song-poetry','','[]','水邊林下道人行，念念無非是道情。',32,'全唐诗/poet.song.229000.json','["水邊林下道人行，念念無非是道情。", "盡去西方尋浄土，青蓮華在淤泥生。"]'),
('445f590a-1e90-47d4-b164-c1dc544a1102','偈頌二十首  其一四','釋如珙','宋','宋诗','song-poetry','','[]','稱心稱意可長保，上苑名園春日花。',32,'全唐诗/poet.song.229000.json','["稱心稱意可長保，上苑名園春日花。", "一箇尖頭茅屋下，長年無事道人家。"]'),
('ed820930-da36-4224-8fa8-aba5af86d417','偈頌二十首  其一五','釋如珙','宋','宋诗','song-poetry','','[]','大道在目前，本來無妙理。',48,'全唐诗/poet.song.229000.json','["大道在目前，本來無妙理。", "陽地生爲人，陰空死作鬼。", "月照嶺上松，風吹原下水。", "髼頭寒拾翁，拍手笑不已。"]'),
('85e14491-bfce-4d45-bf24-8fa8a357f3ea','偈頌二十首  其一六','釋如珙','宋','宋诗','song-poetry','','[]','人有黄金宅，棄之徒自忙。',48,'全唐诗/poet.song.229000.json','["人有黄金宅，棄之徒自忙。", "北風連地起，吹雪上眉梁。", "杳杳黄泉路，難逢日月光。", "吾儂如此說，且去審思量。"]'),
('d795fb9d-0826-418a-a48f-b6544bfc6be3','偈頌二十首  其一七','釋如珙','宋','宋诗','song-poetry','','[]','山中滋味別，往往少人知。',48,'全唐诗/poet.song.229000.json','["山中滋味別，往往少人知。", "野菜合黄獨，能充白日饑。", "風輕翻草葉，猿重墜藤枝。", "餘生只寄此，閒讀古人詩。"]'),
('8d5ec7d7-272f-4b39-b9c0-7dd8b199e180','偈頌二十首  其一八','釋如珙','宋','宋诗','song-poetry','','[]','老農隴上耕，終日手不住。',36,'全唐诗/poet.song.229000.json','["老農隴上耕，終日手不住。", "白骨誰家塚，群鴉噪高樹。", "一條淺溪水，滔滔自流去。"]'),
('fd298f24-0ff2-468b-a222-3cf5f7fc5eab','偈頌二十首  其一九','釋如珙','宋','宋诗','song-poetry','','[]','迷時從他迷，悟時聽他悟。',36,'全唐诗/poet.song.229000.json','["迷時從他迷，悟時聽他悟。", "九牛雖有力，拽之不可住。", "日落又黄昏，風吹白楊樹。"]'),
('5c40e9b3-8580-4bca-a70d-ac6da86bae49','偈頌二十首  其二○','釋如珙','宋','宋诗','song-poetry','','[]','吾家不甚遥，看取脚下路。',48,'全唐诗/poet.song.229000.json','["吾家不甚遥，看取脚下路。", "紅日上山頭，石羊草裏卧。", "人間一百年，彈指聲中過。", "柴門無鎖鑰，白雲自來去。"]'),
('0f76576a-0171-4bfc-be34-c83f9b0fb73d','過竹田西堂無相菴房','釋如珙','宋','宋诗','song-poetry','','[]','懶舉話頭嫌鼻祖，燒香那肯禮西方。',32,'全唐诗/poet.song.229000.json','["懶舉話頭嫌鼻祖，燒香那肯禮西方。", "空房消盡閑心識，日往月來不見長。"]'),
('b3674f1f-d47d-4021-a44d-8b09eb5c9920','清藏主歸鄉省親','釋如珙','宋','宋诗','song-poetry','','[]','入我門來先割愛，胡爲舊路又重行。',32,'全唐诗/poet.song.229000.json','["入我門來先割愛，胡爲舊路又重行。", "娑婆世界多寒暑，一箇皮囊幾度生。"]'),
('80a2c53e-fb25-40a3-b01f-c7870bd71dfb','送契首座住鴈山靈峰','釋如珙','宋','宋诗','song-poetry','','[]','曷送住持芝下寺，祖翁一箇破砂盆。',32,'全唐诗/poet.song.229000.json','["曷送住持芝下寺，祖翁一箇破砂盆。", "寒酸固是難開眼，煮飯猶堪煮菜根。"]'),
('ee1912e9-171f-4aec-ac78-ccd3ac8d93c5','示椿藏主','釋如珙','宋','宋诗','song-poetry','','[]','一夏工夫打不徹，百千億劫不消磨。',32,'全唐诗/poet.song.229000.json','["一夏工夫打不徹，百千億劫不消磨。", "金烏玉兔長相逐，鴈蕩峰頭見也麽。"]'),
('02cafde3-18f1-440d-8bf2-fd7faa8aacd1','到中山寶首座房','釋如珙','宋','宋诗','song-poetry','','[]','巖房終日冷沈沈，經案塵埃一寸深。',32,'全唐诗/poet.song.229000.json','["巖房終日冷沈沈，經案塵埃一寸深。", "五十餘年如此過，道人行世太無心。"]'),
('d83ebf1d-9256-4434-ae8c-2fc6ca9da3c7','永藏主到鴈蕩山放牧寮請益','釋如珙','宋','宋诗','song-poetry','','[]','老來自病救不了，佛病祖病孰能排。',32,'全唐诗/poet.song.229000.json','["老來自病救不了，佛病祖病孰能排。", "壁上葫蘆風打落，床頭拄杖被塵埋。"]'),
('b5cc8fc8-96c5-4e39-8e97-e0cd27a50860','寄予藏主','釋如珙','宋','宋诗','song-poetry','','[]','要成大樹作陰凉，放教片心如泥去。',32,'全唐诗/poet.song.229000.json','["要成大樹作陰凉，放教片心如泥去。", "雲門一舉四十九，臨濟大師無本據。"]'),
('da6c10d0-63f2-4f53-9afd-8820d33a40cd','示莫侍者','釋如珙','宋','宋诗','song-poetry','','[]','參禪只要見得盡，見得盡時無障礙。',32,'全唐诗/poet.song.229000.json','["參禪只要見得盡，見得盡時無障礙。", "六箇門頭長日開，聲香味觸常三昧。"]'),
('6e926bd0-8bfd-4db8-b62f-e99963e5feee','寄明藏主','釋如珙','宋','宋诗','song-poetry','','[]','一顆如來藏裡珠，靈光爍破衆人疑。',32,'全唐诗/poet.song.229000.json','["一顆如來藏裡珠，靈光爍破衆人疑。", "大千沙界無塵土，即是塵勞未脫時。"]'),
('b6ca5f4f-3ddc-49c6-a962-bd1e18cb8606','寄息首座','釋如珙','宋','宋诗','song-poetry','','[]','黄檗三度打臨濟，睦州合喫棒三千。',32,'全唐诗/poet.song.229000.json','["黄檗三度打臨濟，睦州合喫棒三千。", "乾坤儱侗無今古，猛將不來邊上眠。"]'),
('2f9c42d0-4664-4c31-90db-664ff96dd00a','示然侍者','釋如珙','宋','宋诗','song-poetry','','[]','以法傳法獅子吼，以心傳心鐵牛機。',32,'全唐诗/poet.song.229000.json','["以法傳法獅子吼，以心傳心鐵牛機。", "十方世界無行路，圓覺空中有路歸。"]'),
('991d8b5c-fada-4791-9ea6-45bc501948bb','送權侍者遊洞庭','釋如珙','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','七十二峰波面出，盧公去後石屏存。',32,'全唐诗/poet.song.229000.json','["七十二峰波面出，盧公去後石屏存。", "高歌數曲遊三日，圖畫又添僧一尊。"]'),
('7062e748-8537-43d8-af5f-95d397651ec6','寄梓巖西堂和尚','釋如珙','宋','宋诗','song-poetry','','[]','每問往來興寢事，惟言閉戶自安禪。',32,'全唐诗/poet.song.229000.json','["每問往來興寢事，惟言閉戶自安禪。", "西丘壽到八十四，住院都盧無十年。"]'),
('0d64a36f-54e0-49c2-8982-75a1191fe4be','寄寶藏主','釋如珙','宋','宋诗','song-poetry','','[]','識塵消落盡，本性自圓明。',48,'全唐诗/poet.song.229000.json','["識塵消落盡，本性自圓明。", "動靜無差異，語言只似常。", "後到不過此，先來亦只寧。", "坐禪一片石，松樹長青青。"]'),
('dfef3aa4-c261-4128-a917-f96f163a05ba','送明藏主','釋如珙','宋','宋诗','song-poetry','','[]','門內天地闊，門外山水長。',72,'全唐诗/poet.song.229000.json','["門內天地闊，門外山水長。", "一句未脫口，遍界是冰霜。", "寒光奪夜月，鬼神不敢當。", "本來清浄性，胸中無留藏。", "拾得是我弟，寒山是我兄。", "明朝相隨去，一錫兼一瓶。"]'),
('26e708f7-4315-466b-a1b9-27995a588bc3','示收侍者','釋如珙','宋','宋诗','song-poetry','','[]','人言不是面通紅，此病流來自劫空。',32,'全唐诗/poet.song.229000.json','["人言不是面通紅，此病流來自劫空。", "拈出洞山三頓棒，慈明老漢得黄龍。"]'),
('38c43ca8-e8fa-40eb-9213-6a3d8ce91396','送靈石齊物長老','釋如珙','宋','宋诗','song-poetry','','[]','方丈守職莫輕忽，自然久久見全功。',32,'全唐诗/poet.song.229000.json','["方丈守職莫輕忽，自然久久見全功。", "楊岐只是會監寺，踢出馿兒振祖風。"]'),
('e64803da-9062-4e27-9a43-a7a223f827ff','寄端書記','釋如珙','宋','宋诗','song-poetry','','[]','青猿長短聲，獨自倚廊柱。',72,'全唐诗/poet.song.229000.json','["青猿長短聲，獨自倚廊柱。", "三際俱不來，一片冷泉水。", "非唯無衆生，無佛亦無己。", "短句與長吟，遣興適意耳。", "半夜落霜華，日輪正卓午。", "寥寥天地間，只有寒山子。"]'),
('66e09fda-33ff-41cf-8723-4040c3373c85','送茂侍者','釋如珙','宋','宋诗','song-poetry','','[]','一鶚度秋空，秋空無影跡。',60,'全唐诗/poet.song.229000.json','["一鶚度秋空，秋空無影跡。", "千人萬人海，聚頭空唧唧。", "點黑楊岐衣，鷲峰藏得密。", "寒暑知幾年，分付當有日。", "談玄說妙者，脫去情塵執。"]'),
('195bc5a3-8a8b-4b82-87c9-b95e0b92157d','示明侍者','釋如珙','宋','宋诗','song-poetry','','[]','布毛吹起便悟去，未吹布毛何不悟。',32,'全唐诗/poet.song.229000.json','["布毛吹起便悟去，未吹布毛何不悟。", "三三九九八十一，雲門大師有抽顧。"]'),
('49d3b386-e8df-4bb1-91ad-14c5a142123b','寄灌頂長老','釋如珙','宋','宋诗','song-poetry','','[]','半夜鶴鳴山月吟，山翁獨坐破柴床。',32,'全唐诗/poet.song.229000.json','["半夜鶴鳴山月吟，山翁獨坐破柴床。", "幾番劫石成灰去，一點靈光照世明。"]'),
('cc71fd81-bec5-423b-bb53-177bb0424c31','示至侍者','釋如珙','宋','宋诗','song-poetry','','[]','我宗無語亦無法，獼猴各佩古菱花。',32,'全唐诗/poet.song.229000.json','["我宗無語亦無法，獼猴各佩古菱花。", "昏衢燭破無今古，大地衆生盡到家。"]'),
('6d1453f5-5137-460a-9066-2bf78de6af60','送一維那','釋如珙','宋','宋诗','song-poetry','','[]','扣我山寮門，乃是我法姪。',60,'全唐诗/poet.song.229000.json','["扣我山寮門，乃是我法姪。", "來情不用推，一一皆著實。", "生柴带葉燒，新水敲冰汲。", "難得再相逢，今年六十七。", "歸去望東溟，天岸一團日。"]'),
('147d7c4a-7083-4024-9b23-2109b8bc03e9','送琦上人','釋如珙','宋','宋诗','song-poetry','','[]','萬里無寸草，出門便是草。',72,'全唐诗/poet.song.229000.json','["萬里無寸草，出門便是草。", "十年歸不得，忘却來時道。", "今歲秋事早，凉風生木杪。", "拄杖挑鉢囊，銳志不小小。", "孰顧他洞山，瀏陽寒拾老。", "衲僧家行履，不可得尋討。"]'),
('784ef12f-d844-4237-90a4-44970de5917c','寄雪竇千峰琬西堂','釋如珙','宋','宋诗','song-poetry','','[]','千丈崖根芋火香，天上日輪正卓午。',32,'全唐诗/poet.song.229000.json','["千丈崖根芋火香，天上日輪正卓午。", "東土西乾無祖師，白頭老僧七十五。"]'),
('0d0a782c-ee24-45e2-96b4-505352551f37','道藏主號物外因作此偈','釋如珙','宋','宋诗','song-poetry','','[]','何處是物外，徒然勞指註。',48,'全唐诗/poet.song.229000.json','["何處是物外，徒然勞指註。", "物物皆唯我，我實無比喻。", "去却我一字，動靜隨所寓。", "靈光遍寰宇，今古絕來去。"]'),
('7c3c64e0-8095-486e-a8ec-0d1b0b0532f6','寄海藏主','釋如珙','宋','宋诗','song-poetry','','[]','佛佛授手無多子，祖祖相傳似海深。',32,'全唐诗/poet.song.229000.json','["佛佛授手無多子，祖祖相傳似海深。", "昨夜西風撼門扇，天明無跡可追尋。"]'),
('f898e981-c54b-4c11-91d9-d1d217ef24a2','送徹上人遊台鴈','釋如珙','宋','宋诗','song-poetry','','[]','多人乞語過台鴈，上人亦向那邊遊。',80,'全唐诗/poet.song.229000.json','["多人乞語過台鴈，上人亦向那邊遊。", "寒拾不能登妙覺，只爲貪著山水幽。", "巨羅長年抱膝坐，癡癡更是不知休。", "春花正開香滿路，日輪卓午山氣收。", "乘興去時宜速速，乘興回來莫悠悠。"]'),
('2eda53d9-f696-43a4-ac8c-8c6d27cfabd9','送真藏主','釋如珙','宋','宋诗','song-poetry','','[]','達磨不曾來東土，二祖亦不往西天。',32,'全唐诗/poet.song.229000.json','["達磨不曾來東土，二祖亦不往西天。", "一條古路生荆棘，更無佛法可流傳。"]'),
('7faf97c1-9716-4b0d-8c8a-577339eee23c','示霞上人','釋如珙','宋','宋诗','song-poetry','','[]','一大藏教言外薦，十方剎土目前看。',32,'全唐诗/poet.song.229000.json','["一大藏教言外薦，十方剎土目前看。", "老僧住世無多日，只要闍梨心地安。"]'),
('5d2b1cfe-5112-4cee-94f7-2709fd844005','寄靈仲通姪','釋如珙','宋','宋诗','song-poetry','','[]','一樓山色好，山是飛來山。',60,'全唐诗/poet.song.229000.json','["一樓山色好，山是飛來山。", "座上方外友，身心俱閒閒。", "秋來幾夜夢，踏月到其間。", "更轉語方定，瓦爐香未殘。", "一偈聊相寄，山寮長日關。"]'),
('a51dc267-b5d3-4a62-b9ae-a66e6cd4413d','拄杖歌','釋如珙','宋','宋诗','song-poetry','','[]','老龍蛻骨空山，樵人惠我作杖。',54,'全唐诗/poet.song.229000.json','["老龍蛻骨空山，樵人惠我作杖。", "靠在繩床角頭，團團圍繞萬象。", "打狗打雨敲風，總是顛倒妄想。", "有人拗作兩橛，伏惟尚饗。"]'),
('9855fc1b-7e9e-4813-a0e5-cd76ce333ec1','歸山','釋如珙','宋','宋诗','song-poetry','','[]','衰老歸山寮，山寮無雜事。',60,'全唐诗/poet.song.229000.json','["衰老歸山寮，山寮無雜事。", "柴床石枕頭，長伸兩脚睡。", "寒拾約不來，豐干騎虎至。", "虎性本不馴，蒼苔都踏碎。", "春風補得完，八八六十四。"]'),
('54a7a101-8731-41fb-bb84-bd317c2291df','此菴歌','釋如珙','宋','宋诗','song-poetry','','[]','吾結此菴寄殘影，有問此菴壞不壞。',112,'全唐诗/poet.song.229000.json','["吾結此菴寄殘影，有問此菴壞不壞。", "一語發出甚奇怪，隨他口下答不壞。", "凡屬形相皆是壞，爲甚此菴却不壞。", "六窗俱透無一物，常光無內亦無外。", "劫火洞然大千壞，吾結此菴實不壞。", "行住坐卧於其中，只是尋常箇境界。", "有時松風閒舉話，萬象森羅齊爽快。"]'),
('da2b7651-7c8a-46eb-9b16-6470bc77f8a7','示恩藏主','釋如珙','宋','宋诗','song-poetry','','[]','道在目前無變易，只緣體悉有親疎。',32,'全唐诗/poet.song.229000.json','["道在目前無變易，只緣體悉有親疎。", "黄梅夜半傳衣鉢，七百人中一老盧。"]'),
('724cbfeb-526d-440d-9b85-3e3d95921abf','寄琢間和尚','釋如珙','宋','宋诗','song-poetry','','[]','聞得去年交院事，世間誰識老師心。',32,'全唐诗/poet.song.229000.json','["聞得去年交院事，世間誰識老師心。", "青山綠水門前有，浄土西方不去尋。"]'),
('940b9644-b49c-4771-9c83-a72f092478d0','塔偈','釋如珙','宋','宋诗','song-poetry','','[]','午夜髑髏吟，山空片月明。',24,'全唐诗/poet.song.229000.json','["午夜髑髏吟，山空片月明。", "西方無浄土，只有彌陀經。"]'),
('06661bd0-d577-4ced-8681-d2cbcdedae37','塔銘','釋如珙','宋','宋诗','song-poetry','','[]','天生一穴，藏吾枯骨。',40,'全唐诗/poet.song.229000.json','["天生一穴，藏吾枯骨。", "骨朽成土，土能生物。", "結箇葫蘆，掛趙州壁。", "永脫輪迴，超三世佛。"]'),
('dcda084c-2582-4756-8cbc-4edec395434c','雁山','釋如珙','宋','宋诗','song-poetry','','[]','石龍滴滴鼻中水，二十名泉類莫齊。',32,'全唐诗/poet.song.229000.json','["石龍滴滴鼻中水，二十名泉類莫齊。", "頭白山翁貪潄齒，杖藜逐石過橋西。"]'),
('33fedbc6-ffcc-4eea-9cdf-6973739977fa','館中送鄭著作','馬廷鸞','宋','宋诗','song-poetry','','[]','士爲慾心縛，蝸牛粘壁枯。',180,'全唐诗/poet.song.229000.json','["士爲慾心縛，蝸牛粘壁枯。", "榮華不盈睫，咎責彌八區。", "不有君子人，中流誰一壺。", "公懷天台秋，夙昔廊廟須。", "南宮接東觀，並轡驂天衢。", "幽憂腸內熱，慷慨涕濡縷。", "拜疏上虛皇，誦言折姦愚。", "肝腦非己物，宇宙須人扶。", "恭惟天王聖，肯使善類孤。", "一朝擁麾蓋，自詭歌袴襦。", "黟歙股肱郡，新安文物都。", "斯文紫陽翁，千載長昭蘇。", "稻苗新進士，倚公爲播敷。", "繭絲困窮民，願公薦蒍于。", "勉哉崇明德，歸來誦唐虞。"]'),
('cd877deb-d5c9-4590-a380-426b36f8de92','皇太子生辰詩三首  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','煌煌炎宋興，奕世開燕謀。',96,'全唐诗/poet.song.229000.json','["煌煌炎宋興，奕世開燕謀。", "建隆聖人出，庚年寶運周。", "祥符帝子生，巳月神光流。", "稽首頌儲君，昭哉遹嘉猷。", "吹銅協乾陽，主鬯彌千秋。", "星暉狼弧低，海潤青齊收。", "金輪整鶴駕，玉觴侍龍樓。", "無逸能爲壽，乾乾謹時休。"]'),
('2a565319-b4cb-471c-96ce-17c275a4a5f6','皇太子生辰詩三首  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','蒼龍見天東，房駟拱辰北。',96,'全唐诗/poet.song.229000.json','["蒼龍見天東，房駟拱辰北。", "煌煌心星前，炳炳天王側。", "休符協乾文，正陽毓紫極。", "銅樓藹祥光，玉巵奉愉色。", "歎聲沸笙鸞，壽齡指箕翼。", "何以祝元良，勉哉崇明德。", "學問日就將，福祿時萬億。", "永侍帝宸尊，重暉照四國。"]'),
('ff42a0f4-aaca-4520-a9d9-caae33b6f27c','皇太子生辰詩三首  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','正陽毓前星，盛事符仁祖。',96,'全唐诗/poet.song.229000.json','["正陽毓前星，盛事符仁祖。", "仁者壽之基，生意一何溥。", "歡愉侍宮庭，暉潤彌海宇。", "三朝謹師文，寸陰勤惜禹。", "新功鑑銘盤，妙用明絜矩。", "嘉賓從商園，末僚愧韓愈。", "永言祝儲君，重離日常午。", "八表躋春臺，萬年受天祜。"]'),
('4906b557-5619-4d2f-8b81-6784ab407251','用大東萊臨川詩韻示諸兒','馬廷鸞','宋','宋诗','song-poetry','','[]','惠子五車書，彼富吾何慊。',72,'全唐诗/poet.song.229000.json','["惠子五車書，彼富吾何慊。", "滔滔歲崢嶸，濯濯木荏苒。", "前榮悼虛誇，新懦就退斂。", "東鄰有碩師，簦篋孰云遠。", "斯文豈終窮，小子宜黽勉。", "寒檠炷老膏，此興復不淺。"]'),
('720870a9-7e18-4626-8db4-0ec01a09a1f2','次韻周公謹見寄  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','十年思美人，淵淪抑天飛。',48,'全唐诗/poet.song.229000.json','["十年思美人，淵淪抑天飛。", "辛勤種青門，竟作抱蔓歸。", "日月老賓送，霜露沾人衣。", "沾衣何足云，八表籠煙霏。"]'),
('86a6a251-06f7-40d7-9766-ed1f2d651a52','次韻周公謹見寄  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','空山學仙子，滿耳笙簫聽。',48,'全唐诗/poet.song.229000.json','["空山學仙子，滿耳笙簫聽。", "誰知九天上，雲扉本不扃。", "度世同御風，蓬蓬隨飄零。", "又如芬陀花，出火而青青。"]'),
('9392ef0c-233a-4dcd-8d19-f3d03db4f213','次韻周公謹見寄  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','涪翁雪堂仙，分誼故不疎。',48,'全唐诗/poet.song.229000.json','["涪翁雪堂仙，分誼故不疎。", "投之孤芳篇，托根豈云虛。", "報以蟠桃實，一嘗千載餘。", "洗髓躡閬苑，游於物之初。"]'),
('ebfabfd3-900b-4a6d-9fb3-e6d0e9186e46','次韻周公謹見寄  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','射洪高蹈翁，哀歌淚盈盈。',48,'全唐诗/poet.song.229000.json','["射洪高蹈翁，哀歌淚盈盈。", "幽居觀元化，悼此歲月更。", "感遇三十篇，讀之慨余情。", "白露號玄蟬，春日鳴倉庚。"]'),
('73c3a987-37e1-4fa2-aec0-4c45f4bb32dc','次韻周公謹見寄  其五','馬廷鸞','宋','宋诗','song-poetry','','[]','退之懷桂林，藥物珍陸離。',48,'全唐诗/poet.song.229000.json','["退之懷桂林，藥物珍陸離。", "物情惡衰歇，義心感親知。", "我生欠一死，不死當語誰。", "與我制頹齡，悠悠白雲期。"]'),
('7ae9e6be-517f-4597-bb10-862b9af2ddec','題王氏琴清堂','馬廷鸞','宋','宋诗','song-poetry','','[]','孤桐缺月風露秋，夜蟲催織寒颼飀。',160,'全唐诗/poet.song.229000.json','["孤桐缺月風露秋，夜蟲催織寒颼飀。", "拂牀文字翻葉葉，古心埋沒從何求。", "客來洗予箏笛耳，清圜琅然散百憂。", "南窗無絃鼓愈淡，焦尾有桐棄不收。", "卓哉奇士千載去，已矣奇弄萬古休。", "江左諸王孫子儔，琴清之堂遺風流。", "飛泉爽籟十二操，鏗鏘浮玉鳴天球。", "文王宣父次第作，此身還見大雅不。", "收拾書囊雜釣具，伴君携琴隠林丘。", "作詩一爲寫奇趣，此生此興長悠悠。"]'),
('ff809c1c-96ae-4adc-bcbb-99e4ecb354fa','次韻謝潔齋惠春膏紙','馬廷鸞','宋','宋诗','song-poetry','','[]','霜毫禿盡千枝竹，銅雀臺荒死潘谷。',176,'全唐诗/poet.song.229000.json','["霜毫禿盡千枝竹，銅雀臺荒死潘谷。", "哀哉四寶併成空，猶有老崖藤搗玉。", "青錢學士將相科，黑頭刺史朱丹轂。", "懷銀早去鎮湖湘，掞藻端如起巴蜀。", "天乎歲晚椓斯文，往往長吟書短幅。", "雲昏雨暗白龍牋，林密山深紫芝曲。", "鳳樓誰助斧斤修，魚網不禁塵土辱。", "我馳家畔楮先生，越薄吳腴此粗俗。", "鏗金戛玉新有聲，縫霧裁雲豈堪錄。", "向來交友文字間，矢往湍奔如撒菽。", "薄材那敢派江西，一寸詩腸愁萬斛。"]'),
('1a47f95f-df5d-4d53-9e58-c45a5d18c9b1','次韻湯叔遜謝筆墨長句','馬廷鸞','宋','宋诗','song-poetry','','[]','南屏翁，斯文千古何終窮，清輝靈氣斗牛充。',222,'全唐诗/poet.song.229000.json','["南屏翁，斯文千古何終窮，清輝靈氣斗牛充。", "我從公家二老話此事，寒更支坐燭跋紅。", "哀哉人琴俱亡天地覆，有刀有玉誰錯礲。", "翁今巋然魯靈殿，砥柱一葉萬仞中。", "朅來訪我維摩室，我起于坐欣迎公。", "驚呼絕嘆吾道厄，客卿穎士委蒿蓬。", "竈煤葦管不足用，宣城黟水無良工。", "奈何盲卒乘鈍馬，欲寫傑作稱詞雄。", "贈公撒雷揮電施敏手，餘事渲染文字如飛蟲。", "我生哀傷所欠死，十年破硯烟雨濛。", "一朝洗眼獲玉句，金膏水碧浸方瞳。", "翰墨場中身老大，期公盛氣晚霞同。", "崢嶸素論猶激烈，始信迂儒曲學如發蒙。"]'),
('549f2726-a89f-4edf-9383-750a4a7b410d','謝吳直卿惠嘉樹篇','馬廷鸞','宋','宋诗','song-poetry','','[]','槐底婆娑生意盡，柳邊摇落長年悲。',48,'全唐诗/poet.song.229000.json','["槐底婆娑生意盡，柳邊摇落長年悲。", "殷東陽守徒嗟惜，桓大將軍自涕洟。", "不知庾叟江潭賦，何似延陵季子詩。"]'),
('eea04980-2926-4942-88d4-4ea3d01375b9','次趙二車韻','馬廷鸞','宋','宋诗','song-poetry','','[]','世事真如此，勞生何所知。',48,'全唐诗/poet.song.229000.json','["世事真如此，勞生何所知。", "功名蟻行磨，意氣鵲棲枝。", "于蒍歌偏好，歸來賦足師。", "達人寧自苦，天樂更無疑。"]'),
('27867d3c-2138-4350-96ad-0d2fb9f0e1d3','次李改卿韻','馬廷鸞','宋','宋诗','song-poetry','','[]','麗句費敲推，清吟出競病。',48,'全唐诗/poet.song.229000.json','["麗句費敲推，清吟出競病。", "日長簡編叢，春老蓬蒿徑。", "志士苦憂時，高人思繕性。", "山房讀道書，晚花紅艷靜。"]'),
('c80c4bd0-9f54-4215-8a54-f6b3fad023d8','恭進理宗皇帝挽詞  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','仁孝初聞代，謳歌早戴虞。',48,'全唐诗/poet.song.229000.json','["仁孝初聞代，謳歌早戴虞。", "多能天與聖，大度祖同符。", "惻怛欽刑詔，嚴恭事帝圖。", "初終兩甲子，經遠有宏模。"]'),
('591c96b8-2dd1-4368-a7bd-59fa4078053b','恭進理宗皇帝挽詞  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','典學懷終始，熈明四十年。',48,'全唐诗/poet.song.229000.json','["典學懷終始，熈明四十年。", "立心天地厚，接統帝王前。", "舄奕臨雍禮，昭回贊道篇。", "古今惟理大，尊號冠瑶編。"]'),
('ea2d0c71-5abb-4690-af70-f0d83a57bbd7','恭進理宗皇帝挽詞  其三','馬廷鸞','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天保惟勤政，春秋有復讎。',48,'全唐诗/poet.song.229000.json','["天保惟勤政，春秋有復讎。", "園陵初謁漢，境土合歸周。", "連海滄波靜，長江兵祲收。", "庚申重立極，功與建隆侔。"]'),
('69b7ecc2-e95f-4759-86ea-f08783aed38d','恭進理宗皇帝挽詞  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','神冊方增授，龍髯遽莫攀。',48,'全唐诗/poet.song.229000.json','["神冊方增授，龍髯遽莫攀。", "千秋思沛邑，七月葬稽山。", "春暗觚稜影，星回羽衛班。", "寢門如昨日，無復侍威顔。"]'),
('d2aedc0b-a55b-4df4-94d5-37e78c18a8a9','恭進理宗皇帝挽詞  其五','馬廷鸞','宋','宋诗','song-poetry','','[]','盡拜宸奎賜，新編聖訓成。',48,'全唐诗/poet.song.229000.json','["盡拜宸奎賜，新編聖訓成。", "孫謀方燕翼，龍馭忽遐征。", "四海堯音密，三年舜慕情。", "因山圖固在，合應若神明。"]'),
('fc26fa7a-1067-4eac-9cd0-7c32349dc637','十月二十六日甲子','馬廷鸞','宋','宋诗','song-poetry','','[]','乘雲傷往歲，甲子又今晨。',48,'全唐诗/poet.song.229000.json','["乘雲傷往歲，甲子又今晨。", "莫唱貞元曲，誰爲寶慶人。", "早霜明带月，寒菊艷爭春。", "敢睨昭陵柏，僞呵有鬼神。"]'),
('18ca8fee-b2f7-4602-a8fd-cfdd749a5bbc','贈汪泰軒','馬廷鸞','宋','宋诗','song-poetry','','[]','萬言朝鳳闕，一笑落漁舟。',48,'全唐诗/poet.song.229000.json','["萬言朝鳳闕，一笑落漁舟。", "把我葱珩解，從公款段游。", "東來迎羽服，西去羨羊裘。", "揮手謝漢使，蒲輪公所羞。"]'),
('8b35831a-0cc7-4a0f-a831-65a2fba570e4','久雨潦漲未已','馬廷鸞','宋','宋诗','song-poetry','','[]','一雨遂踰月，連朝仍徹宵。',48,'全唐诗/poet.song.229000.json','["一雨遂踰月，連朝仍徹宵。", "雷公自收麥，田父不耘苗。", "時見危垣墮，仍聞比屋漂。", "愧無援溺手，窮巷有持橈。"]'),
('03cab893-9cf6-4b7f-a03c-393dbf59b6d3','恭進度宗皇帝挽詞  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','四閏臨朝淺，羣生被澤深。',48,'全唐诗/poet.song.229000.json','["四閏臨朝淺，羣生被澤深。", "儉勤成禹聖，仁孝本虞心。", "漢殿觴稱玉，軒湖鼎鑄金。", "龍髯攀不得，清血但盈襟。"]'),
('a4e30c6c-e4d9-47e3-b9e6-085c63b33e2b','恭進度宗皇帝挽詞  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','道遠年何駛，民肥身獨癯。',48,'全唐诗/poet.song.229000.json','["道遠年何駛，民肥身獨癯。", "寶龜傳聖子，玉几導宸謨。", "百世尊王度，千秋拱帝圖。", "孤臣慙舜輔，愁絕望蒼梧。"]'),
('012c09dd-47cb-4a63-af6e-70c2094765b4','答趙心游與梭','馬廷鸞','宋','宋诗','song-poetry','','[]','亦有猗那頌，從誰說象賢。',48,'全唐诗/poet.song.229000.json','["亦有猗那頌，從誰說象賢。", "振振麟趾族，煜煜錦袍仙。", "禮樂三雍對，神明百世傳。", "王孫何處隠，芳草自連天。"]'),
('9f995803-1696-4645-86dc-41a9ba5602ba','程楚翁訪考亭舊居著閩山集爲題其後','馬廷鸞','宋','宋诗','song-poetry','','[]','有客傳吟藁，知渠來自閩。',48,'全唐诗/poet.song.229000.json','["有客傳吟藁，知渠來自閩。", "四書猶在魯，六籍不憂秦。", "太史經鄒嶧，離騷感楚臣。", "誰知夢奠日，曾憶後庚申。"]'),
('7f7137e8-f489-499d-a60e-4f6694eb99ee','挽李樓峰  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','萬選膠庠上，三長渠觀中。',48,'全唐诗/poet.song.229000.json','["萬選膠庠上，三長渠觀中。", "端從繡衣使，直擬黑頭公。", "柯爛全枰換，舟移絕壑空。", "素交與年盡，老眼視天夢。"]'),
('fa879732-919a-4b43-a083-39e4dec4fc73','挽李樓峰  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','短槧傳邊警，長篇罄畝忠。',48,'全唐诗/poet.song.229000.json','["短槧傳邊警，長篇罄畝忠。", "危邦韜晝錦，劇盜剪春葱。", "地隔幾廬舍，天憐兩禿翁。", "而今吾後死，作傳豈能工。"]'),
('887794dd-a262-43af-92ee-6bee94e5df6d','挽徐朝奉  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','海內嗟遺老，諸公表逸民。',48,'全唐诗/poet.song.229000.json','["海內嗟遺老，諸公表逸民。", "過庭忠訓在，攀檻直聲新。", "諫草頻尊主，緋花與顯親。", "一門名父子，千載慶君臣。"]'),
('f5b0231c-cf39-4eab-9ebf-f8c44dc890bd','挽徐朝奉  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','兒罷金華講，翁從林下歸。',48,'全唐诗/poet.song.229000.json','["兒罷金華講，翁從林下歸。", "清時伯夷粟，愉色老萊衣。", "洛社風流在，襄陽耆舊稀。", "瀧岡有名筆，字字獨幽輝。"]'),
('e9f8254e-dc58-4ea3-9eef-03ceb3b5cd92','次韻潔堂五日','馬廷鸞','宋','宋诗','song-poetry','','[]','故國天中節，吾儕日暮年。',48,'全唐诗/poet.song.229000.json','["故國天中節，吾儕日暮年。", "愁心菖歜苦，悲緒綵絲牽。", "疊雪虛唐賜，薰風絕舜絃。", "窮山飣越果，醉摘尚凄然。"]'),
('ca871c6c-e17d-4926-aa2a-bf7acec5c2e0','挽費潔堂  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','井絡璠璵瑞，江干英簜馳。',48,'全唐诗/poet.song.229000.json','["井絡璠璵瑞，江干英簜馳。", "萬屯孤宿飽，一旅共時危。", "行地嗟蓬轉，呼天泣黍離。", "百年公有盡，一慟我非私。"]'),
('6d84d0c0-1cf3-4c0c-aa6f-edbbcd632586','挽費潔堂  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','共事咸淳帝，俱生嘉定年。',48,'全唐诗/poet.song.229000.json','["共事咸淳帝，俱生嘉定年。", "江湖正寥闊，梁楚忽姻連。", "不作武擔掾，翻成葛水仙。", "豈忘渠劍閣，來閉此荒阡。"]'),
('ae95edeb-f0af-4bd8-8020-64a292729c68','挽陳本齋','馬廷鸞','宋','宋诗','song-poetry','','[]','擢第韓歐上，論交澗浦邊。',48,'全唐诗/poet.song.229000.json','["擢第韓歐上，論交澗浦邊。", "聲名寧我後，官職遜人先。", "徐廣生多戚，龔賓死獨賢。", "拊膺前劫事，雪涕大招篇。"]'),
('f9cb62b7-6f26-42d6-90a2-3802710bb5ab','贈程楚翁','馬廷鸞','宋','宋诗','song-poetry','','[]','汗竹丹鉛側，空花粉黛中。',48,'全唐诗/poet.song.229000.json','["汗竹丹鉛側，空花粉黛中。", "尚懷丞相亮，肯署大夫雄。", "有客來今雨，誇予邁古風。", "幽情傾不竭，渺渺碧雲東。"]'),
('1e80770f-b32e-4caf-b497-fc77708ec67e','恭進明堂大禮慶成詩','馬廷鸞','宋','宋诗','song-poetry','','[]','鉅典崇邦祀，精禋展國陽。',288,'全唐诗/poet.song.229000.json','["鉅典崇邦祀，精禋展國陽。", "泰元神授筴，癸亥日宣光。", "藝祖郊天始，高皇受命長。", "後庚基再造，先甲迓殊祥。", "率育歌時夏，儀刑詠我將。", "天街澄析木，農扈慶金穰。", "築塞懲獯鬻，梯山謝越裳。", "宗祈嚴美報，親享薦嘉嘗。", "周士咸奔走，堯民共頌揚。", "青冥收夕雨，華耀炳朝陽。", "月御金波穆，星流珠幄黄。", "九重紛羽衛，十二駕龍驤。", "鋗玉琳琅展，軒朱磬管鏘。", "時行肅天步，安坐集神鴹。", "聖孝昭初祼，元良儼貳觴。", "旗常森妸娜，黼黻罷周張。", "柴燄千靈墮，蘭膏百末香。", "金雞初日麗，丹鳳德風翔。", "薄海乾施博，垂雲解澤滂。", "批周仍蹋晉，蹴漢亦超唐。", "臣淺來蓬戶，君仁點玉堂。", "恩書容稿進，嘉頌媿辭荒。", "有道帝能享，難諶聖敢康。", "畏威勤夙夜，萬壽祝君王。"]'),
('67d6df1e-6c78-4412-81df-9b50c2d8bc3d','恭和御製詩  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','聖作巍巍泰華高，淋漓賜筆灑春膏。',64,'全唐诗/poet.song.229000.json','["聖作巍巍泰華高，淋漓賜筆灑春膏。", "奎文河漢天垂象，藻思波瀾海駕鼇。", "淳化罕逢休歎昉，大中親遇不誇綯。", "驪珠數十光盈把，何啻春秋一字褒。"]'),
('0b64eafd-947d-4493-885b-cdcb8b93714c','恭和御製詩  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','直廬峻在九霄高，雨露恩光切仰膏。',64,'全唐诗/poet.song.229000.json','["直廬峻在九霄高，雨露恩光切仰膏。", "夜炬恩濃超賜錦，春船思澀怯提鼇。", "日磚有影占花隠，風鐸無聲引索綯。", "昭代崇儒逢聖主，小臣待詔愧王褒。"]'),
('c0f908cc-fdc7-4330-aa63-94886b31b704','恭和御製賜進士韻','馬廷鸞','宋','宋诗','song-poetry','','[]','熈朝道化聿求成，龍衮天臨策俊英。',64,'全唐诗/poet.song.229000.json','["熈朝道化聿求成，龍衮天臨策俊英。", "清問詳延敷廼聽，嘉猶入告底于行。", "堯章焜燿欣承渥，湯訓丁寧戒近名。", "聖主得賢功烈盛，小臣稽首願升平。"]'),
('6ea11a9c-35c2-4834-a02a-c5fb8b9ff573','御書道山堂次林竹溪韻','馬廷鸞','宋','宋诗','song-poetry','','[]','芒玉平雲璽印紅，洛龜圖畫五三隆。',64,'全唐诗/poet.song.229000.json','["芒玉平雲璽印紅，洛龜圖畫五三隆。", "壁奎星聚來時彥，河漢天垂仰化工。", "文治正應淳化似，恩華重與紹興同。", "何須飛白人人賜，始悟君王欲教忠。"]'),
('a799a0ca-3fd5-4014-b177-7a76af5c4a6c','十月二十日客有言儒學事感而有賦','馬廷鸞','宋','宋诗','song-poetry','','[]','大中之後建隆前，魚爛瓜分且百年。',64,'全唐诗/poet.song.229000.json','["大中之後建隆前，魚爛瓜分且百年。", "地闢天開崇帝學，河輝斗燦動星躔。", "千齡必反人弘道，一念潛通聖即天。", "歎息斯文今有幸，昭昭奎運豈徒然。"]'),
('a36c36bc-dde7-4177-b48d-c82ecadc89ec','和南塘叔賞芙蓉韻','馬廷鸞','宋','宋诗','song-poetry','','[]','自携敗冊小窗開，三十頭顱四十來。',64,'全唐诗/poet.song.229000.json','["自携敗冊小窗開，三十頭顱四十來。", "閒日詩書真足味，薰天富貴只飛灰。", "憐渠每吸醋三斗，輸我清餘水一盃。", "何似山翁醉花下，安排籩豆洗樽罍。"]'),
('23bf4cfd-3957-4c95-b7dc-b635370976aa','雙鶴','馬廷鸞','宋','宋诗','song-poetry','','[]','荒塘水竭只蹄涔，雙鶴翩然啄午陰。',64,'全唐诗/poet.song.229000.json','["荒塘水竭只蹄涔，雙鶴翩然啄午陰。", "此縱有魚應渴死，不濡其咮漫窺臨。", "病鴟尚畏泥坑辱，宿鳥常虞矰繳侵。", "何似舂鋤甘寂寞，一灘藻荇立清深。"]'),
('387f742c-0a8d-42f8-afd1-1641a78a614c','送建康知錄操襟兄','馬廷鸞','宋','宋诗','song-poetry','','[]','虎韉尚落諸賢後，鴈塔誰知幾榜前。',64,'全唐诗/poet.song.229000.json','["虎韉尚落諸賢後，鴈塔誰知幾榜前。", "儘向心田寬地步，却將官職信天緣。", "難忘舊日鍾山閣，易趁東風上水船。", "王謝諸人英烈在，問今何策可籌邊。"]'),
('778c7586-9a28-4a7a-b2d7-c00d862e1555','送湯東澗出守南劍州  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','掉頭不肯住清都，勇趁秋風乞左符。',64,'全唐诗/poet.song.229000.json','["掉頭不肯住清都，勇趁秋風乞左符。", "大論崢嶸聳廊廟，雅懷磊落勝江湖。", "丹心豈不戀明主，清節還能立懦夫。", "正是商山訪鴻鵠，歸來羽翼莫踟躕。"]'),
('7250e9bb-8ccc-4e47-8827-38e56ab638c1','送湯東澗出守南劍州  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','七聚名藩亦甚都，龍津劍氣正扶輿。',64,'全唐诗/poet.song.229000.json','["七聚名藩亦甚都，龍津劍氣正扶輿。", "斯文孰是南夫子，此地重逢行秘書。", "忠愛平生在宗社，歎愁肯使到田閭。", "黄花粲粲牽歸興，歲晚江空一悵如。"]'),
('c2543970-ebbf-4667-8ef5-5b4028c9690f','秘省和劉左司韻','馬廷鸞','宋','宋诗','song-poetry','','[]','三年三揖壁奎星，當日曾登著作庭。',64,'全唐诗/poet.song.229000.json','["三年三揖壁奎星，當日曾登著作庭。", "大雅重逢君子聚，斯文還屬聖人興。", "倚天延閣緣雲上，拔地方壺歷級升。", "自別青藜仙分隔，借書獨對短檠燈。"]'),
('7e7b7216-e78d-4995-aad1-f2289400138e','病中修實錄','馬廷鸞','宋','宋诗','song-poetry','','[]','明聖當陽四十春，十年供奉感孤臣。',64,'全唐诗/poet.song.229000.json','["明聖當陽四十春，十年供奉感孤臣。", "雲龍幄幙天容邇，河漢篇章帝墨新。", "正始遺音危絕縷，貞元舊曲慟沾巾。", "焚膏痛記烏號旦，目斷稽山欲叫旻。"]'),
('d5f053f6-423b-4c07-9bb3-f82edbcc15fc','秋雨歎','馬廷鸞','宋','宋诗','song-poetry','','[]','夜夜黄昏雨打窗，愁霖久矣晦明陽。',64,'全唐诗/poet.song.229000.json','["夜夜黄昏雨打窗，愁霖久矣晦明陽。", "天公一怒四山黑，田父三吁百畝黄。", "禾黍油油生有耳，芭蕉點點斷無腸。", "病身更與兒俱懶，牆角全拋風露凉。"]'),
('670d3dbe-2e45-4b41-93d7-e5fe8ff6c09a','久雨遣餉王新班','馬廷鸞','宋','宋诗','song-poetry','','[]','舍南舍北水漫漫，乍霽仍陰暖復寒。',64,'全唐诗/poet.song.229000.json','["舍南舍北水漫漫，乍霽仍陰暖復寒。", "石補色天原有漏，泥污后土不曾乾。", "龍蛇起陸生光怪，鸞鳳翀霄怯羽翰。", "聊復盤餐餉桑戶，可能藜杖過蘇端。"]'),
('94b61e1c-7a3e-4f5a-a07c-4292a54d1590','十月望日泛舟鵝塘感坡翁後赤壁賦有作','馬廷鸞','宋','宋诗','song-poetry','','[]','浮浮短艇水風微，一枕清溪遶曲崎。',64,'全唐诗/poet.song.229000.json','["浮浮短艇水風微，一枕清溪遶曲崎。", "篷底鎔金斜日碎，天邊散綺暮霞飛。", "霜凝水落黄泥坂，月小山高赤壁磯。", "等是初冬一風景，感今懷昔自歔欷。"]'),
('b496d152-a78c-4d7b-85f7-167ba51fc9b3','二兒就試','馬廷鸞','宋','宋诗','song-poetry','','[]','老病吾今業已衰，已還魏笏尚支頤。',64,'全唐诗/poet.song.229000.json','["老病吾今業已衰，已還魏笏尚支頤。", "祝兒指日傳金榜，懷我當年別玉墀。", "殿陛詳延方籲俊，江湖空曠劇憂時。", "此行蹇諤論邦國，莫爲區區杏苑詩。"]'),
('b33bc345-8f53-4ee0-86af-e582d2ba7035','後中秋','馬廷鸞','宋','宋诗','song-poetry','','[]','金風吹徹玉簫寒，志士悲秋思萬端。',64,'全唐诗/poet.song.229000.json','["金風吹徹玉簫寒，志士悲秋思萬端。", "千古凄凉更餘閏，百年圓缺又重看。", "清輝照膽渾無寐，蒼昊催人自鮮歡。", "斗酒屬公今夜看，只虧些子莫長嘆。"]'),
('21c2da58-0b14-4684-ac02-7728d91ce5d5','次吳園親友韻','馬廷鸞','宋','宋诗','song-poetry','','[]','乞得危身百尺竿，冥心晦息掩柴關。',64,'全唐诗/poet.song.229000.json','["乞得危身百尺竿，冥心晦息掩柴關。", "自尋別墅開荒徑，忽見高軒厭轡環。", "海宇泬寥黄鵠舉，風濤浩蕩白鷗閒。", "劍花落盡長堤圮，歎息英雄隠此山。"]'),
('72c35a8f-3fc1-483e-bc20-0e92bef1aafa','癸酉春暮鍾信甫寄詩次其韻  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','深閉柴門水竹村，是非榮辱總忘言。',64,'全唐诗/poet.song.229000.json','["深閉柴門水竹村，是非榮辱總忘言。", "舍生只懼本心失，犯患誰知尊足存。", "居士病來惟卧室，翟公客去莫書門。", "人心日月無今古，世道何曾頃刻昏。"]'),
('15132512-30f5-4a0a-bf3f-955ae26ea68a','癸酉春暮鍾信甫寄詩次其韻  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','精誠可使嶽雲開，濁世狂瀾挽不回。',64,'全唐诗/poet.song.229000.json','["精誠可使嶽雲開，濁世狂瀾挽不回。", "蒼狗白衣從物變，青山流水喚人來。", "交遊莫作宣明面，氣燄終成內史灰。", "我有長波一歸艇，枕書春睡興悠哉。"]'),
('9b86ede4-049d-4803-8447-a9d9b225aef7','次胡玉叟韻','馬廷鸞','宋','宋诗','song-poetry','','[]','莫學前人索送詩，我無姱節可提撕。',64,'全唐诗/poet.song.229000.json','["莫學前人索送詩，我無姱節可提撕。", "忍聽世上新翻曲，堪笑山中老古錐。", "人境炎凉過駒隙，天邊日夜走蟾規。", "窮閻又度純坤月，誰識初陽變一奇。"]'),
('eca6ccfe-d8bc-46e0-9826-6806225bbaab','和許伯脩韻','馬廷鸞','宋','宋诗','song-poetry','','[]','秋風孤憤只心知，接得詩筒爲色怡。',64,'全唐诗/poet.song.229000.json','["秋風孤憤只心知，接得詩筒爲色怡。", "句眼獨參成佛後，吟肩聳徹欲仙時。", "俗衰競覓胡奴飽，節在何妨臣朔饑。", "此話只今誰舉似，趨時言語正如巵。"]'),
('71072629-79dd-4d89-bbeb-f39029ee0b05','夜病','馬廷鸞','宋','宋诗','song-poetry','','[]','幻身危抱十年病，青眼俄成一旦昏。',64,'全唐诗/poet.song.229000.json','["幻身危抱十年病，青眼俄成一旦昏。", "夜席何常卧尊者，晨炊不擬飯王孫。", "蝸涎有幾春潮湧，鷄唱無憑曉日暾。", "惟有阿樞癡不去，幾回驚起問家尊。"]'),
('39c4d05a-31d0-48cf-a8be-59324ccd3d34','游荷溪西禪寺','馬廷鸞','宋','宋诗','song-poetry','','[]','髣髴招提寄遠村，緇郎草草佛燈昏。',64,'全唐诗/poet.song.229000.json','["髣髴招提寄遠村，緇郎草草佛燈昏。", "水將綠遶縈如带，山送青來列在門。", "句裏風騷耆舊遠，胸中丘壑典刑存。", "滿懷孤憤幾株石，欲起當年兩達尊。"]'),
('bc32b65d-692d-43b4-aa93-1ffe51925be2','三月初四夜宿僧廬','馬廷鸞','宋','宋诗','song-poetry','','[]','風雨蕭蕭夜未央，呼童襥被宿僧房。',64,'全唐诗/poet.song.229000.json','["風雨蕭蕭夜未央，呼童襥被宿僧房。", "無腸可斷啼鵑苦，有喙皆鳴吠蛤忙。", "七歲遺孤今老大，百年遠忌足悲傷。", "司晨喚起窗全曙，歸命清都炷瓣香。"]'),
('8cd163f1-72d9-4b6c-beac-eef83eb1912a','次費潔堂韻','馬廷鸞','宋','宋诗','song-poetry','','[]','誰翻溟渤倒天瓢，大地山河等呴漂。',64,'全唐诗/poet.song.229000.json','["誰翻溟渤倒天瓢，大地山河等呴漂。", "九陌揚塵京路暗，一聲鳴鵙楚魂招。", "歸心猛折湖邊柳，活計頻尋江上苗。", "回首神皋雙淚落，孤烟斜日短長橋。"]'),
('77470b36-e88f-427f-98ba-a2757c669b62','三月初五日先秘閣忌','馬廷鸞','宋','宋诗','song-poetry','','[]','鳥啼花落暮春天，一遇斯晨一泫然。',64,'全唐诗/poet.song.229000.json','["鳥啼花落暮春天，一遇斯晨一泫然。", "舊業豈無書可讀，遺言猶有石堪傳。", "孝思不礙飛遐想，忠憤何由竭報緣。", "廟社已同纓紱盡，尊堯千古憶陳編。"]'),
('444ec352-f71d-433e-ac3f-f461abc4f247','秋謁屺瞻墓','馬廷鸞','宋','宋诗','song-poetry','','[]','了知五十六年非，何處空山叫阿㜷。',64,'全唐诗/poet.song.229000.json','["了知五十六年非，何處空山叫阿㜷。", "斗酒隻雞雙淚落，荒林宿莽九原悲。", "黄花委地傷徂歲，青笋迎船憶舊時。", "廬下夜來霜屨冷，襪材持送懶殘師。"]'),
('68319911-ce60-4160-be19-c81cc306dbba','次韻李竹塢懷古','馬廷鸞','宋','宋诗','song-poetry','','[]','寶籙炎圖未百年，神徂聖伏一凄然。',64,'全唐诗/poet.song.229000.json','["寶籙炎圖未百年，神徂聖伏一凄然。", "徵先生起淹中禮，與老人期圯上編。", "柯爛不驚人換世，瓢空獨樂士希賢。", "昌黎憤世猶稽古，難拗何妨只自鞭。"]'),
('78c79981-418a-4f9e-bbc3-b1229ce2730f','拜屺瞻墓有感','馬廷鸞','宋','宋诗','song-poetry','','[]','我走金塘十五年，新年六十意凄然。',64,'全唐诗/poet.song.229000.json','["我走金塘十五年，新年六十意凄然。", "扶藜策蹇趨廬下，洗盞將雛拜影前。", "蠹化不妨松飲露，鳳棲猶擬柏參天。", "微吟緩步滄江晚，一抹青山落照邊。"]'),
('16d7c91f-9597-4f04-b21a-c252eafc9479','我輩小年端午給假蒲酒奉親之外日遊村田間致足樂也今老矣竹塢老友近館授徒逢此小熟奉一酌道舊且有感於并汾舊事云','馬廷鸞','宋','宋诗','song-poetry','','[]','香羅細葛端陽節，絳帳青衿少小時。',64,'全唐诗/poet.song.229000.json','["香羅細葛端陽節，絳帳青衿少小時。", "曩以彈丸俘晉孽，今於筒黍弔湘纍。", "千年感舊慵開卷，一酌銷憂强把巵。", "蒲酒少年供母後，村南村北恣遊嬉。"]'),
('3de77f8f-6399-4de3-8038-317fa535b24c','五月二十夜記夢','馬廷鸞','宋','宋诗','song-poetry','','[]','生來不作浮名計，老去翻驚幽夢奇。',64,'全唐诗/poet.song.229000.json','["生來不作浮名計，老去翻驚幽夢奇。", "宮黍不知哀九廟，廷麻猶聽拜三師。", "睡昏擬草榻前疏，寤辟疑催牖下期。", "更把在前榮路看，癡翁說夢儘添癡。"]'),
('07d21230-8d47-46ce-a3c1-c4f57d2f2a5c','德壽宮古松太上愛之嘗持御香釃酒祠土神以祈屏蟊賊云時紹興壬午思陵馘亮之歲也于今百二十年矣僕生六十年後而十月八日又思陵上仙之晨感而有賦  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','六龍親御奠神州，甲子如今甫再周。',64,'全唐诗/poet.song.229000.json','["六龍親御奠神州，甲子如今甫再周。", "百世尚瞻虞帝祀，五傳遽抱杞天憂。", "臣民莫廢瓜華敬，今古長悲禾黍秋。", "歎息餘生孤露甚，門弧弓棘總成愁。"]'),
('06e5d818-ff16-4351-8d17-86e888722db8','德壽宮古松太上愛之嘗持御香釃酒祠土神以祈屏蟊賊云時紹興壬午思陵馘亮之歲也于今百二十年矣僕生六十年後而十月八日又思陵上仙之晨感而有賦  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','南來天馬總辛勤，內禪經今歷再壬。',64,'全唐诗/poet.song.229000.json','["南來天馬總辛勤，內禪經今歷再壬。", "復漢赤符還舊宇，法堯黄屋本非心。", "思成門外衣冠盡，德壽宮前茨棘深。", "嘆息餘生孤露甚，匪莪彼黍涕淋淫。"]'),
('7cb84c43-93ce-4ee4-8437-960e7ebec3fc','又題德壽宮古松','馬廷鸞','宋','宋诗','song-poetry','','[]','千歲堂堂十八公，雨膏露沐貯清風。',64,'全唐诗/poet.song.229000.json','["千歲堂堂十八公，雨膏露沐貯清風。", "龍吟高嘯長身客，蠹化低摧禿鬢翁。", "誰謂蚍蜉能撼樹，不堪蟊賊欲蟠空。", "御香灑酒荒荆棘，腸斷孤臣泣壽宮。"]'),
('76e2d9e0-f3f2-4dfb-a6a3-48d3e2896c95','與三兒涉穰田渡車中讀朱忠靖中興事實有感','馬廷鸞','宋','宋诗','song-poetry','','[]','騷情長愛重陽近，客路歸遲夕照西。',64,'全唐诗/poet.song.229000.json','["騷情長愛重陽近，客路歸遲夕照西。", "舉目山河秋寂寂，滿城風雨晚凄凄。", "老思舊隠盟鷗社，寒涉深流信馬蹄。", "憑軾試看炎紹錄，空嗟語石與天齊。"]'),
('ac835f1c-aa0a-4153-a551-7b96ca5f2692','十月八日有感','馬廷鸞','宋','宋诗','song-poetry','','[]','日來天馬憤揮戈，直爲當年斧畫河。',64,'全唐诗/poet.song.229000.json','["日來天馬憤揮戈，直爲當年斧畫河。", "萬炬蓮燈照鯨海，一杯麥飯渡滹沱。", "思陵錄上哀榮極，德壽宮前耆舊多。", "忍把原碑參葉記，江頭石刻懶摩挲。"]'),
('8b82d040-f658-4af9-8402-16cedce24c66','十月二十日有感','馬廷鸞','宋','宋诗','song-poetry','','[]','精一危微尚贅辭，只須三語好爲之。',64,'全唐诗/poet.song.229000.json','["精一危微尚贅辭，只須三語好爲之。", "風清月白此良夜，雪暗雲昏彼一時。", "玉斧照廊開嗣聖，金縢納冊付宮姬。", "思成門外荒荆棘，惆悵何人失令規。"]'),
('81c0414c-35d5-4330-8f2e-0c1c31f1b2e7','外孫朱饒歸吳興','馬廷鸞','宋','宋诗','song-poetry','','[]','出門一別行千里，閉戶歸休讀五車。',64,'全唐诗/poet.song.229000.json','["出門一別行千里，閉戶歸休讀五車。", "天路塵冥車服驥，世科墨濕字翻鴉。", "繡綳尚憶春暉報，雲舍無令暮靄遮。", "晚歲飾巾吾待盡，高空摩翮汝橫斜。"]'),
('c8798eab-c63c-4459-9451-0216a22b69ce','七夕雨中飲客','馬廷鸞','宋','宋诗','song-poetry','','[]','羈懷病思不禁秋，又報西風大火流。',64,'全唐诗/poet.song.229000.json','["羈懷病思不禁秋，又報西風大火流。", "梧葉未凋高樹翠，薇花不厭小山幽。", "燕鴻來往書生老，禾黍高低故國愁。", "志士悲秋寧復爾，樓頭罇酒漫銷憂。"]'),
('21d1e0c8-9146-4a15-8415-3482ead0d275','十月二十日感舊','馬廷鸞','宋','宋诗','song-poetry','','[]','九衢燈火閙嘈嘈，斗柄低昂列宿高。',64,'全唐诗/poet.song.229000.json','["九衢燈火閙嘈嘈，斗柄低昂列宿高。", "漏箭聲沉金鎖徹，紗籠影避貴官豪。", "烏號望帝窮霄壤，魚爛遺民沸海濤。", "三百五年風雪夕，孤臣白首卧林臯。"]'),
('f315391e-67c5-42aa-9a87-558593aff03b','正月四日','馬廷鸞','宋','宋诗','song-poetry','','[]','皇厭紛拏五季餘，萬兵朝遣暮還都。',64,'全唐诗/poet.song.229000.json','["皇厭紛拏五季餘，萬兵朝遣暮還都。", "虎頭預卜清明旦，鼇足重開混一區。", "天下歸仁吾有道，日中爲市爾無虞。", "孤臣白首懷佳節，奠桂焚蘭淚與俱。"]'),
('7e54a467-02ba-4b78-a418-1e9e465049ac','次張龍山韻反騷','馬廷鸞','宋','宋诗','song-poetry','','[]','雪柏霜松自有神，衝風槁葉故難禁。',64,'全唐诗/poet.song.229000.json','["雪柏霜松自有神，衝風槁葉故難禁。", "雲間已閟貞元曲，歲晚誰聞正始音。", "天地有窮歸幻化，聖賢無命亦山林。", "愁來又把離騷讀，長夜悠悠慷慨吟。"]'),
('a943c03d-1e20-4290-8fcf-826f9b33757e','冬至','馬廷鸞','宋','宋诗','song-poetry','','[]','山寒律琯又飛灰，萬壑松風冬起雷。',64,'全唐诗/poet.song.229000.json','["山寒律琯又飛灰，萬壑松風冬起雷。", "風景不殊雲黯淡，雪霜初霽日徘徊。", "無人獻襪拋塵屨，有客傳觴醱凍醅。", "天地不教陽德盡，韋編曾叩伏羲來。"]'),
('74929c8b-39c3-4f5a-a4e2-8aa021c863cd','次韻潔堂別歲','馬廷鸞','宋','宋诗','song-poetry','','[]','月底南枝插屋椽，無人共賞祇凋年。',64,'全唐诗/poet.song.229000.json','["月底南枝插屋椽，無人共賞祇凋年。", "我慙王氏青氈舊，君效坡翁白鶴遷。", "小隠未荒存菊徑，獨清難涴出山泉。", "歸時好待春江漲，穩泛輕舟一葉蓮。"]'),
('c84f448d-b1c5-4bc8-a533-ea2c4dfe6059','用潔堂韻贈徐清溪禱雨','馬廷鸞','宋','宋诗','song-poetry','','[]','怒起乖龍變蟄雷，神翁此手更神哉。',64,'全唐诗/poet.song.229000.json','["怒起乖龍變蟄雷，神翁此手更神哉。", "老天於物何嘗病，舊雨如人自不來。", "彼稷之苗餘滯穗，我行其野絕纖埃。", "方平狡獪猶餘事，聊慰饑農取大咍。"]'),
('35b8172d-7400-40d4-a0ba-040953d8ed2b','得熊靜程主簿書且誨以二父庚甲用舊韻奉寄','馬廷鸞','宋','宋诗','song-poetry','','[]','負米無親不忍嘗，誰爲故老在鄰牆。',64,'全唐诗/poet.song.229000.json','["負米無親不忍嘗，誰爲故老在鄰牆。", "百年寧復知耆舊，六甲猶能記歲陽。", "襟佩書生聯講席，鼓旂騷將角名場。", "斯文未敢荒先緒，白首遺孤靦最良。"]'),
('5ebfd136-8ece-4401-89a1-d94dc5d0e141','苦雨','馬廷鸞','宋','宋诗','song-poetry','','[]','倦夜拋書病不禁，投床無寐雨涔涔。',64,'全唐诗/poet.song.229000.json','["倦夜拋書病不禁，投床無寐雨涔涔。", "長潸舊國山河淚，細滴孤臣禾黍心。", "狂象蹋池喧濘淖，饑鴉謀稻愴淋淫。", "天公老手須斟酌，次第龍分正望霖。"]'),
('5cfe7f63-9940-42aa-9e0f-1901fc2dc98d','謝毛子文見壽','馬廷鸞','宋','宋诗','song-poetry','','[]','編排老朽我爲魁，綠鬢朱顔可得迴。',64,'全唐诗/poet.song.229000.json','["編排老朽我爲魁，綠鬢朱顔可得迴。", "周雅輟吟悲顧復，楚騷長嘆誦恢台。", "鴻飛滅沒孤身在，燕逐炎凉幾客來。", "苜宿黎祁湯餠供，一澆眊矂强持盃。"]'),
('6dbadd15-ca9d-48a9-b2c5-f667d8b19884','次韻朱婿實甫見壽','馬廷鸞','宋','宋诗','song-poetry','','[]','南華參透解天刑，夜夜心香禱玉衡。',64,'全唐诗/poet.song.229000.json','["南華參透解天刑，夜夜心香禱玉衡。", "紫蓋十年違帝闕，青山九瑣夢雲京。", "緇郎寧忍忘天祐，白傅空令羨普明。", "人以壽歡臣以戚，孤懷借酒爲澆平。"]'),
('df931476-4462-451f-8549-29e7379606a5','觀魚車渡溪','馬廷鸞','宋','宋诗','song-poetry','','[]','如带溪流拍兩崖，投泥賈客競喧豗。',64,'全唐诗/poet.song.229000.json','["如带溪流拍兩崖，投泥賈客競喧豗。", "隻輪自力掀諸淖，斷岸先登陟彼嵬。", "江水斗升寧汝活，岸旁車馬爲渠來。", "老夫自取鯨鯢戮，掩鼻沙丘未足哀。"]'),
('73bc4698-d717-44c3-8556-e7eb2ca922f4','北平家傳成  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','三百年間事屢危，降之人傑豈中衰。',64,'全唐诗/poet.song.229000.json','["三百年間事屢危，降之人傑豈中衰。", "巍巍祖烈將千歲，赫赫元功彼一時。", "起義堂碑雲漢麗，凌煙閣像日星垂。", "藏山自纂前朝史，付與雲礽百代知。"]'),
('583af421-fff2-45d2-a9b1-11f28a3e2f9a','北平家傳成  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','選將初年起范陽，和戎晚節誤平凉。',64,'全唐诗/poet.song.229000.json','["選將初年起范陽，和戎晚節誤平凉。", "大功宜受春秋責，盛毀何能日月傷。", "文士談兵多謬誤，蘭臺作史漫裁量。", "折衷自有成書在，公論從知千歲長。"]'),
('92b7dfb3-4c61-4a5d-b74f-e447fce7e55f','北平家傳成  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','彼美人兮無古今，挑燈勘史夜沉沉。',64,'全唐诗/poet.song.229000.json','["彼美人兮無古今，挑燈勘史夜沉沉。", "昌唐無復浯溪頌，哀郢常多楚澤吟。", "麟獲自傷王迹息，鵑啼誰念帝魂深。", "祇今莫唱貞元曲，但憶曾聞正始音。"]'),
('135fdf44-b6a7-4085-bbb9-eee78f57aaa6','餞朱婿','馬廷鸞','宋','宋诗','song-poetry','','[]','哀郢那能拾穗歌，卧陶誰復杖藜過。',64,'全唐诗/poet.song.229000.json','["哀郢那能拾穗歌，卧陶誰復杖藜過。", "白頭老我已如此，青眼看君餘幾何。", "風雨夜吟蛩滿砌，雲山寒影鴈橫坡。", "暮年親友臨分苦，小酌村醪借臉酡。"]'),
('ab0c83cd-c45f-43e3-b9f4-25f46d0dbeeb','屺瞻拜墓  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','老誦劬勞易感傷，一年一度拜金塘。',64,'全唐诗/poet.song.229000.json','["老誦劬勞易感傷，一年一度拜金塘。", "食蓮正憶慈顔遠，毀璧新增苦淚滂。", "松蠹穹林成禿帚，草荒高冢蔽幽篁。", "山哀浦思愁余極，陣陣溪風葉葉黄。"]'),
('5f2a2b76-e756-4d3a-9d41-a0e46817a03d','屺瞻拜墓  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','假汝稀年只八年，爭教老境不凄然。',64,'全唐诗/poet.song.229000.json','["假汝稀年只八年，爭教老境不凄然。", "青山慈母已黄壤，綠鬢中男餘白顛。", "天外羣鴻隨滅沒，雲間孤鶴自蹁躚。", "共携斗酒澆墳土，衰淚何由滴到泉。"]'),
('fdd5fbaa-aa6d-4a18-aa5e-88d9ea3c5422','宿屺瞻夜賦  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','咿軋籃輿度曉岑，撫今懷昔淚淋淫。',64,'全唐诗/poet.song.229000.json','["咿軋籃輿度曉岑，撫今懷昔淚淋淫。", "蓼莪老去仍追誦，常棣新來又廢吟。", "有恨臺瓜隨蔓盡，無情澗藻與波沉。", "僧窗月苦夜無寐，莫詠兒寒動母心。"]'),
('13270b96-b2e3-440e-8121-69d5c2b7e06f','宿屺瞻夜賦  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','六十年前我已孤，嬰兒抱母泣呱呱。',64,'全唐诗/poet.song.229000.json','["六十年前我已孤，嬰兒抱母泣呱呱。", "昊天罔極幽明隔，良月就盈今昔殊。", "雲塞斷行悲獨鴈，風林反哺感羣烏。", "澄江只似洹河水，一碧寒泓照白鬚。"]'),
('985ec219-8e4a-41a1-aaf2-8ad9f41eadc4','過屺瞻墓','馬廷鸞','宋','宋诗','song-poetry','','[]','白髮蒼顔六十三，年年拜母憶中男。',64,'全唐诗/poet.song.229000.json','["白髮蒼顔六十三，年年拜母憶中男。", "雲歸別岫山呈碧，江抱寒汀水染藍。", "草報春暉天罔極，樹隨人老我何堪。", "薦餘煮茗清泉供，淚泫餘潸酒不酣。"]'),
('49296bb5-e25e-40bd-b181-5a44aad1cf13','屺瞻道中  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','蓐食需明出遠村，筍輿咿軋睡昏昏。',64,'全唐诗/poet.song.229000.json','["蓐食需明出遠村，筍輿咿軋睡昏昏。", "禾麻豐歲雲連畝，風露高秋水落痕。", "清曉跨鞍兒從父，當年戲綵母憐孫。", "白頭老病松楸隔，一望雲飛一斷魂。"]'),
('cb481f04-3be0-4ab6-8b59-2a735e492952','屺瞻道中  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','波粼粼處淺溪沙，漁屋低迷舴艋家。',64,'全唐诗/poet.song.229000.json','["波粼粼處淺溪沙，漁屋低迷舴艋家。", "地老天荒原野靜，江空歲晚水雲賒。", "淤泥日課黄金粟，清泚時吹白浪花。", "漫喜時豐阡陌裏，豚蹄行矣祝汙邪。"]'),
('9b2afdba-56a6-48b3-bc10-515200bf8637','山中對紫薇花書感','馬廷鸞','宋','宋诗','song-poetry','','[]','輕盈插向膽瓶中，看到山林禁籞同。',64,'全唐诗/poet.song.229000.json','["輕盈插向膽瓶中，看到山林禁籞同。", "閣下天葩秋月黯，樓頭奎畫曉雲空。", "高攀玉樹扶斑白，靜掃蒼苔拾墮紅。", "三十年前天上夢，老來無淚灑西風。"]'),
('9e21b235-29ef-4761-91c6-f24c1600bbab','次許表兄韻','馬廷鸞','宋','宋诗','song-poetry','','[]','物換星移一慨然，天荒地老斷鼇前。',64,'全唐诗/poet.song.229000.json','["物換星移一慨然，天荒地老斷鼇前。", "豈無志士王官谷，亦有飛仙太華巔。", "我若加三逢本命，君今過一漸稀年。", "兩人中表俱頭白，蜀餽纔堪幾幅箋。"]'),
('f66ea6c5-c8cd-4a9d-beb2-435e7b5dcc9e','次龍山韻  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','新來霄漢冥鴻客，舊日風雲振鷺行。',64,'全唐诗/poet.song.229000.json','["新來霄漢冥鴻客，舊日風雲振鷺行。", "脫下戲衫優便散，驚回客枕夢何長。", "莫將吳蜀分岐路，政把乾坤作醉鄉。", "惟有葵傾心不死，清魂幾到殿中央。"]'),
('019d2c7e-0f7f-44c6-9527-cbaad2d64fac','次龍山韻  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','窗間莫問喚祁嘉，望斷宗周黍稷華。',64,'全唐诗/poet.song.229000.json','["窗間莫問喚祁嘉，望斷宗周黍稷華。", "斗帳高眠聊避客，深衣暫到漫爲家。", "我懷荒草同元亮，君悼空絃謝伯牙。", "老矣悲歡總無奈，仙書頻讀覽荒遐。"]'),
('364d2caa-ded2-4a6e-890b-cea80fc94330','拜餞修史大著吏部使浙西','馬廷鸞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','高懷豈必薄崑崙，攬轡登車意自欣。',64,'全唐诗/poet.song.229000.json','["高懷豈必薄崑崙，攬轡登車意自欣。", "周太史官慚著我，漢常平使喜推君。", "廬山向已高千仞，野水從今寬一分。", "□□鷫鸘裘供□，□□□□更紛紛。"]'),
('19deba46-b61f-4dd6-bccf-c8fa123874c0','仰和皇太子殿下明禋慶成詩韻  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','聖主精禋格，明廷對月深。',24,'全唐诗/poet.song.229000.json','["聖主精禋格，明廷對月深。", "元良贊宸極，盛德享天心。"]'),
('1486117c-a338-481c-a627-88de24a9e40a','仰和皇太子殿下明禋慶成詩韻  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','夕宿猶疎雨，昕朝覩大明。',24,'全唐诗/poet.song.229000.json','["夕宿猶疎雨，昕朝覩大明。", "重光符景貺，熈事慶昇平。"]'),
('068dfafb-28c4-4579-92c9-231c226c2f5c','仰和皇太子殿下明禋慶成詩韻  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','鳴鑾回紫禁，步玉捧宸旒。',24,'全唐诗/poet.song.229000.json','["鳴鑾回紫禁，步玉捧宸旒。", "肆眚遵虞典，歡傳十二州。"]'),
('af5cf6d4-eca1-413b-9646-bf507848b1ff','用清秋鶴髮翁韻賦小書招潔堂  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','幽居抱孤明，懷古思舊京。',24,'全唐诗/poet.song.229000.json','["幽居抱孤明，懷古思舊京。", "渴望寶連山，老桂不勝清。"]'),
('8b8c5b64-b13c-404d-95dc-8a41b2ce630b','用清秋鶴髮翁韻賦小書招潔堂  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','月照窗炯炯，蟲鳴室幽幽。',24,'全唐诗/poet.song.229000.json','["月照窗炯炯，蟲鳴室幽幽。", "策杖柴門曉，菰蒲半沼秋。"]'),
('4ab885f6-ce7c-4178-bc61-5f9090069def','用清秋鶴髮翁韻賦小書招潔堂  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','火中寒暑退，造物其猶醵。',24,'全唐诗/poet.song.229000.json','["火中寒暑退，造物其猶醵。", "老身不繭蠶，清夜獨警鶴。"]'),
('3f95ba8b-ebdd-448c-91b8-c0758ad7c49b','用清秋鶴髮翁韻賦小書招潔堂  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','老蟾明孤心，凉飈蘇病骨。',24,'全唐诗/poet.song.229000.json','["老蟾明孤心，凉飈蘇病骨。", "保此中夜存，微陽有毫髮。"]'),
('2db3bc1b-4b2c-4416-b78b-920e9893765f','用清秋鶴髮翁韻賦小書招潔堂  其五','馬廷鸞','宋','宋诗','song-poetry','','[]','庭草無言綠，林花取意紅。',24,'全唐诗/poet.song.229000.json','["庭草無言綠，林花取意紅。", "因之酌茅柴，招喚西鄰翁。"]'),
('a28dc392-25ce-4936-9c22-8dc7995d8b46','和潔堂見壽十章  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','老色上尺宅，靈氣虧三田。',24,'全唐诗/poet.song.229000.json','["老色上尺宅，靈氣虧三田。", "懷我長房翁，授汝雞犬仙。"]'),
('e72685ec-2ac0-4b16-ad91-33c103e53624','和潔堂見壽十章  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','早知無廊廟，胡不素丘園。',24,'全唐诗/poet.song.229000.json','["早知無廊廟，胡不素丘園。", "揮手謝世氛，保此中夜存。"]'),
('3e98d03c-9ae9-405d-bd4e-be0e9b771ef0','和潔堂見壽十章  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','我生嘉定間，寶運稽炎隆。',24,'全唐诗/poet.song.229000.json','["我生嘉定間，寶運稽炎隆。", "當時貢珍祥，今日泣麟窮。"]'),
('5730c448-35da-4f24-a241-3b9581fe34db','和潔堂見壽十章  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','風雨傾燕巢，波濤漲鯨海。',24,'全唐诗/poet.song.229000.json','["風雨傾燕巢，波濤漲鯨海。", "茅簷得此生，其誰爲爾宰。"]'),
('a669f573-11bf-473c-8620-fa9e11c511bc','和潔堂見壽十章  其五','馬廷鸞','宋','宋诗','song-poetry','','[]','大冬嚴寒至，病骨裹粗纊。',24,'全唐诗/poet.song.229000.json','["大冬嚴寒至，病骨裹粗纊。", "羸然祝雞翁，不識山中相。"]'),
('c5f3b1ec-49e7-4a0a-8b38-c0489605175f','和潔堂見壽十章  其六','馬廷鸞','宋','宋诗','song-poetry','','[]','琅琅金薤篇，慰此暮年癯。',24,'全唐诗/poet.song.229000.json','["琅琅金薤篇，慰此暮年癯。", "誦我徵咎賦，誇君摘句圖。"]'),
('85af70c3-680f-448b-bb6b-15e737388449','和潔堂見壽十章  其七','馬廷鸞','宋','宋诗','song-poetry','','[]','喪亂屬何辜，訏訏者誰子。',24,'全唐诗/poet.song.229000.json','["喪亂屬何辜，訏訏者誰子。", "生來乏遠猷，死去憂良史。"]'),
('ba9cdcb2-ab44-4ba9-9160-5cd2ed8e1a19','和潔堂見壽十章  其八','馬廷鸞','宋','宋诗','song-poetry','','[]','道義挹親仁，詩書仰鄰富。',24,'全唐诗/poet.song.229000.json','["道義挹親仁，詩書仰鄰富。", "翠蓬羞排門，驪珠驚滿袖。"]'),
('831a3c8c-271c-4f3e-a0f3-813bc13d5c0d','和潔堂見壽十章  其九','馬廷鸞','宋','宋诗','song-poetry','','[]','山哀兮浦思，月諸兮日居。',24,'全唐诗/poet.song.229000.json','["山哀兮浦思，月諸兮日居。", "伊誰百歲期，遲汝十年書。"]'),
('e16f4f7b-8c13-4e09-a46a-e6ebad12912a','和潔堂見壽十章  其一○','馬廷鸞','宋','宋诗','song-poetry','','[]','祝公千齡壽，小我五月生。',24,'全唐诗/poet.song.229000.json','["祝公千齡壽，小我五月生。", "如何山林槁，得並江漢英。"]'),
