('9014e44b-8b02-44a5-b75e-668bb17b9363','題楊妃唾壺圖','馬廷鸞','宋','宋诗','song-poetry','','[]','三郎好女思傾國，一霎沉酣四海奔。',89,'全唐诗/poet.song.229000.json','["三郎好女思傾國，一霎沉酣四海奔。", "漢業巍巍英主事，內庭供奉孔家孫。", "漢武帝時執此物者侍中孔安國也，唐明皇時楊妃職之，漢唐之所以成敗歟？", "然而寵任中書宦官，又自漢始。", "此話甚長，小子識之。"]'),
('9a54f1be-2c40-4c11-b791-af58fa363065','九月十九夜紀夢','馬廷鸞','宋','宋诗','song-poetry','','[]','堪嗟劫運永嘉末，忽夢清風乾道初。',32,'全唐诗/poet.song.229000.json','["堪嗟劫運永嘉末，忽夢清風乾道初。", "二十年間閒處士，可能身世得同渠。"]'),
('5067453f-e024-477e-a45b-1ae553fa707c','十一月十二夜夢南冠舊友感泣有賦','馬廷鸞','宋','宋诗','song-poetry','','[]','麥秀漸漸禾黍新，清宵夢斷泣遺民。',32,'全唐诗/poet.song.229000.json','["麥秀漸漸禾黍新，清宵夢斷泣遺民。", "只憐肝腦輸宗社，不負當年第一人。"]'),
('415fc823-6dff-460c-b215-b3d8690ccdbd','題芳洲詩集  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','采采芹甘不自謀，慇懃直欲奉王羞。',32,'全唐诗/poet.song.229000.json','["采采芹甘不自謀，慇懃直欲奉王羞。", "可憐斜日三千字，曾獻當年十二旒。"]'),
('e5a495cd-2fde-4b8c-a428-07ac95076252','題芳洲詩集  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','虎踞已知王氣盡，鵑啼誰感帝魂哀。',32,'全唐诗/poet.song.229000.json','["虎踞已知王氣盡，鵑啼誰感帝魂哀。", "怪渠冊後詩情苦，曾到留都豐鎬來。"]'),
('995f86ba-bad8-41aa-867c-b22190a07a66','近聞在舊京賣縵笠子','馬廷鸞','宋','宋诗','song-poetry','','[]','蚤歲葫蘆依畫本，暮年臺笠養閒身。',32,'全唐诗/poet.song.229000.json','["蚤歲葫蘆依畫本，暮年臺笠養閒身。", "如今半幅謄麻紙，羞寄鑾坡舊主人。"]'),
('9f12ae6b-d852-4cf0-9c76-440d8382b6ba','甲子初冬宿直玉堂凄風小雨次日即承先帝晏駕之變距今二十年矣大忌前一日孤臣獨眠山庵景象正似當年挑燈危坐聞田家鼓笛之聲凄其有感二首  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','無限都人哭鼎龍，年多澤久似仁宗。',32,'全唐诗/poet.song.229000.json','["無限都人哭鼎龍，年多澤久似仁宗。", "愁來一樣黄昏雨，天上人間自不同。"]'),
('fb8925a9-ccd0-4524-83ef-db24a968b28a','甲子初冬宿直玉堂凄風小雨次日即承先帝晏駕之變距今二十年矣大忌前一日孤臣獨眠山庵景象正似當年挑燈危坐聞田家鼓笛之聲凄其有感二首  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','雲黯天低結暝陰，孤燈對影夜沉沉。',32,'全唐诗/poet.song.229000.json','["雲黯天低結暝陰，孤燈對影夜沉沉。", "可憐一曲村田樂，猶是堯民擊壤音。"]'),
('7a575132-6ec1-49cc-9f84-1a2464bfc68d','挽許秋浦  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','紛紛頂板盡圈紅，伯仲高鶱槐市風。',32,'全唐诗/poet.song.229000.json','["紛紛頂板盡圈紅，伯仲高鶱槐市風。", "一第不酬攀桂客，千年祇泣感麟翁。"]'),
('b97f41ea-4737-4ced-9956-f398d52de195','挽許秋浦  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','蒼顔白髮王官谷，綠幕黄簾六館生。',32,'全唐诗/poet.song.229000.json','["蒼顔白髮王官谷，綠幕黄簾六館生。", "閲世舊嗟身偃蹇，懷人新有淚縱橫。"]'),
('126d3fce-c2e3-43e8-8d6a-01b1c4420098','挽許秋浦  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','青門何在從瓜熟，玉水難忘對竹哦。',32,'全唐诗/poet.song.229000.json','["青門何在從瓜熟，玉水難忘對竹哦。", "政復安車裹輪好，情知老子不婆娑。"]'),
('784221fd-4537-4a86-8bae-3ab7b2450ef6','挽許秋浦  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','歌騷讀盡遠遊篇，淡日寒空引紼天。',32,'全唐诗/poet.song.229000.json','["歌騷讀盡遠遊篇，淡日寒空引紼天。", "遶浦黄花秋易老，晚香留付子孫賢。"]'),
('1a51e4b0-4d47-438c-9219-ab4ab3256836','挽張龍山  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','雄篇爛漫兔園冊，挺翮扶摇鵬背風。',32,'全唐诗/poet.song.229000.json','["雄篇爛漫兔園冊，挺翮扶摇鵬背風。", "揭日科名輕拾紫，粘天名姓捷圈紅。"]'),
('d7a097a7-f52b-450b-b14a-91386f074d72','挽張龍山  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','大雅林中集衆英，三長正合入承明。',32,'全唐诗/poet.song.229000.json','["大雅林中集衆英，三長正合入承明。", "汗青有日頭無白，家傳修來國史成。"]'),
('f41c7903-4407-4823-be4b-fd202169d398','挽張龍山  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','欽翹人物觀奇士，芳潤衣冠儼碩師。',32,'全唐诗/poet.song.229000.json','["欽翹人物觀奇士，芳潤衣冠儼碩師。", "槐柳門前氣成霧，清風茗碗只談詩。"]'),
('81471b23-2749-442b-a54f-5b492b971ee0','挽張龍山  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','諸公莫唱貞元曲，老子曾聞正始音。',32,'全唐诗/poet.song.229000.json','["諸公莫唱貞元曲，老子曾聞正始音。", "寂寞吳王堤上路，白楊花落晝多陰。"]'),
('2206eb62-51a1-457b-bf49-43c107e30fc1','挽李小溪  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','人是西京長者孫，橫秋一鶚早青雲。',32,'全唐诗/poet.song.229000.json','["人是西京長者孫，橫秋一鶚早青雲。", "假令折就天邊桂，竇十郎家不足云。"]'),
('72da64a2-6402-4b16-b465-ea3b414e5b89','挽李小溪  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','三十年間借一瓻，鵠袍門外欠相携。',32,'全唐诗/poet.song.229000.json','["三十年間借一瓻，鵠袍門外欠相携。", "降霜御史風稜惡，瞎眼春官日色迷。"]'),
('6ed23eb1-7739-46d2-a107-44c5dd262db5','挽李小溪  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','鬰鬰南坡一聚塵，荒園野草不成春。',32,'全唐诗/poet.song.229000.json','["鬰鬰南坡一聚塵，荒園野草不成春。", "家聲久矣非前日，宅相居然亦古人。"]'),
('c4aa8b6a-784f-43a3-a7c7-eb8e14e7b2e4','挽李小溪  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','仙李由來公與侯，宋唐相望盡名流。',32,'全唐诗/poet.song.229000.json','["仙李由來公與侯，宋唐相望盡名流。", "金鑾論事嗟無地，往遡天風記玉樓。"]'),
('5cd66cb6-285d-4373-93b7-262cce1e3fcb','題老學道院  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','天典民彜聖得知，斯文千歲以爲期。',32,'全唐诗/poet.song.229000.json','["天典民彜聖得知，斯文千歲以爲期。", "試看涑水三雍贊，何必蘭陵賦詭詩。"]'),
('21f23bd5-a688-4965-98dd-515ad0c6e2f8','題老學道院  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','瓜爛東陵老廢鋤，野民八十尚躭書。',32,'全唐诗/poet.song.229000.json','["瓜爛東陵老廢鋤，野民八十尚躭書。", "窗風文字翻葉葉，抱膝長吟一擁爐。"]'),
('8776bea1-c1ef-4b88-ac1e-d50dca99b297','題老學道院  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','白日臨晨老可娛，平生有味太玄𤕠。',32,'全唐诗/poet.song.229000.json','["白日臨晨老可娛，平生有味太玄𤕠。", "莫將華皓嗤童習，更採玄文扁此廬。"]'),
('9fbec100-fbfd-4bcf-8bd1-cdc14eec0659','題老學道院  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','繁筆泉石兩成癡，早學東家晚學西。',32,'全唐诗/poet.song.229000.json','["繁筆泉石兩成癡，早學東家晚學西。", "章甫峨峨寧汝誤，如今翻恨十年遲。"]'),
('0b72d736-d116-4cd8-9a83-a839df700d03','益國趙公生祠','馬廷鸞','宋','宋诗','song-poetry','','[]','康山之崇兮，公惠不窮兮。',53,'全唐诗/poet.song.229000.json','["康山之崇兮，公惠不窮兮。", "洎水之陽兮，公惠寖長兮。", "山浮清兮水涵暉，公有惠澤兮民有秉彜。", "堅珉深刻兮，來者永思。"]'),
('bd30530f-8d98-46df-8970-ff29d9aaf616','梓潼帝君祠','馬廷鸞','宋','宋诗','song-poetry','','[]','梁山劍閣橫岷嶓，梓潼七曲高嵯峨。',139,'全唐诗/poet.song.229000.json','["梁山劍閣橫岷嶓，梓潼七曲高嵯峨。", "真人初基斧畫河，靈君受職山之阿。", "丹碧岌嶪龍虎呵，拄天功業石可磨。", "江流滔滔東逝波，靈之來兮自江沱。", "結屋兮奉祠，釀桂兮羞芝。", "神格思兮士曰時，躍淵兮天飛。", "冠若箕兮劍拄頤，長策用兮奇謀施，敵北遁兮靈西歸。", "錦幡兮寶蓋，導霓旌兮駕玉螭。", "吾言非誇兮，神之聽之。"]'),
('f9495d96-4f60-4a06-b599-d1dc3ef54c98','饒娥廟祀神歌  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','日吉兮辰良，芳菲菲兮滿堂。',119,'全唐诗/poet.song.229000.json','["日吉兮辰良，芳菲菲兮滿堂。", "蕙殽烝兮蘭藉，奠桂酒兮椒漿。", "靈連蜷兮既留，爛昭昭兮未央。", "駕飛龍兮于征，邅吾道兮鄉之長城。", "波滔滔兮淚盈盈，望汾潭兮磐石橫。", "僊灘兮揚靈，揚靈兮未極，隠思君兮太息。", "朝馳騖兮江之潯，夕弭節兮縣西之側，待娥不來兮使我心惻。"]'),
('c58e0e35-7eab-40e6-a5c6-8bc712b51799','饒娥廟祀神歌  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','我生之初尚無爲，我生之後唐世衰。',156,'全唐诗/poet.song.229000.json','["我生之初尚無爲，我生之後唐世衰。", "有父溺死兮誰者憐之，呼天與地兮涕漣洏。", "至險不測濤與風，至幽不仁魚與龍，至孝不昧感即通。", "豈人之靈兮，不若厖之雄。", "惟天地之無窮兮，哀吾生之弱齡。", "往者吾不及兮，來者吾不獲觀其敗與贏。", "愚公老矣山爲平，精衛藐然海爲傾。", "枕吾戈兮縛爾纓，猛志毅氣妖氛澄。", "昊天克鞏兮靡人弗勝，誦娥之烈兮摇我心旌。"]'),
('172853d7-01dc-47d6-b426-992fd53ca003','饒娥廟祀神歌  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','自我天覆，雲之油油。',144,'全唐诗/poet.song.229000.json','["自我天覆，雲之油油。", "大田多稼兮，屯膏是憂。", "雄虹朝隮兮，雌霓夕虬。", "觸石兮通氣，雷車兮電幟。", "雨甚至兮，神哉沛農。", "有成功兮，懷雞黍之招邀。", "士未失職兮，冀鵬鯤之扶摇。", "錫之豐歲兮，俾爾餘饒。", "報以修程兮，匪我宣驕。", "揚桴兮拊鼓，餞飈游兮遠渚。", "欲少留此靈瑣兮，日忽忽其將暮。", "祝娥之來下兮，慰我士民于終古。"]'),
('e512a715-c11f-4367-9632-bbda641f43c7','贈山堂僧','馬廷鸞','宋','宋诗','song-poetry','','[]','無生究竟是真源，浮世虛名可氣吞。',64,'全唐诗/poet.song.229000.json','["無生究竟是真源，浮世虛名可氣吞。", "浄行要從圓處覓，好詩添向悶中喧。", "一心認我如如體，萬事同渠莫莫言。", "歸向靈巖巖底坐，道根聖果滿祇園。"]'),
('55cfcd58-72b0-4670-8143-8a61ffdc8057','贈地理李生','馬廷鸞','宋','宋诗','song-poetry','','[]','崑崙宇宙一株石，拄地撐天日夜浮。',32,'全唐诗/poet.song.229000.json','["崑崙宇宙一株石，拄地撐天日夜浮。", "萬古青山青未了，西風斜日黯凝眸。"]'),
('1fb18c66-b8c7-4eb4-82cb-000538fa3db5','贈相者非常眼','馬廷鸞','宋','宋诗','song-poetry','','[]','已分山林著此臞，一科端不補遺餘。',32,'全唐诗/poet.song.229000.json','["已分山林著此臞，一科端不補遺餘。", "朝來忽遇非常眼，廢却窗前半日書。"]'),
('25fe7376-cbd2-49cf-be79-a3130eb1c015','贈相士二首  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','人物渺然吁可歎，憑誰指出植鰭翁。',32,'全唐诗/poet.song.229000.json','["人物渺然吁可歎，憑誰指出植鰭翁。", "勤伊急向傅巖看，當在君王夢寐中。"]'),
('73ed48db-9a25-41de-843e-c70b8c6a343c','贈相士二首  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','處仲恰如王眼目，了翁舊識蔡精神。',32,'全唐诗/poet.song.229000.json','["處仲恰如王眼目，了翁舊識蔡精神。", "儘教識盡公卿相，不願公卿屬箇人。"]'),
('1d3fe978-c46c-4393-885c-4b30f8c81b34','酬縣教徐志友','馬廷鸞','宋','宋诗','song-poetry','','[]','二十五宗詩有派，九成宮帖字名家。',32,'全唐诗/poet.song.229000.json','["二十五宗詩有派，九成宮帖字名家。", "何須奠去無人識，政自吟來與舅誇。"]'),
('98dab493-b51b-42f6-9a54-4bb068335729','奉謝龍山使君','馬廷鸞','宋','宋诗','song-poetry','','[]','四美持來野老家，燈前兒女自讙譁。',64,'全唐诗/poet.song.229000.json','["四美持來野老家，燈前兒女自讙譁。", "匙抄天上神仙飯，瓶插人間富貴花。", "剡雪尚堪書繭紙，吳霜聊欲寄烏紗。", "今朝新雨無人跡，莫向門前幾箇誇。"]'),
('72a44f0e-bfcd-4cfc-96c7-f2e16d2ac7d5','詩謝趙南岡','馬廷鸞','宋','宋诗','song-poetry','','[]','早從諸暨厚相於，郭史能書也憶渠。',64,'全唐诗/poet.song.229000.json','["早從諸暨厚相於，郭史能書也憶渠。", "萬事只今同去鶴，十年依舊愛前魚。", "試嘗小缶烹蓴玉，旋潑新醅漉酒釃。", "故舊不遺風韻在，猶存越絕幾編書。"]'),
('71c8e039-913b-4b41-b20f-27c0b007e6c7','謝龍山惠柱杖并求石銚四首  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','山窗閑笏倦支頤，出戶猶嗟擬步遲。',32,'全唐诗/poet.song.229000.json','["山窗閑笏倦支頤，出戶猶嗟擬步遲。", "萬事一條橫楖栗，緣坡穿徑走如馳。"]'),
('f13aab5d-3811-49bf-ae43-1adf3c59d002','謝龍山惠柱杖并求石銚四首  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','讀書未把壯心降，瀹雪烹雲聽煮湯。',32,'全唐诗/poet.song.229000.json','["讀書未把壯心降，瀹雪烹雲聽煮湯。", "澆我胸中過秦論，笑渠臧穀兩忘羊。"]'),
('2bc07085-78b1-4c51-8ddc-c9ea58b210cd','謝龍山惠柱杖并求石銚四首  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','捷徑新來競朵頤，登山有道只逶遲。',32,'全唐诗/poet.song.229000.json','["捷徑新來競朵頤，登山有道只逶遲。", "瘦藤獨立西風上，看盡坡頭萬馬馳。"]'),
('9e4b9da7-8726-4733-a898-65f2cc4c9a19','謝龍山惠柱杖并求石銚四首  其四','馬廷鸞','宋','宋诗','song-poetry','','[]','磚爐石銚竹方牀，何必銀瓶爲瀉湯。',32,'全唐诗/poet.song.229000.json','["磚爐石銚竹方牀，何必銀瓶爲瀉湯。", "苦茗只堪澆菜肚，春風却負太官羊。"]'),
('e515cccb-7704-4c08-9f03-369e78230a4c','題毛氏榴峰','馬廷鸞','宋','宋诗','song-poetry','','[]','誰家馬鬣懷先人，何人牛腰騁奇作。',64,'全唐诗/poet.song.229000.json','["誰家馬鬣懷先人，何人牛腰騁奇作。", "山高水長霜露濡，柏茂松深鳥烏落。", "曾玄有酒酹淒涼，翁仲無言卧冥寞。", "胥濤怒起越雲橫，血灑蒼梧雙淚落。"]'),
('839cf794-5304-4e4d-a707-f7fdea548c97','創木行','馬廷鸞','宋','宋诗','song-poetry','','[]','矯首昂霄上，刳心泣露餘。',48,'全唐诗/poet.song.229000.json','["矯首昂霄上，刳心泣露餘。", "高門封植舊，暴客斧斤初。", "斲作有瑕玉，創爲無用樗。", "終當宿威鳳，勿爲汝欷歔。"]'),
('65e6ac43-976d-4341-83dd-0bc436a01c28','錦雞','馬廷鸞','宋','宋诗','song-poetry','','[]','照水棲山自一奇，絳冠雪羽豈人犧。',32,'全唐诗/poet.song.229000.json','["照水棲山自一奇，絳冠雪羽豈人犧。", "明明在上今□望，是汝簞瓢捽茹時。"]'),
('2039177f-c193-4f6b-861a-cedf51470bec','余氏心暉堂','馬廷鸞','宋','宋诗','song-poetry','','[]','客從銀山來，遺我驪龍珠。',204,'全唐诗/poet.song.229000.json','["客從銀山來，遺我驪龍珠。", "高文偉大冊，至寶耀室隅。", "一讀心爲眩，再讀目爲盱。", "夫記者爲誰，潁封人之徒。", "人生天地間，母懷靡知愚。", "至恩嗟莫報，大節尤可吁。", "柏舟諒人只，蓼莪生子劬。", "所以茅季偉，鷄半饌設腴。", "所以王休證，魚雙甘旨需。", "此理有俱有，此心無息無。", "兒寒衣蘆花，母在足欣娛。", "兒罪履中野，母憐自噫嗚。", "高高心暉堂，申旦所依於。", "儼然其若存，何可離須臾。", "我吟方區區，我步方于于。", "起看物所性，因悟理不誣。", "懷哉反哺者，城頭尾畢逋。"]'),
('ed13a2be-9e35-4e1b-8ce6-7b3b078ba7b3','方氏臨清堂二首  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','割取風煙歸此堂，塵纓更好濯滄浪。',32,'全唐诗/poet.song.229000.json','["割取風煙歸此堂，塵纓更好濯滄浪。", "青山屋上下流水，永日翻書樂未央。"]'),
('58b62318-a414-4cbe-b58f-9b5be5f3eba2','方氏臨清堂二首  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','陶翁歸計已成遲，未折腰前好賦詩。',32,'全唐诗/poet.song.229000.json','["陶翁歸計已成遲，未折腰前好賦詩。", "到底尚稱千載士，高人拈向此中題。"]'),
('abb21bfb-ab2e-4e29-9eb3-74202c4dd8c3','徐氏拜榮堂','馬廷鸞','宋','宋诗','song-poetry','','[]','銀黌三組歸去來，繡衣朱轂胡爲哉。',128,'全唐诗/poet.song.229000.json','["銀黌三組歸去來，繡衣朱轂胡爲哉。", "富貴薰天無足道，人間至樂歸老萊。", "青衫隨分當綵衣，阿母一笑生兒癡。", "笋生雪底冰下魚，此事惟有天公知。", "吾母今年五十餘，襟期正與君母俱。", "雙瞳點漆髮未白，畫堂茅舍各自如。", "何時兩母俱徜徉，安輿來往陳壺觴。", "因觀吾廬戲綵章，就賦君家拜榮堂。"]'),
('f4a178c4-23a0-4b42-ab03-036462a19fd9','七月八夜宿東平精舍','馬廷鸞','宋','宋诗','song-poetry','','[]','昨夜雙星會鵲橋，好風佳月度今宵。',64,'全唐诗/poet.song.229000.json','["昨夜雙星會鵲橋，好風佳月度今宵。", "天孫曉發銀河落，帝昊秋成寶穡饒。", "玉露尚添荷縕藉，金風不惜柳飄飄。", "爐香直爲攀髯苦，望斷高空正泬寥。"]'),
('49169a4b-7cdf-4694-b4a2-0bcb55741de8','宿齋和同僚韻','馬廷鸞','宋','宋诗','song-poetry','','[]','羣玉峯頭一望賒，枕書舊監憶乘槎。',64,'全唐诗/poet.song.229000.json','["羣玉峯頭一望賒，枕書舊監憶乘槎。", "自從芸蠹三分席，何啻槐龍五見花。", "大典奏篇文綜覈，清吟落筆字橫斜。", "絕憐名輩諸公□，鞙璲如何趁佩霞。"]'),
('3dcb8978-619a-4d72-8a3f-b15b63bedc66','無題三首  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','大地生靈惜暵乾，紙田不飽腐儒餐。',32,'全唐诗/poet.song.229000.json','["大地生靈惜暵乾，紙田不飽腐儒餐。", "閑將博士虀鹽味，試上先生苜蓿盤。"]'),
('66fe2186-fff1-4962-bd2c-c7a20e80be61','無題三首  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','口語甘時心獨異，中邊甜處味方宜。',32,'全唐诗/poet.song.229000.json','["口語甘時心獨異，中邊甜處味方宜。", "詩情合薦東坡老，慙媿當年蜜荔枝。"]'),
('8ade4f3f-c59e-417d-9ab0-0a58cebda4cf','無題三首  其三','馬廷鸞','宋','宋诗','song-poetry','','[]','聞說江邊起柁樓，欲將吾道付滄洲。',64,'全唐诗/poet.song.229000.json','["聞說江邊起柁樓，欲將吾道付滄洲。", "三年惡瞰盧仝屋，一日輕裝范蠡舟。", "蹈海高懷欣獨往，濟川好手蹇難留。", "檣陰舸下能容我，雨笠煙簑傲白鷗。"]'),
('416eaf7d-fb71-4019-b752-ae3992603f7e','題林彥潛詩編','馬廷鸞','宋','宋诗','song-poetry','','[]','快讀詩人七鉅編，前身端合是逋仙。',32,'全唐诗/poet.song.229000.json','["快讀詩人七鉅編，前身端合是逋仙。", "村翁溪老開吟社，媿我猶撐上水船。"]'),
('4033002f-d305-4985-bf7a-c12702576f0c','讀史有感','馬廷鸞','宋','宋诗','song-poetry','','[]','永嘉直數到貞明，三百年間宇宙傾。',64,'全唐诗/poet.song.229000.json','["永嘉直數到貞明，三百年間宇宙傾。", "草草梁陳貂尾續，紛紛雲代犬牙爭。", "誰知普六茹堅者，已向重光作噩生。", "畢竟開皇能混一，天公憒憒豈無情。"]'),
('33dc7838-e62d-4647-a6da-2fb68b7c1173','送朱子式從軍','馬廷鸞','宋','宋诗','song-poetry','','[]','折鏃奇勛在，衝冠怒氣深。',48,'全唐诗/poet.song.229000.json','["折鏃奇勛在，衝冠怒氣深。", "堯天日月大，禹甸曀霾侵。", "塞下將軍令，隆中梁甫吟。", "酒行君可起，快展擊胡心。"]'),
('6bd9f1e1-33cf-4cb4-82a0-35fa4b64d3ca','送文甫兄歸番陽二首  其一','馬廷鸞','宋','宋诗','song-poetry','','[]','白髮蒼顔老弟兄，累年隔闊話情親。',64,'全唐诗/poet.song.229000.json','["白髮蒼顔老弟兄，累年隔闊話情親。", "杭京一訪且千里，盤祖諸孫纔九人。", "掃榻少留深雨夜，著鞭又趁早霜晨。", "曾門有衍詩書澤，爲計維垣蜜印新。"]'),
('4fc9e8e8-41ce-4e36-854d-498d2c4baf39','送文甫兄歸番陽二首  其二','馬廷鸞','宋','宋诗','song-poetry','','[]','少小追隨子佩青，如今相視鬢絲橫。',64,'全唐诗/poet.song.229000.json','["少小追隨子佩青，如今相視鬢絲橫。", "式相好矣天倫重，歸去來兮世念輕。", "目送飛鴻雲縹緲，身憐病鶴影伶仃。", "聖恩若許還農畝，依舊山窗共短檠。"]'),
('f5046f4e-ddd9-4ba4-9d53-6fe0ba18182b','本朝治衰高宗生','馬廷鸞','宋','宋诗','song-poetry','','[]','歲逢淵獻感炎精，創業中興二主生。',64,'全唐诗/poet.song.229000.json','["歲逢淵獻感炎精，創業中興二主生。", "天啟高皇符藝祖，人將大觀擬天成。", "生民厭亂思平治，造物開先毓聖明。", "甲子□□□□亥，試從漢史漫推評。"]'),
('204fd87e-8375-4f18-ab1f-1200a29889b8','梅巖','馬廷鸞','宋','宋诗','song-poetry','','[]','卓哉青壁插晴空，古貌稜稜列士風。',32,'全唐诗/poet.song.229000.json','["卓哉青壁插晴空，古貌稜稜列士風。", "人物山川相與重，是間知有植鰭翁。"]'),
('5d2b0652-b723-44b7-86c0-d34fe4c9f764','披雲堂歌','馬廷鸞','宋','宋诗','song-poetry','','[]','癡雲壓隴如堅城，猛風擊破如雄兵。',142,'全唐诗/poet.song.229000.json','["癡雲壓隴如堅城，猛風擊破如雄兵。", "寒谿古洞收不徹，有如奔車白旆歸空營。", "林稍劃劃露微碧，玉匣漸見青銅精。", "影轉西風流日脚，萬斛黄金散空落。", "寶篦刮盡重瞳膜，倒盛一海春冰薄。", "世界傾在琉璃屏，神豪氣爽肌骨清。", "便欲垂羽翰，飛上朝玉京。", "不須七椀秋江波，兩腋自有清風生。", "長憶當年玉川子，慇懃會問蒼生事。"]'),
('1fa7e2bc-7523-4018-9334-81e8af52f61e','老學樓','馬廷鸞','宋','宋诗','song-poetry','','[]','元龍高卧仲宣憂，我獨叢書置此樓。',64,'全唐诗/poet.song.229000.json','["元龍高卧仲宣憂，我獨叢書置此樓。", "把卷欣將聖賢對，憑欄遮斷古今愁。", "山前翠樹森雲表，林罅青秧匝壠頭。", "收拾吟篇供老眼，陳登王粲總悠悠。"]'),
('8666d2c2-9d05-4337-9f89-b625cef8e59f','盤園','馬廷鸞','宋','宋诗','song-poetry','','[]','雲水鄉中樓觀開，溪山好處興悠哉。',64,'全唐诗/poet.song.229000.json','["雲水鄉中樓觀開，溪山好處興悠哉。", "平章風月歸茶鼎，管領烟霞付酒杯。", "吟骨已成枯鶴瘦，機心莫遣狎鷗猜。", "大夫整頓乾坤了，黄帽青鞋歸去來。"]'),
('64d53339-1ee3-4e0b-95df-d2a67bf36529','四友相陪亭','馬廷鸞','宋','宋诗','song-poetry','','[]','誰伴幽人飽歲寒，霜葩雪榦翠琅玕。',32,'全唐诗/poet.song.229000.json','["誰伴幽人飽歲寒，霜葩雪榦翠琅玕。", "眼前交道如渠少，好作長年耐久看。"]'),
('ed16b117-fdd3-4fe3-b63f-881bffe5db03','宋江三十六贊  其一','龔開','宋','宋诗','song-poetry','','[]','不假稱王，而呼保義。',20,'全唐诗/poet.song.229000.json','["不假稱王，而呼保義。", "豈若狂卓，專犯忌諱。"]'),
('90f51e19-9c44-427f-9983-e09b6e65c3a4','宋江三十六贊  其二','龔開','宋','宋诗','song-poetry','','[]','古人用智，義國安民。',20,'全唐诗/poet.song.229000.json','["古人用智，義國安民。", "惜哉所予，酒色粗人。"]'),
('fcb440c9-067d-4785-8938-9ef84e91a621','宋江三十六贊  其三','龔開','宋','宋诗','song-poetry','','[]','白玉麒麟，見之可愛。',20,'全唐诗/poet.song.229000.json','["白玉麒麟，見之可愛。", "風塵大行，皮毛終壞。"]'),
('56415246-62a1-4bc2-af90-75b225e6776f','宋江三十六贊  其四','龔開','宋','宋诗','song-poetry','','[]','大刀關勝，豈雲長孫。',20,'全唐诗/poet.song.229000.json','["大刀關勝，豈雲長孫。", "雲長義勇，汝其後昆。"]'),
('5fe1b9a5-7b1b-41d9-8008-bd4afb29a298','宋江三十六贊  其五','龔開','宋','宋诗','song-poetry','','[]','地下閻羅，追魂攝魄。',20,'全唐诗/poet.song.229000.json','["地下閻羅，追魂攝魄。", "今其活矣，名喝太伯。"]'),
('0ab08664-378a-4b98-a58f-27c65ecc4ec0','宋江三十六贊  其六','龔開','宋','宋诗','song-poetry','','[]','將軍下短，貴稱侯王。',20,'全唐诗/poet.song.229000.json','["將軍下短，貴稱侯王。", "汝豈非夫，腿尺八長。"]'),
('7740b63b-31f5-496e-b066-abb223d1b99e','宋江三十六贊  其七','龔開','宋','宋诗','song-poetry','','[]','箭以羽行，破敵無頗。',20,'全唐诗/poet.song.229000.json','["箭以羽行，破敵無頗。", "七札難穿，如游斜何。"]'),
('5d1b5098-8a51-46c6-8bb6-50a3686e6004','宋江三十六贊  其八','龔開','宋','宋诗','song-poetry','','[]','平康巷陌，豈知汝名。',20,'全唐诗/poet.song.229000.json','["平康巷陌，豈知汝名。", "大行春色，有一丈青。"]'),
('14696f8e-02e7-4e5a-a525-8b0bc7ce343a','宋江三十六贊  其九','龔開','宋','宋诗','song-poetry','','[]','尉遲壯士，以病自名。',20,'全唐诗/poet.song.229000.json','["尉遲壯士，以病自名。", "端能去病，國功可成。"]'),
('d39befd6-3707-4a98-911a-8d40a09f7d06','宋江三十六贊  其一○','龔開','宋','宋诗','song-poetry','','[]','雪浪如山，汝能白跳。',20,'全唐诗/poet.song.229000.json','["雪浪如山，汝能白跳。", "願隨忠魂，來駕怒潮。"]'),
('ab5d08c0-2895-4a6d-abda-29f54d519322','宋江三十六贊  其一一','龔開','宋','宋诗','song-poetry','','[]','大行好漢，三十有六。',20,'全唐诗/poet.song.229000.json','["大行好漢，三十有六。", "無此火兒，其數不足。"]'),
('c625f3be-f302-47e4-ad7b-2ca240dc784d','宋江三十六贊  其一二','龔開','宋','宋诗','song-poetry','','[]','灌口少年，短命何益。',20,'全唐诗/poet.song.229000.json','["灌口少年，短命何益。", "曷不監之，清源廟食。"]'),
('c9526b24-c065-4e6f-9264-cbb5fd6e3317','宋江三十六贊  其一三','龔開','宋','宋诗','song-poetry','','[]','有飛飛兒，出家尤好。',20,'全唐诗/poet.song.229000.json','["有飛飛兒，出家尤好。", "與爾同袍，佛也被惱。"]'),
('8cac8ae9-9d83-4e9b-9a72-bef12e5ac7e2','宋江三十六贊  其一四','龔開','宋','宋诗','song-poetry','','[]','汝優婆塞，五戒在身。',20,'全唐诗/poet.song.229000.json','["汝優婆塞，五戒在身。", "酒色財氣，更要殺人。"]'),
('44e26805-b2f8-4496-bfbb-181c5854b40e','宋江三十六贊  其一五','龔開','宋','宋诗','song-poetry','','[]','尉遲彥章，去來一身。',20,'全唐诗/poet.song.229000.json','["尉遲彥章，去來一身。", "長鞭鐵鑄，汝豈其人。"]'),
('3798753b-97b1-41eb-b15d-b95ae0c73cad','宋江三十六贊  其一六','龔開','宋','宋诗','song-poetry','','[]','乖龍混江，射之即濟。',20,'全唐诗/poet.song.229000.json','["乖龍混江，射之即濟。", "武皇雄爭，自惜神臂。"]'),
('2bfe9bfb-3938-446f-8b2b-70544d4c12b5','宋江三十六贊  其一七','龔開','宋','宋诗','song-poetry','','[]','龍數肖九，汝有九文。',20,'全唐诗/poet.song.229000.json','["龍數肖九，汝有九文。", "盍從東皇，駕五色雲。"]'),
('209f3874-f27c-4f3d-8f1a-3f1307cfd74d','宋江三十六贊  其一八','龔開','宋','宋诗','song-poetry','','[]','中心慕漢，奪馬而歸。',20,'全唐诗/poet.song.229000.json','["中心慕漢，奪馬而歸。", "汝能慕廣，何憂數奇。"]'),
('6cb4d361-2505-4c65-aa2e-657b0371d620','宋江三十六贊  其一九','龔開','宋','宋诗','song-poetry','','[]','霹靂有火，摧山破嶽。',20,'全唐诗/poet.song.229000.json','["霹靂有火，摧山破嶽。", "天心無妄，汝孽自作。"]'),
('b035016d-1dd2-48cb-883e-def586924eba','宋江三十六贊  其二○','龔開','宋','宋诗','song-poetry','','[]','風有大小，不辨雌雄。',20,'全唐诗/poet.song.229000.json','["風有大小，不辨雌雄。", "山谷之中，遇爾亦凶。"]'),
('00cc798a-50bc-491c-875e-eb6e72ff3512','宋江三十六贊  其二一','龔開','宋','宋诗','song-poetry','','[]','風有大小，黑惡則懼。',20,'全唐诗/poet.song.229000.json','["風有大小，黑惡則懼。", "一噫之微，香滿太虛。"]'),
('b532d64e-2a81-4fb8-9129-88c6d61d2287','宋江三十六贊  其二二','龔開','宋','宋诗','song-poetry','','[]','飛而食肉，有此雄奇。',20,'全唐诗/poet.song.229000.json','["飛而食肉，有此雄奇。", "生入玉關，豈傷令姿。"]'),
('25511bc9-c6ec-4177-986f-af87bff35e9d','宋江三十六贊  其二三','龔開','宋','宋诗','song-poetry','','[]','不疾而速，故神無方。',20,'全唐诗/poet.song.229000.json','["不疾而速，故神無方。", "汝行何之，敢離大行。"]'),
('c5717f6d-1374-444d-8528-64bbbb0e926f','宋江三十六贊  其二四','龔開','宋','宋诗','song-poetry','','[]','行軍出師，其鋒必先。',20,'全唐诗/poet.song.229000.json','["行軍出師，其鋒必先。", "汝勿銳進，天兵在前。"]'),
('e7b63142-2d64-4229-b4cd-e7978c060cd1','宋江三十六贊  其二五','龔開','宋','宋诗','song-poetry','','[]','東家之西，即西家東。',20,'全唐诗/poet.song.229000.json','["東家之西，即西家東。", "汝雖特立，何有吾宮。"]'),
('b5dbd6bc-f1ec-4993-811a-4e6a04dc16fe','宋江三十六贊  其二六','龔開','宋','宋诗','song-poetry','','[]','聖人治世，四靈在郊。',20,'全唐诗/poet.song.229000.json','["聖人治世，四靈在郊。", "汝獸何名，走曠勞勞。"]'),
('9493b1a4-dd1c-488b-b417-da3601411131','宋江三十六贊  其二七','龔開','宋','宋诗','song-poetry','','[]','關索之雄，超之亦賢。',20,'全唐诗/poet.song.229000.json','["關索之雄，超之亦賢。", "能持義勇，自命何全。"]'),
('43f45fe1-3b7b-4278-8ce5-48dec98bf429','宋江三十六贊  其二八','龔開','宋','宋诗','song-poetry','','[]','昔樊將軍，鴻門直撞。',20,'全唐诗/poet.song.229000.json','["昔樊將軍，鴻門直撞。", "斗酒肉肩，其言甚壯。"]'),
('57e48c5a-a973-48fc-9f79-5574224c69f0','宋江三十六贊  其二九','龔開','宋','宋诗','song-poetry','','[]','左嚙右噬，其毒可畏。',20,'全唐诗/poet.song.229000.json','["左嚙右噬，其毒可畏。", "逢陰德人，杖之亦斃。"]'),
('1bbc857c-4c11-4549-94d6-1b451819e24d','宋江三十六贊  其三○','龔開','宋','宋诗','song-poetry','','[]','長髯郁然，美哉丰姿。',20,'全唐诗/poet.song.229000.json','["長髯郁然，美哉丰姿。", "忍使尺宅，而見愁眉。"]'),
('db824dbc-8d23-4be2-9920-6a8aa237e064','宋江三十六贊  其三一','龔開','宋','宋诗','song-poetry','','[]','出沒太行，茫無畔岸。',20,'全唐诗/poet.song.229000.json','["出沒太行，茫無畔岸。", "雖沒遮攔，難離火伴。"]'),
('14d39243-95a0-436a-a1f2-8772635e268a','宋江三十六贊  其三二','龔開','宋','宋诗','song-poetry','','[]','石秀拚命，志在金寶。',20,'全唐诗/poet.song.229000.json','["石秀拚命，志在金寶。", "大似河魨，腹果一飽。"]'),
('fbb0f531-9da4-4c0f-882e-d224afdf4c51','宋江三十六贊  其三三','龔開','宋','宋诗','song-poetry','','[]','醫師用蝎，其體貴全。',20,'全唐诗/poet.song.229000.json','["醫師用蝎，其體貴全。", "反其常性，雷公汝嫌。"]'),
('b7ea20a4-4627-4114-b6a2-7fe65f8cfc8e','宋江三十六贊  其三四','龔開','宋','宋诗','song-poetry','','[]','毗沙天人，證紫金軀。',20,'全唐诗/poet.song.229000.json','["毗沙天人，證紫金軀。", "頑鐵鑄汝，亦出洪爐。"]'),
('88fc4f38-9281-490f-b9f4-466f5b74e758','宋江三十六贊  其三五','龔開','宋','宋诗','song-poetry','','[]','金不可辱，亦忌在穢。',20,'全唐诗/poet.song.229000.json','["金不可辱，亦忌在穢。", "盍鑄長殳，羽林是衛。"]'),
('fe038ce4-dd9c-4ec2-b206-3568bfe7f3dc','宋江三十六贊  其三六','龔開','宋','宋诗','song-poetry','','[]','鷙禽雄長，惟鵰最狡。',20,'全唐诗/poet.song.229000.json','["鷙禽雄長，惟鵰最狡。", "毋撲天飛，封狐在草。"]'),
('27d170a1-4b7e-4519-b95b-02b07fe9af91','高馬小兒圖','龔開','宋','宋诗','song-poetry','','[]','華驄料肥九分臕，童子身長五尺饒。',176,'全唐诗/poet.song.229000.json','["華驄料肥九分臕，童子身長五尺饒。", "青絲鞚短金勒緊，春風去去人馬驍。", "莫作尋常廝養看，沙陀義兒皆好漢。", "此兒此馬俱可憐，馬方三齒兒未冠。", "天真爛漫好容儀，楚楚衣裝無不宜。", "豈比五陵年少輩，胭脂坡下鬭輕肥。", "四海風塵雖已息，人才自少當愛惜。", "如此小兒如此馬，它日應須萬人敵。", "老夫出無馿可騎，乃有此馬騎此兒。", "呼兒回頭爲小駐，停鞭聽我新吟詩。", "兒不回頭馬行疾，老夫對之空嘖嘖。"]'),
('06b38e04-628f-4555-8048-355da8272c1c','黑馬圖','龔開','宋','宋诗','song-poetry','','[]','八尺龍媒出墨池，崑崙月窟等閑馳。',32,'全唐诗/poet.song.229000.json','["八尺龍媒出墨池，崑崙月窟等閑馳。", "幽州俠客夜騎去，行過陰山鬼不知。"]'),
('1f5d52ba-ea2b-4faa-b7d0-480c8152fdf5','瘦馬圖','龔開','宋','宋诗','song-poetry','','[]','一從雲霧降天關，空盡先朝十二閑。',32,'全唐诗/poet.song.229000.json','["一從雲霧降天關，空盡先朝十二閑。", "今日有誰憐瘦骨，夕陽沙岸影如山。"]'),
('611f3be4-985a-4427-9836-3399f86a303b','陸右丞君實輓詩  其一','龔開','宋','宋诗','song-poetry','','[]','立事寧將敗事論，在邊難與在朝分。',64,'全唐诗/poet.song.229000.json','["立事寧將敗事論，在邊難與在朝分。", "從來大地爲滄海，可得孤臣抱幼君。", "南北一家今又見，乾坤再造古曾聞。", "他年自有春秋筆，不比田橫祭墓文。"]'),
('5e04e79f-c4f6-4c58-a9ca-2a3f92301960','陸右丞君實輓詩  其二','龔開','宋','宋诗','song-poetry','','[]','數關天地人何預，分在君臣禮可無。',64,'全唐诗/poet.song.229000.json','["數關天地人何預，分在君臣禮可無。", "周粟如山夷叔餒，史書猶日臼嬰誣。", "舊邦新命方開化，公法私情本不渝。", "忠義未須論彼此，後先崇長是昌圖。"]'),
('4b602515-d237-4fc9-894c-a09c3900cfe8','題中山出遊圖','龔開','宋','宋诗','song-poetry','','[]','髯君家本住中山，駕言出遊安所適。',128,'全唐诗/poet.song.229000.json','["髯君家本住中山，駕言出遊安所適。", "謂爲小獵無鷹犬，以爲意行有家室。", "阿妹韶容見靚妝，五色臙脂最宜黑。", "道逢驛舍須少憩，古屋無人供酒食。", "赤幘烏衫固可烹，美人清血終難得。", "不如歸飲中山釀，一醉三年萬緣息。", "却愁有物覷高明，八姨豪買他人宅。", "待得君醒爲掃除，馬嵬金馱去無跡。"]'),
('05ba7ec9-ec6a-4d35-8d75-94df30398b2a','僕爲虛谷先生作玉豹馬先生有詩見酬極筆勢之馳騁乃以此詩報謝','龔開','宋','宋诗','song-poetry','','[]','南山有雄豹，隠霧成變化。',288,'全唐诗/poet.song.229000.json','["南山有雄豹，隠霧成變化。", "奇姿驚世人，毛物亦增價。", "天上房星浥瑞光，孕成白馬而黑章。", "爲誰容易來中國，風雪天山道路長。", "頭爲王，欲得方。", "目爲相，欲得明。", "脊爲將軍欲得强，腹爲城郭欲得張。", "絕憐此馬皆具足，十五肋中包腎腸。", "嗟予老去有馬癖，豈但障泥知愛惜。", "千金市駿已無人，禿筆松煤聊自得。", "君侯昔如汗血駒，名場萬馬曾先驅。", "山林鍾鼎今何有，歲晚江湖託著書。", "白雲未信仙鄉遠，黄髮鬖鬖健有餘。", "飲酒百川猶一吸，吟詩何嫌萬夫敵。", "我持此馬將安歸，投之君侯如獻璧。", "君侯作詩凜馳騖，八荒滿盈動雷雨。", "定知此馬知此意，獨欠老奚通馬語。", "曹將軍，杜工部，各有一心存萬古。", "其傳非畫亦非詩，要在我輩之襟期，君侯君侯知不知。"]'),
('72ab3943-6f9b-4982-889d-f8efc5b558f1','自題山水卷','龔開','宋','宋诗','song-poetry','','[]','谷口長松澗底藤，石橋山路晚登登。',32,'全唐诗/poet.song.229000.json','["谷口長松澗底藤，石橋山路晚登登。", "囊琴斗酒來何暮，空負寒齋昨夜鐙。"]'),
('807c64f0-665e-4d65-8407-b085b8183308','題趙鷗波高士圖','龔開','宋','宋诗','song-poetry','','[]','雪氣侵人卧欲僵，苦勞明府到藜牀。',32,'全唐诗/poet.song.229000.json','["雪氣侵人卧欲僵，苦勞明府到藜牀。", "主賓問答皆情語，何用閒名入薦章。"]'),
('7a3f7749-b08e-44f8-ad6b-e114187f948a','題昭陵什伐赤馬圖','龔開','宋','宋诗','song-poetry','','[]','赤驥駝僧去玉關，換他白馬載經□。',32,'全唐诗/poet.song.229000.json','["赤驥駝僧去玉關，換他白馬載經□。", "誰憐什伐飛龍子，贏得金創卧帝閑。"]'),
('80c8ea1d-2525-4b61-9009-a7b56d875149','一字至七字觀周曾秋塘圖有作','龔開','宋','宋诗','song-poetry','','[]','秋，秋。',70,'全唐诗/poet.song.229000.json','["秋，秋。", "瀟灑，清幽。", "人靜處，水邊頭。", "波紋細細，風色颼颼。", "鷗鷺情相狎，鳧鷖樂自由。", "疎葦敗荷池沼，白蘋紅蓼汀洲。", "幾竿漁釣去已盡，一段晚雲寒不收。"]'),
('88238d45-c827-46c2-8f0f-1693739a9f25','兒子咸畫鴈老人作江天仍作詩命咸書卷上','龔開','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','朔方六月猶有雪，江南十月冰未結。',96,'全唐诗/poet.song.229000.json','["朔方六月猶有雪，江南十月冰未結。", "鴈門一夜起秋風，飛到江南未八月。", "江南處處多稻粱，景物何獨爲瀟湘。", "沙汀月暗漁火起，警奴一夜空荒忙。", "休言汝肉不登俎，全身已被家兒取。", "猶幸先生有愛心，放汝長江得容與。"]'),
('17bbc944-3ef1-434c-b875-4f61b8fe1aa1','題自寫蘇黄像','龔開','宋','宋诗','song-poetry','','[]','海風吹髮如短蓬，精魄弄成禿鬢翁。',312,'全唐诗/poet.song.229000.json','["海風吹髮如短蓬，精魄弄成禿鬢翁。", "歸來已覺陽羨鄰里喜，不似雪堂概江空。", "六年歲月幪尊中。", "何况如今一螺墨，安能及公目如初生犢。", "細觀此畫尤崛奇，兩顴巉巖無剩肉。", "百年光景春夢婆，人閒遂少天上多。", "一炷清香留永日，柰此堂堂不語何。", "譬如寶鼎淪洄水，萬夫之力那能起。", "後來博古彼誰子，猶寫雄深吞簠簋。", "不然豈徒有三足兩耳□□，天地中閒泣神鬼。", "□□人之龍，文之虎，人言海內四學士，又云蘇門之六子。", "洪崖肩高萬丈餘，談笑拍摩何軒渠。", "當爲誰作前者王，當爲誰作後者盧。", "詩到聖時不讀書，高處豈獨煮湯坐團蒲。", "豈非迢迢百世下，好事亦寫蘇黄圖。", "又非中郎虎賁之有身，又非叔敖身後之□死。", "典刑摩詰劣少須，一丈精神三尺素，光芒射人數百步。", "布袍便是山谷褐，可能其中有菜肚。"]'),
('ec515668-3af9-495a-95e6-6dc6b1a8f496','鼈山','王應麟','宋','宋诗','song-poetry','','[]','天柱不可折，柱折不可撐。',192,'全唐诗/poet.song.229000.json','["天柱不可折，柱折不可撐。", "九鼎不可覆，鼎覆人莫扛。", "袁公烈丈夫，獨立東南方。", "欲以一己力，代國相頡頏。", "適遭宋祚移，恥爲不義戕。", "奮然抱志起，誓欲掃攙槍。", "拔劍突前麾，手回日月光。", "敵勢愈猖獗，山摧失忠良。", "嗚呼絕倫志，不得騁才長。", "妻孥悉從溺，枯骨誰爲襄。", "忠烈動天地，遊魂爲國殤。", "山水倍堪悲，抱恨徹穹蒼。", "穹蒼幸一息，庶幾紀星霜。", "西風白楊路，哀猿號崇岡。", "解劍掛墓柏，泣下沾衣裳。", "惜哉時不利，抽毫述悲傷。"]'),
('2fa38e1c-b30b-4ab7-9ede-c0345db2bb1c','天童寺','王應麟','宋','宋诗','song-poetry','','[]','十里青松接翠微，梵王宮殿白雲飛。',64,'全唐诗/poet.song.229000.json','["十里青松接翠微，梵王宮殿白雲飛。", "鐘聲出岫客初到，月色滿庭僧未歸。", "偶有閒情依凈土，竟無塵慮瀆天機。", "明朝尚有登高興，千仞岡頭一振衣。"]'),
('f768659e-0d54-4f45-b121-804d9349f6c9','望春山','王應麟','宋','宋诗','song-poetry','','[]','羣峯西南起還伏，湖上丹丘立于獨。',80,'全唐诗/poet.song.229000.json','["羣峯西南起還伏，湖上丹丘立于獨。", "神仙寓迹山水間，不在幽深在清淑。", "松潭水暖龍欲起，蕙帳人空鶴自宿。", "飛雲曉馭紫瓊車，沆瀣宵涵白銀屋。", "蓬萊之名不可思，俗客須當避爾躅。"]'),
('1926663c-3c84-456b-879b-eaf4920104e4','東錢湖','王應麟','宋','宋诗','song-poetry','','[]','湖草青青湖水平，酒航西渡入空明。',64,'全唐诗/poet.song.229000.json','["湖草青青湖水平，酒航西渡入空明。", "月波夜靜銀浮鏡，霞嶼春深錦作屏。", "丞相祠前惟古柏，讀書臺上但啼鶑。", "年年謝豹花開日，猶有遊人作伴行。"]'),
('99626383-e3b0-444b-8af2-1ea7e53c1eeb','唐開成年墓誌石','王應麟','宋','宋诗','song-poetry','','[]','鴻濛肇開闢，變嬗幾成毀。',288,'全唐诗/poet.song.229000.json','["鴻濛肇開闢，變嬗幾成毀。", "寥寥斷竹歌，瓦堲溯姚姒。", "周墳典以族，詎認青烏子。", "公琴記咎繇，邢山稱東里。", "葛淯失之矯，璠璵過于侈。", "焉知宮夾墓，莫識龜言水。", "銅槃字十六，銘自比于始。", "延陵有孔篆，烏寧半辭止。", "漢甎猶簡樸，石章寖華靡。", "無愧惟有道，媚俗多虛美。", "七松談士良，何以懲不軌。", "載筆鮮南董，襲浮謬臧否。", "豈悟冢中人，三百年不死。", "婦名弗出閫，古未有碑誄。", "謚見春秋初，誌起典午氏。", "簪蒿隠士妻，芳刻垂千祀。", "楊高託不朽，習之文中理。", "或犯葵丘禁，息國事何恥。", "蛾眉爲黄土，磨滅更誰紀。", "宰如比何人，維邑之士女。", "逸民孺仲裔，冰雪濯紈綺。", "采儷古鄞州，儉勤終莫齒。", "試問幾何年，頗與銅人似。", "雖微黄絹辭，亦質而不俚。"]'),
('54e24c30-530f-4bc3-a509-7920fade8ecc','配食大成樂章 酌獻郕國公','王應麟','宋','宋诗','song-poetry','','[]','心傳忠恕，一以貫之。',40,'全唐诗/poet.song.229000.json','["心傳忠恕，一以貫之。", "爰述太學，萬世訓彜。", "惠我光明，尊聞行知。", "繼聖迪後，是享是宜。"]');
